// Helper to extract email from various formats (e.g., "John Doe <john@example.com>" -> "john@example.com")
function extractEmail(input: string): string | null {
  if (!input) return null;
  const emailMatch = input.match(/<([^>]+@[^>]+)>/);
  if (emailMatch) return emailMatch[1].toLowerCase().trim();
  if (input.includes('@')) return input.toLowerCase().trim();
  return null;
}

// Helper to extract name from email or format (e.g., "john.doe@example.com" -> "John Doe")
function extractName(input: string): string {
  if (!input) return 'Unknown';
  // Check for "Name <email>" format
  const nameMatch = input.match(/^([^<]+)</);
  if (nameMatch) return nameMatch[1].trim();
  // Extract from email address (john.doe@example.com -> John Doe)
  const email = extractEmail(input);
  if (email) {
    const localPart = email.split('@')[0];
    return localPart
      .replace(/[._-]/g, ' ')
      .split(' ')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
      .join(' ');
  }
  return input.trim() || 'Unknown';
}

// Helper to extract domain from email
function extractDomain(email: string | null): string | null {
  if (!email) return null;
  const parts = email.split('@');
  return parts.length > 1 ? parts[1].toLowerCase() : null;
}

// Entity extraction and counting for business summaries
async function extractEntityInvolvement(
  communications: any[],
  internalDomains: string[] = []
): Promise<EntityInvolvement> {
  const entityMap = new Map<string, {
    name: string;
    email: string | null;
    role: string | null;
    department: string | null;
    asSender: number;
    asRecipient: number;
    mentionedInBody: number;
    communications: Set<string>;
    documents: Set<string>;
    firstSeen: Date | null;
    lastSeen: Date | null;
    isInternal: boolean;
    isVendor: boolean;
  }>();

  // Known vendor domains (common third-party services)
  const vendorDomainPatterns = [
    'salesforce.com', 'hubspot.com', 'slack.com', 'zoom.us', 'microsoft.com',
    'google.com', 'dropbox.com', 'box.com', 'docusign.com', 'adobe.com',
    'aws.amazon.com', 'oracle.com', 'sap.com', 'workday.com', 'zendesk.com',
    'servicenow.com', 'mailchimp.com', 'stripe.com', 'twilio.com'
  ];

  // Process each communication
  for (const comm of communications) {
    const commId = comm.id;
    const timestamp = comm.timestamp ? new Date(comm.timestamp) : (comm.createdAt ? new Date(comm.createdAt) : null);

    // Process sender
    if (comm.sender) {
      const email = extractEmail(comm.sender);
      const name = extractName(comm.sender);
      const key = email || name.toLowerCase();
      const domain = extractDomain(email);
      
      const isInternal = domain ? internalDomains.some(d => domain.includes(d)) : false;
      const isVendor = domain ? vendorDomainPatterns.some(v => domain.includes(v)) : false;

      if (!entityMap.has(key)) {
        entityMap.set(key, {
          name,
          email,
          role: null,
          department: comm.custodianDepartment || null,
          asSender: 0,
          asRecipient: 0,
          mentionedInBody: 0,
          communications: new Set(),
          documents: new Set(),
          firstSeen: timestamp,
          lastSeen: timestamp,
          isInternal,
          isVendor
        });
      }
      
      const entity = entityMap.get(key)!;
      entity.asSender++;
      entity.communications.add(commId);
      if (timestamp) {
        if (!entity.firstSeen || timestamp < entity.firstSeen) entity.firstSeen = timestamp;
        if (!entity.lastSeen || timestamp > entity.lastSeen) entity.lastSeen = timestamp;
      }
      if (comm.custodianDepartment && !entity.department) {
        entity.department = comm.custodianDepartment;
      }
    }

    // Process recipients
    const recipients = Array.isArray(comm.recipients) ? comm.recipients : [];
    for (const recipient of recipients) {
      const email = extractEmail(recipient);
      const name = extractName(recipient);
      const key = email || name.toLowerCase();
      const domain = extractDomain(email);
      
      const isInternal = domain ? internalDomains.some(d => domain.includes(d)) : false;
      const isVendor = domain ? vendorDomainPatterns.some(v => domain.includes(v)) : false;

      if (!entityMap.has(key)) {
        entityMap.set(key, {
          name,
          email,
          role: null,
          department: null,
          asSender: 0,
          asRecipient: 0,
          mentionedInBody: 0,
          communications: new Set(),
          documents: new Set(),
          firstSeen: timestamp,
          lastSeen: timestamp,
          isInternal,
          isVendor
        });
      }
      
      const entity = entityMap.get(key)!;
      entity.asRecipient++;
      entity.communications.add(commId);
      if (timestamp) {
        if (!entity.firstSeen || timestamp < entity.firstSeen) entity.firstSeen = timestamp;
        if (!entity.lastSeen || timestamp > entity.lastSeen) entity.lastSeen = timestamp;
      }
    }
  }

  // Convert to arrays and classify
  const employees: EntityInvolvementEntry[] = [];
  const thirdParties: EntityInvolvementEntry[] = [];
  const vendors: EntityInvolvementEntry[] = [];

  for (const [key, entity] of entityMap.entries()) {
    const entry: EntityInvolvementEntry = {
      name: entity.name,
      email: entity.email,
      role: entity.role,
      department: entity.department,
      communication_count: entity.communications.size,
      document_count: entity.documents.size || entity.communications.size, // Use comm count as doc count for now
      as_sender: entity.asSender,
      as_recipient: entity.asRecipient,
      mentioned_in_body: entity.mentionedInBody,
      first_seen: entity.firstSeen?.toISOString() || null,
      last_seen: entity.lastSeen?.toISOString() || null
    };

    if (entity.isVendor) {
      vendors.push(entry);
    } else if (entity.isInternal) {
      employees.push(entry);
    } else {
      thirdParties.push(entry);
    }
  }

  // Sort by communication count (descending)
  const sortByCount = (a: EntityInvolvementEntry, b: EntityInvolvementEntry) => 
    b.communication_count - a.communication_count;
  
  employees.sort(sortByCount);
  thirdParties.sort(sortByCount);
  vendors.sort(sortByCount);

  return {
    employees,
    third_parties: thirdParties,
    vendors,
    total_unique_entities: entityMap.size,
    total_communications_analyzed: communications.length,
    extraction_date: new Date().toISOString()
  };
}

// Helper to log audit trails
async function logAction(req: any, action: string, entityType: string, entityId?: string, details?: any) {
  try {
    const userId = req.user?.id || req.user?.claims?.sub;
    // Check if user exists before creating audit log to avoid FK constraint errors
    if (userId) {
      const userExists = await db.select({ id: schema.users.id }).from(schema.users).where(eq(schema.users.id, userId)).limit(1);
      if (userExists.length === 0) {
        console.log("Audit log skipped - user not found in database:", userId);
        return;
      }
    }
    await storage.createAuditLog({
      userId,
      action,
      entityType,
      entityId,
      details,
      ipAddress: req.ip,
      userAgent: req.headers["user-agent"],
    });
  } catch (error) {
    console.error("Audit log error:", error);
  }
}

