  // Send invitations to event invitees
  const sendInvitationsSchema = z.object({
    eventId: z.string().min(1),
    invitees: z.array(z.object({
      name: z.string(),
      email: z.string().email().optional(),
      phone: z.string().optional(),
      notifyVia: z.enum(["email", "sms", "both"])
    }).refine(
      (inv) => inv.email || inv.phone,
      { message: "Each invitee must have at least an email or phone number" }
    ))
  });

  app.post("/api/calendar/events/:eventId/send-invitations", isAuthenticated, async (req: any, res) => {
    try {
      const { eventId } = req.params;
      const parseResult = sendInvitationsSchema.safeParse({ eventId, ...req.body });
      
      if (!parseResult.success) {
        return res.status(400).json({ message: parseResult.error.errors[0]?.message || "Invalid request" });
      }

      const { invitees } = parseResult.data;
      
      // Get event details
      const event = await storage.getCalendarEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      const results: { email?: string; phone?: string; method: string; status: string; sentAt: string }[] = [];
      const sentAt = new Date().toISOString();

      for (const invitee of invitees) {
        // Generate meeting URL using meetingRoomId for consistent links
        const baseUrl = process.env.REPLIT_DEV_DOMAIN ? `https://${process.env.REPLIT_DEV_DOMAIN}` : 'http://localhost:5000';
        const roomId = (event as any).meetingRoomId || eventId;
        const meetingUrl = event.videoConferenceUrl || `${baseUrl}/video-meeting/${roomId}?eventId=${eventId}`;
        
        const eventDetails = `
Event: ${event.title}
Date: ${new Date(event.startTime).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
Time: ${new Date(event.startTime).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' })} - ${new Date(event.endTime).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' })}
${event.location ? `Location: ${event.location}` : ''}
${event.videoConferenceType && event.videoConferenceType !== 'none' ? `Join Meeting: ${meetingUrl}` : ''}
${event.description ? `\nDetails: ${event.description}` : ''}
        `.trim();

        // For now, log the invitation (in production, integrate with email/SMS provider)
        if (invitee.notifyVia === "email" || invitee.notifyVia === "both") {
          if (invitee.email) {
            console.log(`[EMAIL INVITATION] To: ${invitee.email}\nSubject: You're invited: ${event.title}\n\n${eventDetails}`);
            results.push({ email: invitee.email, method: "email", status: "queued", sentAt });
          }
        }
        
        if (invitee.notifyVia === "sms" || invitee.notifyVia === "both") {
          if (invitee.phone) {
            const smsMessage = `You're invited to "${event.title}" on ${new Date(event.startTime).toLocaleDateString()}. ${event.videoConferenceType && event.videoConferenceType !== 'none' ? `Join: ${meetingUrl}` : ''}`;
            console.log(`[SMS INVITATION] To: ${invitee.phone}\nMessage: ${smsMessage}`);
            results.push({ phone: invitee.phone, method: "sms", status: "queued", sentAt });
          }
        }
      }

      // Store notification records in the event
      await storage.updateCalendarEvent(eventId, {
        inviteeNotifications: results,
        externalAttendees: invitees.map(i => ({ name: i.name, email: i.email || "" }))
      });

      await logAction(req, "send_invitations", "calendar_event", eventId, { count: results.length });
      
      res.json({ 
        message: `Invitations ${results.length > 0 ? 'sent' : 'queued'} successfully`,
        results,
        note: "Email and SMS delivery requires configured providers (SendGrid/Twilio)"
      });
    } catch (error: any) {
      console.error("Error sending invitations:", error);
      res.status(500).json({ message: error.message });
    }
  });
  // Zod schema for image extraction request
  const extractFromImageSchema = z.object({
    image: z.string()
      .min(1, "Image is required")
      .refine(
        (val) => /^data:image\/(jpeg|png|gif|webp);base64,/.test(val),
        "Invalid image format. Please upload a JPEG, PNG, GIF, or WebP image."
      )
      .refine(
        (val) => {
          const base64Data = val.split("base64,")[1];
          if (!base64Data) return false;
          const estimatedSize = (base64Data.length * 3) / 4;
          return estimatedSize <= 10 * 1024 * 1024; // 10MB
        },
        "Image too large. Please upload an image smaller than 10MB."
      )
  });

  // Extract event details from image using OpenAI vision
  app.post("/api/calendar/extract-from-image", isAuthenticated, async (req: any, res) => {
    try {
      // Validate request body with Zod schema
      const parseResult = extractFromImageSchema.safeParse(req.body);
      if (!parseResult.success) {
        return res.status(400).json({ 
          message: parseResult.error.errors[0]?.message || "Invalid request" 
        });
      }
      
      const { image } = parseResult.data;
      const base64Data = image.split("base64,")[1];
      const mimeMatch = image.match(/^data:(image\/[^;]+);/);
      const mimeType = mimeMatch ? mimeMatch[1] : "image/jpeg";

      const response = await openai.chat.completions.create({
        model: "gpt-5",
        messages: [
          {
            role: "system",
            content: `You are an AI assistant that extracts calendar event details from images of legal documents, court notices, meeting invitations, and similar documents.

Extract the following fields if present:
- title: The event title or subject
- eventType: One of: hearing, deposition, deadline, trial, meeting, filing, mediation, conference, other
- startTime: Date and time in ISO 8601 format (YYYY-MM-DDTHH:mm)
- duration: Duration in minutes (15, 30, 45, 60, 120, 180, 240, 300, 360, 420, 480, half_day, all_day)
- description: A brief description or summary
- location: The venue or address
- courtName: If it's a court-related event
- judgeName: If a judge is mentioned

Return ONLY a valid JSON object with these fields. Only include fields that you can confidently extract from the image. If a date is found but no time, assume 9:00 AM.`
          },
          {
            role: "user",
            content: [
              {
                type: "text",
                text: "Extract event details from this document image:"
              },
              {
                type: "image_url",
                image_url: {
                  url: `data:${mimeType};base64,${base64Data}`
                }
              }
            ]
          }
        ],
        max_completion_tokens: 1000,
      });

      const content = response.choices[0]?.message?.content || "";
      
      // Robust JSON parsing with multiple fallback strategies
      let extracted: any = {};
      let jsonStr = content.trim();
      
      try {
        extracted = JSON.parse(jsonStr);
      } catch {
        const jsonBlockMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
        if (jsonBlockMatch) {
          jsonStr = jsonBlockMatch[1].trim();
        }
        
        const braceMatch = jsonStr.match(/\{[\s\S]*\}/);
        if (braceMatch) {
          jsonStr = braceMatch[0];
        }
        
        try {
          extracted = JSON.parse(jsonStr);
        } catch (parseError) {
          console.error("Failed to parse AI response:", content);
          return res.status(422).json({ 
            message: "Could not extract event details from this image. Please try a clearer image or enter details manually." 
          });
        }
      }
      
      // Validate extracted fields have expected types
      const validatedResult: Record<string, string> = {};
      const stringFields = ["title", "eventType", "startTime", "duration", "description", "location", "courtName", "judgeName"];
      
      for (const field of stringFields) {
        if (extracted[field] && typeof extracted[field] === "string") {
          validatedResult[field] = extracted[field];
        }
      }
      
      res.json(validatedResult);
    } catch (error: any) {
      console.error("Error extracting event from image:", error);
      res.status(500).json({ message: error.message || "Failed to extract event details" });
    }
  });
  // Update calendar event
