  // Search autocomplete endpoint
  app.get("/api/search/autocomplete", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req, res) => {
    try {
      const query = (req.query.query as string || '').toLowerCase();
      const caseId = req.query.caseId ? parseInt(req.query.caseId as string) : undefined;
      
      if (query.length < 2) {
        return res.json([]);
      }

      const suggestions: Array<{
        type: 'person' | 'tag' | 'custodian' | 'domain';
        value: string;
        label: string;
        count?: number;
      }> = [];

      // Get unique senders and recipients from communications
      const peopleQuery = await db.execute(sql`
        SELECT DISTINCT sender as email, COUNT(*) as count
        FROM ${schema.communications}
        WHERE LOWER(sender) LIKE ${`%${query}%`}
        ${caseId ? sql`AND case_id = ${caseId}` : sql``}
        GROUP BY sender
        UNION
        SELECT DISTINCT recipient as email, COUNT(*) as count
        FROM ${schema.communications},
        LATERAL jsonb_array_elements_text(recipients::jsonb) AS recipient
        WHERE LOWER(recipient) LIKE ${`%${query}%`}
        ${caseId ? sql`AND case_id = ${caseId}` : sql``}
        GROUP BY recipient
        ORDER BY count DESC
        LIMIT 10
      `);

      for (const row of peopleQuery.rows as any[]) {
        suggestions.push({
          type: 'person',
          value: row.email,
          label: row.email,
          count: parseInt(row.count),
        });
      }

      // Get unique domains
      const domainQuery = await db.execute(sql`
        SELECT DISTINCT 
          SUBSTRING(sender FROM '@(.*)$') as domain,
          COUNT(*) as count
        FROM ${schema.communications}
        WHERE LOWER(sender) LIKE ${`%${query}%`}
        ${caseId ? sql`AND case_id = ${caseId}` : sql``}
        AND sender LIKE '%@%'
        GROUP BY domain
        ORDER BY count DESC
        LIMIT 5
      `);

      for (const row of domainQuery.rows as any[]) {
        if (row.domain && row.domain.toLowerCase().includes(query.toLowerCase())) {
          suggestions.push({
            type: 'domain',
            value: row.domain,
            label: `@${row.domain}`,
            count: parseInt(row.count),
          });
        }
      }

      // Get tags
      const tagsQuery = await db.select({
        name: schema.tags.name,
        count: sql<number>`COUNT(*)`,
      })
        .from(schema.tags)
        .where(sql`LOWER(${schema.tags.name}) LIKE ${`%${query}%`}`)
        .groupBy(schema.tags.name)
        .limit(5);

      for (const tag of tagsQuery) {
        suggestions.push({
          type: 'tag',
          value: tag.name,
          label: tag.name,
          count: Number(tag.count),
        });
      }

      // Get custodians
      const custodiansQuery = await db.execute(sql`
        SELECT DISTINCT custodian_name as name, COUNT(*) as count
        FROM ${schema.communications}
        WHERE LOWER(custodian_name) LIKE ${`%${query}%`}
        ${caseId ? sql`AND case_id = ${caseId}` : sql``}
        AND custodian_name IS NOT NULL
        GROUP BY custodian_name
        ORDER BY count DESC
        LIMIT 5
      `);

      for (const row of custodiansQuery.rows as any[]) {
        suggestions.push({
          type: 'custodian',
          value: row.name,
          label: row.name,
          count: parseInt(row.count),
        });
      }

      res.json(suggestions);
    } catch (error: any) {
      console.error("Error fetching autocomplete suggestions:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Communication routes
  app.get("/api/communications", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req, res) => {
    try {
      const filters: import("./storage").CommunicationFilters = {};
      
      // Helper to parse array params (Express exposes repeated params as arrays)
      const parseArray = (param: any): string[] | undefined => {
        if (!param) return undefined;
        if (Array.isArray(param)) return param as string[];
        if (typeof param === 'string') return [param];  // Single value becomes array
        return undefined;
      };
      
      // Legacy filters (for compatibility)
      filters.employees = parseArray(req.query.employees);
      filters.departments = parseArray(req.query.departments);
      
      // Case-scoped filtering - CRITICAL: Filter documents by case ID
      if (req.query.caseId && typeof req.query.caseId === 'string') {
        filters.caseId = req.query.caseId;
      }
      
      // Date filters
      if (req.query.date && typeof req.query.date === 'string') {
        filters.date = req.query.date;
      }
      if (req.query.dateFrom && typeof req.query.dateFrom === 'string') {
        filters.dateFrom = req.query.dateFrom;
      }
      if (req.query.dateTo && typeof req.query.dateTo === 'string') {
        filters.dateTo = req.query.dateTo;
      }
      
      // People filters
      if (req.query.sender && typeof req.query.sender === 'string') {
        filters.sender = req.query.sender;
      }
      if (req.query.recipient && typeof req.query.recipient === 'string') {
        filters.recipient = req.query.recipient;
      }
      filters.from = parseArray(req.query.from);
      filters.to = parseArray(req.query.to);
      filters.cc = parseArray(req.query.cc);
      filters.bcc = parseArray(req.query.bcc);
      filters.participants = parseArray(req.query.participants);
      filters.excludePeople = parseArray(req.query.excludePeople);
      filters.domain = parseArray(req.query.domain);
      filters.author = parseArray(req.query.author);
      filters.custodian = parseArray(req.query.custodian);
      
      // Content filters
      if (req.query.query && typeof req.query.query === 'string') {
        filters.query = req.query.query;
      }
      if (req.query.queryMode && (req.query.queryMode === 'natural' || req.query.queryMode === 'boolean')) {
        filters.queryMode = req.query.queryMode;
      }
      
      // Communication type filter
      filters.communicationType = parseArray(req.query.communicationType);
      
      // Attachment filters
      if (req.query.hasAttachments !== undefined) {
        filters.hasAttachments = req.query.hasAttachments === 'true';
      }
      filters.attachmentTypes = parseArray(req.query.attachmentTypes);
      if (req.query.attachmentSizeMin) {
        filters.attachmentSizeMin = Number(req.query.attachmentSizeMin);
      }
      if (req.query.attachmentSizeMax) {
        filters.attachmentSizeMax = Number(req.query.attachmentSizeMax);
      }
      
      // Classification filters
      filters.tags = parseArray(req.query.tags);
      filters.privilege = parseArray(req.query.privilege);
      if (req.query.riskScoreMin) {
        filters.riskScoreMin = Number(req.query.riskScoreMin);
      }
      if (req.query.riskScoreMax) {
        filters.riskScoreMax = Number(req.query.riskScoreMax);
      }
      
      // Review workflow filters
      filters.reviewStatus = parseArray(req.query.reviewStatus);
      filters.assignedReviewer = parseArray(req.query.assignedReviewer);
      if (req.query.reviewedBy && typeof req.query.reviewedBy === 'string') {
        filters.reviewedBy = req.query.reviewedBy;
      }
      filters.batchSet = parseArray(req.query.batchSet);
      
      const communications = await storage.getCommunications(filters);
      res.json(communications);
    } catch (error: any) {
      console.error("Error fetching communications:", error);
      res.status(500).json({ message: error.message });
    }
  });

