  // Requires caseId to enforce case-level authorization
  app.post("/api/communications/batch", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req, res) => {
    try {
      const { ids, caseId } = req.body;
      if (!ids || !Array.isArray(ids) || ids.length === 0) {
        return res.json([]);
      }
      
      if (!caseId) {
        return res.status(400).json({ message: "caseId is required for authorization" });
      }
      
      // Limit to 20 documents per batch request
      const limitedIds = ids.slice(0, 20);
      
      // Only return communications that belong to the specified case
      const communications = await db
        .select({
          id: schema.communications.id,
          subject: schema.communications.subject,
          sender: schema.communications.sender,
          recipients: schema.communications.recipients,
          messageType: schema.communications.messageType,
          riskLevel: schema.communications.riskLevel,
          body: schema.communications.body,
          sentAt: schema.communications.sentAt,
          caseId: schema.communications.caseId,
        })
        .from(schema.communications)
        .where(and(
          inArray(schema.communications.id, limitedIds),
          eq(schema.communications.caseId, caseId)
        ));
      
      res.json(communications);
    } catch (error: any) {
      console.error("Error batch fetching communications:", error);
      res.status(500).json({ message: error.message });
    }
  });

