  // Compliance analysis endpoint
  app.post("/api/communications/:id/analyze-compliance", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req: any, res) => {
    try {
      const communication = await storage.getCommunication(req.params.id);
      if (!communication) {
        return res.status(404).json({ message: "Communication not found" });
      }

      // Check if already analyzed (within last 24 hours)
      if (communication.analyzedAt) {
        const hoursSinceAnalysis = (Date.now() - new Date(communication.analyzedAt).getTime()) / (1000 * 60 * 60);
        if (hoursSinceAnalysis < 24) {
          return res.json({
            complianceScore: communication.complianceScore,
            riskLevel: communication.riskLevel,
            aiComplianceAnalysis: communication.aiComplianceAnalysis,
            analyzedAt: communication.analyzedAt,
            cached: true,
          });
        }
      }

      // Get all communications for context
      const allCommunications = await storage.getCommunications({});
      
      // Get policies for analysis
      const policies = await storage.getPolicies();

      // Perform AI analysis
      const analysis = await analyzeCompliance(
        {
          id: communication.id,
          subject: communication.subject,
          body: communication.body,
          sender: communication.sender,
          recipients: communication.recipients,
          timestamp: communication.timestamp,
        },
        allCommunications.map(c => ({
          id: c.id,
          subject: c.subject,
          body: c.body,
          sender: c.sender,
          recipients: c.recipients,
          timestamp: c.timestamp,
        })),
        policies.map(p => ({
          id: p.id,
          title: p.title,
          content: p.content || "",
          category: p.category,
        }))
      );

      // Update communication with analysis results
      await db.update(schema.communications)
        .set({
          complianceScore: analysis.complianceScore,
          riskLevel: analysis.riskLevel,
          aiComplianceAnalysis: analysis.explanation,
          analyzedAt: new Date(),
        })
        .where(eq(schema.communications.id, req.params.id));

      // Store related document relationships
      for (const relatedDoc of analysis.relatedDocuments) {
        await db.insert(schema.documentRelationships).values({
          sourceDocumentId: communication.id,
          relatedDocumentId: relatedDoc.id,
          relationshipType: relatedDoc.relationshipType,
          confidenceScore: relatedDoc.confidence,
          explanation: relatedDoc.explanation,
        });
      }

      await logAction(req, "compliance_analyzed", "communication", req.params.id);

      res.json({
        complianceScore: analysis.complianceScore,
        riskLevel: analysis.riskLevel,
        aiComplianceAnalysis: analysis.explanation,
        violatedRegulations: analysis.violatedRegulations,
        policyViolations: analysis.policyViolations,
        analyzedAt: new Date(),
        cached: false,
      });
    } catch (error: any) {
      console.error("Error analyzing compliance:", error);
      res.status(500).json({ message: error.message });
    }
  });

