  // Document Export to PDF
  app.post("/api/documents/export", isAuthenticated, requireRole("admin", "attorney", "compliance_officer", "external_counsel", "auditor"), async (req: any, res) => {
    try {
      const userId = req.user?.id;
      if (!userId) {
        return res.status(401).json({ message: "User not authenticated" });
      }

      const exportRequestSchema = z.object({
        type: z.enum(['pdf', 'email', 'share']),
        documentIds: z.array(z.string()).min(1, "At least one document ID is required"),
        options: z.object({
          includeMetadata: z.boolean().optional().default(true),
          includeAttachments: z.boolean().optional().default(true),
          includeHighlights: z.boolean().optional().default(true),
          to: z.string().optional(),
          subject: z.string().optional(),
          message: z.string().optional(),
          userId: z.string().optional(),
        }).optional().default({}),
      });

      const validationResult = exportRequestSchema.safeParse(req.body);
      if (!validationResult.success) {
        return res.status(400).json({ 
          message: "Invalid request payload", 
          errors: validationResult.error.errors 
        });
      }

      const { type, documentIds, options } = validationResult.data;

      if (type === 'pdf') {
        // Limit to 100 documents per export to prevent performance issues
        if (documentIds.length > 100) {
          return res.status(400).json({ 
            message: "Cannot export more than 100 documents at once. Please select fewer documents." 
          });
        }

        // Fetch communications
        const communications = await db.select().from(schema.communications)
          .where(inArray(schema.communications.id, documentIds));

        if (communications.length === 0) {
          return res.status(404).json({ message: "No documents found with the provided IDs" });
        }

        // Fetch tags for these documents (safely handle empty results)
        let tagsByDocument: Record<string, Array<{tagName: string, category: string, color: string}>> = {};
        
        try {
          const documentTagsData = await db.select({
            entityId: schema.documentTags.entityId,
            tagId: schema.documentTags.tagId,
            tagName: schema.tags.name,
            category: schema.tags.category,
            color: schema.tags.color,
          })
          .from(schema.documentTags)
          .innerJoin(schema.tags, eq(schema.documentTags.tagId, schema.tags.id))
          .where(and(
            inArray(schema.documentTags.entityId, documentIds),
            eq(schema.documentTags.entityType, 'communication')
          ));

          // Group tags by document ID (entityId)
          tagsByDocument = (documentTagsData || []).reduce((acc: Record<string, Array<{tagName: string, category: string, color: string}>>, tag) => {
            if (tag && tag.entityId) {
              if (!acc[tag.entityId]) {
                acc[tag.entityId] = [];
              }
              acc[tag.entityId].push({
                tagName: tag.tagName || 'Unknown',
                category: tag.category || 'General',
                color: tag.color || '#666666',
              });
            }
            return acc;
          }, {});
        } catch (tagError) {
          console.error("Error fetching tags for documents:", tagError);
          // Continue without tags if there's an error
        }

        // Format documents for PDF export
        const documentsForPdf = communications.map(comm => ({
          id: comm.id,
          subject: comm.subject,
          body: comm.body,
          sender: comm.sender,
          recipients: Array.isArray(comm.recipients) ? comm.recipients : [],
          timestamp: comm.timestamp,
          sourceType: comm.sourceType,
          tags: tagsByDocument[comm.id] || [],
          annotations: null, // Annotations not yet implemented in schema
        }));

        // Generate PDF
        const pdfDoc = generateDocumentExportPDF(documentsForPdf, {
          includeMetadata: options?.includeMetadata ?? true,
          includeAttachments: options?.includeAttachments ?? true,
          includeHighlights: options?.includeHighlights ?? true,
        });

        // Set response headers for PDF download
        const filename = communications.length === 1
          ? `${communications[0].subject?.replace(/[^a-zA-Z0-9]/g, '-') || 'document'}.pdf`
          : `document-export-${documentIds.length}-documents.pdf`;
        
        res.setHeader('Content-Type', 'application/pdf');
        res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);

        // Stream PDF to response - pipe first, then end
        pdfDoc.pipe(res);
        pdfDoc.end();

        await logAction(req, "documents_exported_pdf", "communication", undefined, { 
          documentCount: communications.length,
          documentIds: documentIds.slice(0, 10), // Log first 10 IDs
        });

      } else if (type === 'email') {
        // Email export functionality
        return res.status(501).json({ message: "Email export not yet implemented" });
      } else if (type === 'share') {
        // Share functionality
        return res.status(501).json({ message: "Share functionality not yet implemented" });
      }

    } catch (error: any) {
      console.error("Error exporting documents:", error);
      res.status(500).json({ message: error.message || "Failed to export documents" });
    }
  });

