  // Get network graph data (nodes and edges) for force-directed visualization
  app.get("/api/cases/:caseId/communications/network", isAuthenticated, requireRole("admin", "attorney", "compliance_officer", "auditor"), async (req: any, res) => {
    try {
      const caseId = req.params.caseId;
      const minMessages = parseInt(req.query.minMessages as string) || 1;
      const dateFrom = req.query.dateFrom as string | undefined;
      const dateTo = req.query.dateTo as string | undefined;
      const sourceType = req.query.sourceType as string | undefined;

      // Fetch all communications for this case
      const communications = await db
        .select({
          id: schema.communications.id,
          sender: schema.communications.sender,
          recipients: schema.communications.recipients,
          timestamp: schema.communications.timestamp,
          sourceType: schema.communications.sourceType,
        })
        .from(schema.communications)
        .where(eq(schema.communications.caseId, caseId));

      // Apply filters
      let filtered = communications;
      if (dateFrom) {
        const fromDate = new Date(dateFrom);
        filtered = filtered.filter(c => c.timestamp && new Date(c.timestamp) >= fromDate);
      }
      if (dateTo) {
        const toDate = new Date(dateTo);
        filtered = filtered.filter(c => c.timestamp && new Date(c.timestamp) <= toDate);
      }
      if (sourceType && sourceType !== 'all') {
        filtered = filtered.filter(c => c.sourceType === sourceType);
      }

      // Build node and edge maps
      const nodeMap = new Map<string, {
        id: string;
        email: string;
        name: string;
        domain: string | null;
        sentCount: number;
        receivedCount: number;
        totalMessages: number;
        isInternal: boolean;
      }>();

      const edgeMap = new Map<string, {
        source: string;
        target: string;
        weight: number;
        messages: string[];
      }>();

      // Helper to normalize email
      const normalizeEmail = (input: string): string => {
        const emailMatch = input.match(/<([^>]+@[^>]+)>/);
        if (emailMatch) return emailMatch[1].toLowerCase().trim();
        if (input.includes('@')) return input.toLowerCase().trim();
        return input.toLowerCase().trim();
      };

      // Helper to extract name
      const getDisplayName = (input: string): string => {
        const nameMatch = input.match(/^([^<]+)</);
        if (nameMatch) return nameMatch[1].trim();
        const email = normalizeEmail(input);
        const localPart = email.split('@')[0];
        return localPart
          .replace(/[._-]/g, ' ')
          .split(' ')
          .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
          .join(' ');
      };

      // Helper to get/create node
      const getOrCreateNode = (emailStr: string) => {
        const email = normalizeEmail(emailStr);
        if (!nodeMap.has(email)) {
          const domain = email.includes('@') ? email.split('@')[1] : null;
          nodeMap.set(email, {
            id: email,
            email,
            name: getDisplayName(emailStr),
            domain,
            sentCount: 0,
            receivedCount: 0,
            totalMessages: 0,
            isInternal: false, // Will be computed later based on domain frequency
          });
        }
        return nodeMap.get(email)!;
      };

      // Helper to create edge key (always alphabetically sorted for consistency)
      const getEdgeKey = (a: string, b: string) => {
        const normalized = [normalizeEmail(a), normalizeEmail(b)].sort();
        return `${normalized[0]}|${normalized[1]}`;
      };

      // Process communications
      for (const comm of filtered) {
        if (!comm.sender) continue;

        const senderNode = getOrCreateNode(comm.sender);
        senderNode.sentCount++;
        senderNode.totalMessages++;

        // Process recipients
        const recipients = Array.isArray(comm.recipients) ? comm.recipients : [];
        for (const recipient of recipients) {
          if (!recipient || typeof recipient !== 'string') continue;

          const recipientNode = getOrCreateNode(recipient);
          recipientNode.receivedCount++;
          recipientNode.totalMessages++;

          // Create/update edge
          const edgeKey = getEdgeKey(comm.sender, recipient);
          if (!edgeMap.has(edgeKey)) {
            edgeMap.set(edgeKey, {
              source: normalizeEmail(comm.sender),
              target: normalizeEmail(recipient),
              weight: 0,
              messages: [],
            });
          }
          const edge = edgeMap.get(edgeKey)!;
          edge.weight++;
          if (edge.messages.length < 5) {
            edge.messages.push(comm.id);
          }
        }
      }

      // Determine internal domains (domains with most emails)
      const domainCounts = new Map<string, number>();
      for (const node of nodeMap.values()) {
        if (node.domain) {
          domainCounts.set(node.domain, (domainCounts.get(node.domain) || 0) + node.totalMessages);
        }
      }
      const sortedDomains = [...domainCounts.entries()].sort((a, b) => b[1] - a[1]);
      const internalDomains = new Set(sortedDomains.slice(0, 3).map(d => d[0]));

      // Mark internal nodes
      for (const node of nodeMap.values()) {
        node.isInternal = node.domain ? internalDomains.has(node.domain) : false;
      }

      // Filter nodes by minimum message count
      const filteredNodes = [...nodeMap.values()].filter(n => n.totalMessages >= minMessages);
      const nodeIds = new Set(filteredNodes.map(n => n.id));

      // Filter edges to only include nodes that passed the filter
      const filteredEdges = [...edgeMap.values()].filter(
        e => nodeIds.has(e.source) && nodeIds.has(e.target)
      );

      // Calculate max values for normalization
      const maxMessages = Math.max(...filteredNodes.map(n => n.totalMessages), 1);
      const maxEdgeWeight = Math.max(...filteredEdges.map(e => e.weight), 1);

      res.json({
        nodes: filteredNodes.map(n => ({
          ...n,
          normalizedSize: Math.sqrt(n.totalMessages / maxMessages),
        })),
        edges: filteredEdges.map(e => ({
          ...e,
          normalizedWeight: e.weight / maxEdgeWeight,
        })),
        stats: {
          totalNodes: filteredNodes.length,
          totalEdges: filteredEdges.length,
          totalCommunications: filtered.length,
          internalDomains: [...internalDomains],
        },
      });
    } catch (error: any) {
      console.error("Error computing network graph:", error);
      res.status(500).json({ message: error.message });
    }
  });

