  app.get("/api/cases/:caseId/timeline", isAuthenticated, requireRole("admin", "attorney", "compliance_officer"), async (req, res) => {
    try {
      // Validate query parameters with Zod
      const querySchema = z.object({
        showHidden: z.string().optional().transform(val => val === 'true' ? true : undefined),
        eventTypes: z.union([z.string(), z.array(z.string())]).optional().transform(val => 
          val ? (Array.isArray(val) ? val : [val]) : undefined
        ),
        dateFrom: z.string().optional().refine(val => !val || !isNaN(Date.parse(val)), {
          message: "Invalid dateFrom format"
        }).transform(val => val ? new Date(val) : undefined),
        dateTo: z.string().optional().refine(val => !val || !isNaN(Date.parse(val)), {
          message: "Invalid dateTo format"
        }).transform(val => val ? new Date(val) : undefined),
        minImportance: z.string().optional().refine(val => !val || !isNaN(parseInt(val, 10)), {
          message: "Invalid minImportance value"
        }).transform(val => val ? parseInt(val, 10) : undefined),
      });
      
      const validated = querySchema.safeParse(req.query);
      if (!validated.success) {
        return res.status(400).json({ message: "Invalid query parameters", errors: validated.error.errors });
      }
      
      const filters = validated.data;
      const events = await storage.getCaseTimelineEvents(req.params.caseId, filters);
      res.json(events);
    } catch (error: any) {
      console.error("Error fetching timeline events:", error);
      res.status(500).json({ message: error.message });
    }
  });

