  // Ask About Case - AI-powered investigation assistant
  app.post("/api/cases/:caseId/ask", isAuthenticated, requireRole("admin", "attorney", "compliance_officer"), async (req: any, res) => {
    try {
      const caseId = req.params.caseId;
      const userId = req.user.id;
      const userRole = req.user.role;

      // Validate case exists
      const caseData = await storage.getCase(caseId);
      if (!caseData) {
        return res.status(404).json({ message: "Case not found" });
      }

      // Per-case authorization: Verify user has access to this specific case
      // Admins and compliance officers have global access
      if (userRole !== "admin" && userRole !== "compliance_officer") {
        // Check if user is case creator or assigned to the case
        const isAssigned = await db.query.caseAssignments.findFirst({
          where: and(
            eq(schema.caseAssignments.caseId, caseId),
            eq(schema.caseAssignments.userId, userId)
          ),
        });

        if (caseData.createdBy !== userId && !isAssigned) {
          return res.status(403).json({ message: "You do not have permission to access this case" });
        }
      }

      // Validate request body
      const validation = askCaseRequestSchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({ 
          message: "Invalid request", 
          errors: validation.error.errors 
        });
      }

      // Call the investigation service
      const result = await askAboutCase(caseId, validation.data, userId);

      await logAction(req, "case_ai_question", "case", caseId, { 
        question: validation.data.question.substring(0, 100),
        evidenceCount: result.evidenceItems.length 
      });

      res.json(result);
    } catch (error: any) {
      console.error("Error asking about case:", error);
      res.status(500).json({ message: error.message });
    }
  });

