  app.post("/api/admin/ai-recommendations/:caseId", isAuthenticated, requireRole("admin", "compliance_officer"), async (req, res) => {
    try {
      // Get case details with related communications and alerts
      const caseData = await storage.getCase(req.params.caseId);
      if (!caseData) {
        return res.status(404).json({ message: "Case not found" });
      }

      // Get related communications if alert exists
      let commDetails = null;
      if (caseData.alertId) {
        const alert = await storage.getAlert(caseData.alertId);
        if (alert) {
          commDetails = await storage.getCommunication(alert.communicationId);
        }
      }

      // Get applicable regulations
      const regulations = await storage.getRegulations();
      const applicableRegs = regulations.filter(r => 
        r.framework === caseData.violationType ||
        (r.tags && Array.isArray(r.tags) && r.tags.includes(caseData.violationType))
      );

      // Build AI prompt for recommendations
      const prompt = `You are a legal compliance AI assistant for Sentinel Counsel LLP. Analyze this case and provide detailed next steps recommendations.

Case Information:
- Case Number: ${caseData.caseNumber}
- Title: ${caseData.title}
- Violation Type: ${caseData.violationType}
- Status: ${caseData.status}
- Priority: ${caseData.priority}
- Description: ${caseData.description || 'N/A'}
${commDetails ? `
Communication Context:
- From: ${commDetails.sender}
- Subject: ${commDetails.subject || 'N/A'}
- Body: ${commDetails.body?.substring(0, 500) || 'N/A'}
` : ''}

Applicable Regulations:
${applicableRegs.map(r => `- ${r.title}: ${r.description?.substring(0, 200) || 'N/A'}`).join('\n')}

Based on this case information, provide:
1. Immediate Next Steps (3-5 specific action items)
2. Investigation Strategy (key areas to focus on)
3. Risk Assessment (potential legal risks and exposure)
4. Documentation Recommendations (what evidence to gather)
5. Timeline Recommendations (suggested milestones)
6. Regulatory Compliance Considerations (specific requirements to follow)

Format your response as JSON with these keys: immediateSteps (array), investigationStrategy (string), riskAssessment (string), documentationNeeds (array), timeline (string), regulatoryConsiderations (string)`;

      const completion = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: "You are a legal compliance AI assistant. Provide detailed, actionable recommendations for compliance investigations. Always respond in valid JSON format."
          },
          {
            role: "user",
            content: prompt
          }
        ],
        temperature: 0.7,
        response_format: { type: "json_object" }
      });

      const recommendations = JSON.parse(completion.choices[0].message.content || "{}");
      
      await logAction(req, "ai_recommendations_generated", "case", caseData.id);
      res.json({
        caseId: caseData.id,
        caseNumber: caseData.caseNumber,
        recommendations
      });
    } catch (error: any) {
      console.error("Error generating AI recommendations:", error);
      res.status(500).json({ message: error.message });
    }
  });

