  // Export tagged documents to Excel with file type breakdown
  app.get("/api/tags/:tagId/export-excel", isAuthenticated, async (req: any, res) => {
    try {
      const { tagId } = req.params;
      const caseId = req.query.caseId as string | undefined;
      
      // Get tag info
      const tagInfo = await db.select().from(schema.tags).where(eq(schema.tags.id, tagId)).limit(1);
      if (!tagInfo.length) {
        return res.status(404).json({ message: "Tag not found" });
      }
      const tag = tagInfo[0];
      
      // Get all documents for this tag
      const documents = await storage.getDocumentsForTag(tagId, caseId);
      
      // Calculate file type breakdown
      let emailCount = 0;
      let pdfCount = 0;
      let wordCount = 0;
      let excelCount = 0;
      let otherCount = 0;
      
      for (const doc of documents) {
        const ext = (doc.fileExtension || '').toLowerCase();
        const mime = (doc.mimeType || '').toLowerCase();
        const type = (doc.communicationType || '').toLowerCase();
        
        if (type === 'email' || ext === '.eml' || ext === '.msg') {
          emailCount++;
        } else if (ext === '.pdf' || mime.includes('pdf')) {
          pdfCount++;
        } else if (ext === '.doc' || ext === '.docx' || mime.includes('word') || mime.includes('document')) {
          wordCount++;
        } else if (ext === '.xls' || ext === '.xlsx' || mime.includes('excel') || mime.includes('spreadsheet')) {
          excelCount++;
        } else {
          otherCount++;
        }
      }
      
      const totalCount = documents.length;
      
      // Create Excel workbook
      const ExcelJS = (await import('exceljs')).default;
      const workbook = new ExcelJS.Workbook();
      workbook.creator = 'Sentinel Counsel LLP';
      workbook.created = new Date();
      
      const worksheet = workbook.addWorksheet('Tag Report');
      
      // Add headers
      worksheet.columns = [
        { header: 'Search Terms Applied', key: 'searchTerms', width: 40 },
        { header: 'Total Files Responsive', key: 'total', width: 20 },
        { header: 'Emails Responsive', key: 'emails', width: 20 },
        { header: 'PDFs Responsive', key: 'pdfs', width: 20 },
        { header: 'Word Docs Responsive', key: 'word', width: 20 },
        { header: 'Excel Docs Responsive', key: 'excel', width: 20 },
        { header: 'Other Docs Responsive', key: 'other', width: 20 },
      ];
      
      // Style header row
      worksheet.getRow(1).font = { bold: true };
      worksheet.getRow(1).fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: 'FFE0E0E0' }
      };
      
      // Add data row
      worksheet.addRow({
        searchTerms: tag.name,
        total: totalCount,
        emails: emailCount,
        pdfs: pdfCount,
        word: wordCount,
        excel: excelCount,
        other: otherCount,
      });
      
      // Add summary section
      worksheet.addRow([]);
      worksheet.addRow(['Document Details']);
      worksheet.addRow(['Subject', 'Sender', 'Date', 'Type', 'File Extension']);
      
      const headerRow = worksheet.lastRow;
      if (headerRow) {
        headerRow.font = { bold: true };
        headerRow.fill = {
          type: 'pattern',
          pattern: 'solid',
          fgColor: { argb: 'FFE0E0E0' }
        };
      }
      
      // Add document details
      for (const doc of documents) {
        worksheet.addRow([
          doc.subject || 'Untitled',
          doc.sender || '',
          doc.timestamp ? new Date(doc.timestamp).toLocaleDateString() : '',
          doc.communicationType || 'Document',
          doc.fileExtension || '',
        ]);
      }
      
      // Set response headers
      res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
      res.setHeader('Content-Disposition', `attachment; filename="${tag.name.replace(/[^a-z0-9]/gi, "_")}_report.xlsx"`);
      
      // Write to response
      await workbook.xlsx.write(res);
      res.end();
      
    } catch (error: any) {
      console.error("Error exporting tag to Excel:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Tag Usage Report - Get statistics on tag usage for a case
  app.get("/api/cases/:caseId/tags/usage-report", isAuthenticated, requireRole("admin", "attorney", "compliance_officer"), async (req, res) => {
    try {
      const { caseId } = req.params;
      
      // Get all communications and chat messages for this case
      const caseComms = await db
        .select({ id: communications.id })
        .from(communications)
        .where(eq(communications.caseId, caseId));
      
      const caseChats = await db
        .select({ id: ingestedChatMessages.id })
        .from(ingestedChatMessages)
        .where(eq(ingestedChatMessages.caseId, caseId));
      
      const commIds = caseComms.map(c => c.id);
      const chatIds = caseChats.map(c => c.id);
      const totalDocuments = commIds.length + chatIds.length;
      
      // Get all tags
      const allTags = await db
        .select()
        .from(schema.tags)
        .orderBy(schema.tags.name);
      
      interface TagUsageStats {
        tagId: string;
        tagName: string;
        category: string;
        color: string;
        documentCount: number;
        communicationCount: number;
        chatMessageCount: number;
        uniqueApplicators: number;
        usagePercentage: number;
        isPreset: boolean;
      }
      
      const tagStats: TagUsageStats[] = [];
      
      for (const tag of allTags) {
        // Count communications tagged with this tag
        const commDocTags = await db
          .select()
          .from(schema.documentTags)
          .where(
            and(
              eq(schema.documentTags.tagId, tag.id),
              eq(schema.documentTags.entityType, 'communication'),
              inArray(schema.documentTags.entityId, commIds.length > 0 ? commIds : [''])
            )
          );
        
        // Count chat messages tagged with this tag
        const chatDocTags = await db
          .select()
          .from(schema.documentTags)
          .where(
            and(
              eq(schema.documentTags.tagId, tag.id),
              eq(schema.documentTags.entityType, 'chat_message'),
              inArray(schema.documentTags.entityId, chatIds.length > 0 ? chatIds : [''])
            )
          );
        
        const totalTagCount = commDocTags.length + chatDocTags.length;
        
        if (totalTagCount > 0) {
          // Count unique applicators (users who tagged)
          const allTaggedBy = [...commDocTags.map(dt => dt.taggedBy), ...chatDocTags.map(dt => dt.taggedBy)];
          const uniqueApplicators = new Set(allTaggedBy).size;
          
          tagStats.push({
            tagId: tag.id,
            tagName: tag.name,
            category: tag.category,
            color: tag.color,
            documentCount: totalTagCount,
            communicationCount: commDocTags.length,
            chatMessageCount: chatDocTags.length,
            uniqueApplicators,
            usagePercentage: totalDocuments > 0 ? (totalTagCount / totalDocuments) * 100 : 0,
            isPreset: tag.isPreset,
          });
        }
      }
      
      // Sort by document count (descending)
      tagStats.sort((a, b) => b.documentCount - a.documentCount);
      
      res.json({
        caseId,
        totalDocuments,
        totalCommunications: commIds.length,
        totalChatMessages: chatIds.length,
        tagStats,
        generatedAt: new Date().toISOString(),
      });
    } catch (error: any) {
      console.error("Error generating tag usage report:", error);
      res.status(500).json({ message: error.message });
    }
  });

