  app.post("/api/document-codings", isAuthenticated, requireRole("admin", "attorney", "compliance_officer"), async (req: any, res) => {
    try {
      const validated = schema.insertDocumentCodingSchema.parse(req.body);
      const coding = await storage.saveDocumentCoding({
        ...validated,
        reviewerId: req.user.id,
      });
      await logAction(req, "document_coded", "communication", validated.documentId);

      // Parse @mentions from review notes and send notifications
      if (validated.reviewNotes) {
        const { parseMentions, saveAnnotationMentions, createNotification } = await import('./services/notification-service');
        const mentionedUserIds = parseMentions(validated.reviewNotes);
        
        if (mentionedUserIds.length > 0) {
          // Save mention records
          await saveAnnotationMentions(coding.id, mentionedUserIds, req.user.id);

          // Create notifications for each mentioned user
          const mentionedByName = `${req.user.firstName || ""} ${req.user.lastName || ""}`.trim() || req.user.email;
          for (const userId of mentionedUserIds) {
            // Skip self-mentions
            if (userId === req.user.id) continue;

            // Get document info for the notification
            const communication = await storage.getCommunication(validated.documentId);
            const documentTitle = communication?.subject || "Document";

            await createNotification(
              userId,
              "annotation_mention",
              `${mentionedByName} mentioned you in an annotation`,
              `You were mentioned in an annotation on "${documentTitle}"`,
              `/document-review?id=${validated.documentId}`,
              {
                documentId: validated.documentId,
                caseId: validated.caseId,
                mentionedBy: req.user.id,
                codingId: coding.id,
              }
            );
          }
        }
      }

      res.json(coding);
    } catch (error: any) {
      console.error("Error saving document coding:", error);
      res.status(400).json({ message: error.message });
    }
  });

