      if (updates.upjohnWarningTimestamp && typeof updates.upjohnWarningTimestamp === 'string') {
        updates.upjohnWarningTimestamp = new Date(updates.upjohnWarningTimestamp);
      }
      if (updates.completedAt && typeof updates.completedAt === 'string') {
        updates.completedAt = new Date(updates.completedAt);
      }
      if (updates.scheduledFor && typeof updates.scheduledFor === 'string') {
        updates.scheduledFor = new Date(updates.scheduledFor);
      }
      if (updates.privilegeAssertedAt && typeof updates.privilegeAssertedAt === 'string') {
        updates.privilegeAssertedAt = new Date(updates.privilegeAssertedAt);
      }
      
      const interview = await storage.updateInterview(req.params.id, updates);
      
      // Log specific actions based on what was updated
      if (req.body.upjohnWarningGiven === "true") {
        await logAction(req, "upjohn_warning_given", "interview", interview.id);
      }
      if (req.body.consentObtained === "true") {
        await logAction(req, "consent_obtained", "interview", interview.id);
      }
      if (req.body.recordingUrl) {
        await logAction(req, "recording_uploaded", "interview", interview.id);
      }
      if (req.body.transcriptText || req.body.transcriptUrl) {
        await logAction(req, "transcript_uploaded", "interview", interview.id);
      }
      if (req.body.privilegeAssertedBy) {
        await logAction(req, "privilege_asserted", "interview", interview.id);
      }
      
      res.json(interview);
