  // Schedule live interview and send invitation
  app.post("/api/interviews/schedule-live", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const {
        caseId,
        intervieweeName,
        intervieweeEmail,
        intervieweePhone,
        interviewType,
        scheduledFor,
        location,
        meetingLink,
        purpose,
        deliveryChannel,
      } = req.body;

      // Generate unique access token for instant link sharing
      const accessToken = nanoid(32);
      
      // Create the interview record
      const interviewData = {
        caseId,
        intervieweeName,
        intervieweeEmail: intervieweeEmail || "",
        interviewerIds: [req.user.id], // Current user as interviewer
        interviewType: interviewType === "virtual" ? "investigative" : "fact_finding", // Map to valid types
        scheduledFor: new Date(scheduledFor),
        status: "scheduled",
        notes: purpose || undefined,
        location: location || undefined,
        meetingLink: meetingLink || undefined,
        accessToken,
      };

      const interview = await storage.createInterview(interviewData);

      // Send invitation email
      if (deliveryChannel === "email" || deliveryChannel === "both") {
        if (!intervieweeEmail) {
          throw new Error("Email address is required for email delivery");
        }
        
        // Format the scheduled date/time
        const scheduledDate = new Date(scheduledFor);
        const formattedDateTime = scheduledDate.toLocaleString("en-US", {
          weekday: "long",
          year: "numeric",
          month: "long",
          day: "numeric",
          hour: "numeric",
          minute: "2-digit",
          timeZoneName: "short"
        });

        // Prepare email content
        const emailSubject = `Interview Scheduled: ${intervieweeName}`;
        const locationInfo = interviewType === "in_person" 
          ? `Location: ${location}`
          : interviewType === "virtual"
          ? `Meeting Link: ${meetingLink}`
          : `This will be a phone call`;

        const emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 0 auto; padding: 20px; }
    .header { background-color: #1e40af; color: white; padding: 20px; text-align: center; }
    .content { padding: 20px; background-color: #f9fafb; }
    .details { background-color: white; padding: 15px; border-left: 4px solid #1e40af; margin: 20px 0; }
    .footer { text-align: center; padding: 20px; color: #6b7280; font-size: 14px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>Interview Scheduled</h1>
    </div>
    <div class="content">
      <p>Dear ${intervieweeName},</p>
      <p>You have been scheduled for an interview as part of case <strong>${caseId}</strong>.</p>
      <div class="details">
        <h3>Interview Details:</h3>
        <ul>
          <li><strong>Date & Time:</strong> ${formattedDateTime}</li>
          <li><strong>Type:</strong> ${interviewType === "in_person" ? "In-Person" : interviewType === "phone" ? "Phone Call" : "Virtual Meeting"}</li>
          <li><strong>${locationInfo}</strong></li>
          ${purpose ? `<li><strong>Purpose:</strong> ${purpose}</li>` : ""}
        </ul>
      </div>
      <p>Please confirm your attendance by replying to this email.</p>
      <p>If you have any questions or need to reschedule, please contact us immediately.</p>
      <p>Best regards,<br><strong>Sentinel Counsel LLP</strong></p>
    </div>
    <div class="footer">
      This is an automated message. Please do not reply directly to this email.
    </div>
  </div>
</body>
</html>
        `.trim();

        await emailService.sendEmail({
          to: intervieweeEmail,
          subject: emailSubject,
          html: emailHtml,
        });
      }

      // Send invitation SMS
      if (deliveryChannel === "sms" || deliveryChannel === "both") {
        if (!intervieweePhone) {
          throw new Error("Phone number is required for SMS delivery");
        }

        const scheduledDate = new Date(scheduledFor);
        const formattedDate = scheduledDate.toLocaleDateString("en-US");
        const formattedTime = scheduledDate.toLocaleTimeString("en-US", {
          hour: "numeric",
          minute: "2-digit"
        });

        const smsMessage = `Interview scheduled for ${formattedDate} at ${formattedTime}. ${
          interviewType === "in_person" ? `Location: ${location}` : 
          interviewType === "virtual" ? `Meeting link will be sent via email` : 
          `You will receive a phone call`
        }. Reply to confirm. - Sentinel Counsel`;

        await smsService.sendSMS({
          to: intervieweePhone,
          message: smsMessage,
        });
      }

      await logAction(req, "interview_scheduled", "interview", interview.id);
      
      res.json({
        success: true,
        interview,
        message: `Interview scheduled successfully. Invitation sent via ${deliveryChannel}.`
      });
    } catch (error: any) {
      console.error("Error scheduling live interview:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Helper function to provide investigation type context
  function getCategoryContext(category: string): string {
    const categoryContextMap: Record<string, string> = {
      fcpa: "FCPA (Foreign Corrupt Practices Act) - Focus on bribery of foreign officials, recordkeeping violations, internal controls, facilitation payments, and third-party intermediaries.",
      banking: "Banking Compliance - Focus on BSA/AML requirements, suspicious activity reporting, know-your-customer protocols, wire transfer compliance, and regulatory reporting.",
      antitrust: "Antitrust/Competition Law - Focus on price-fixing agreements, market allocation, bid-rigging, monopolization attempts, trade association activities, and competitor communications.",
      sec: "SEC Compliance - Focus on securities fraud, insider trading, disclosure violations, accounting fraud, financial reporting accuracy, and control deficiencies.",
      sox: "Sarbanes-Oxley Act - Focus on financial reporting accuracy, internal controls over financial reporting (ICFR), certification requirements, and whistleblower protections.",
      harassment: "Workplace Harassment - Focus on unwelcome conduct, hostile work environment, quid pro quo harassment, reporting mechanisms, and witness corroboration per Title VII and state laws.",
      discrimination: "Workplace Discrimination - Focus on protected characteristics (race, gender, age, disability, etc.), disparate treatment, disparate impact, reasonable accommodations, and retaliation per Title VII, ADA, ADEA.",
      retaliation: "Workplace Retaliation - Focus on protected activity, adverse employment actions, causal connection, temporal proximity, and witness testimony per federal and state whistleblower laws.",
      whistleblower: "Whistleblower Complaint - Focus on protected disclosure, good faith belief, reporting channels, employer response, and retaliation protection under SOX, Dodd-Frank, and state laws.",
      theft_fraud: "Theft/Fraud Investigation - Focus on misappropriation, unauthorized access, false statements, financial losses, intent, and documentary evidence.",
      policy_violation: "Policy Violation - Focus on specific policy language, employee knowledge of policy, prior violations, mitigating circumstances, and corrective actions.",
      other: "General Investigation - Focus on fact-finding, timeline establishment, witness knowledge, documentary evidence, and compliance with applicable laws and company policies.",
    };
    return categoryContextMap[category] || "";
  }

  // Helper function to fetch relevant regulations and policies
  async function getRelevantDocumentsForCategory(storage: IStorage, category: string | undefined, narrative: string): Promise<string[]> {
    const documents: string[] = [];
    
    try {
      // Fetch regulations relevant to category
      if (category) {
        const regulations = await storage.getRegulations();
        const relevantRegulations = regulations.filter(reg => {
          // Match category keywords in regulation titles/descriptions
          const searchText = `${reg.title} ${reg.description || ""}`.toLowerCase();
          const categoryKeywords = getCategoryKeywords(category);
          return categoryKeywords.some(keyword => searchText.includes(keyword));
        }).slice(0, 3); // Limit to top 3 regulations
        
        relevantRegulations.forEach(reg => {
          documents.push(`**Regulation: ${reg.title}**\n${reg.description || ""}\nKey Requirements: ${(reg.keyRequirements || []).join("; ")}`);
        });
      }
      
      // Fetch company policies relevant to narrative
      const policies = await storage.getPolicies();
      const relevantPolicies = policies.filter(policy => {
        const policyText = `${policy.title} ${policy.description || ""}`.toLowerCase();
        const narrativeWords = narrative.toLowerCase().split(/\s+/).filter(word => word.length > 4);
        // Match if policy mentions key terms from narrative
        return narrativeWords.some(word => policyText.includes(word));
      }).slice(0, 2); // Limit to top 2 policies
      
      relevantPolicies.forEach(policy => {
        documents.push(`**Company Policy: ${policy.title}**\n${policy.description || ""}`);
      });
    } catch (error) {
      console.error("Error fetching relevant documents:", error);
      // Continue with empty documents array
    }
    
    return documents;
  }

  // Helper function to get category search keywords
  function getCategoryKeywords(category: string): string[] {
    const keywordMap: Record<string, string[]> = {
      fcpa: ["fcpa", "foreign corrupt", "bribery", "anti-corruption"],
      banking: ["bank secrecy", "bsa", "aml", "anti-money laundering", "suspicious activity"],
      antitrust: ["antitrust", "sherman act", "clayton act", "price fixing", "competition"],
      sec: ["securities", "sec", "insider trading", "10-k", "10-q", "disclosure"],
      sox: ["sarbanes", "sox", "section 302", "section 404", "financial reporting"],
      harassment: ["harassment", "hostile environment", "title vii", "sexual harassment"],
      discrimination: ["discrimination", "title vii", "ada", "adea", "equal employment"],
      retaliation: ["retaliation", "whistleblower", "adverse action", "protected activity"],
      whistleblower: ["whistleblower", "qui tam", "dodd-frank", "protected disclosure"],
      theft_fraud: ["fraud", "theft", "embezzlement", "misappropriation"],
      policy_violation: ["policy", "code of conduct", "employee handbook"],
      other: [],
    };
    return keywordMap[category] || [];
  }

  // Helper function to fetch document context from Document Sets and tagged items
  async function getDocumentContextForQuestions(storage: IStorage, documentSetIds?: string[], tagIds?: string[]): Promise<string[]> {
    const documents: string[] = [];
    const maxDocuments = 10; // Limit to prevent token overflow
    const maxContentLength = 1500; // Max chars per document excerpt
    
    try {
      // Fetch documents from Document Sets
      if (documentSetIds && documentSetIds.length > 0) {
        for (const setId of documentSetIds.slice(0, 3)) { // Limit to 3 sets
          try {
            const documentSet = await storage.getDocumentSet(setId);
            if (documentSet) {
              // Fetch communications that are members of this set
              const communications = await storage.getDocumentsInSet(setId);
              
              for (const communication of communications.slice(0, maxDocuments)) {
                const excerpt = communication.content
                  ? communication.content.substring(0, maxContentLength)
                  : communication.summary || "";
                documents.push(
                  `**Document from Set "${documentSet.name}"**\n` +
                  `From: ${communication.sender || "Unknown"}\n` +
                  `To: ${communication.recipients?.join(", ") || "Unknown"}\n` +
                  `Date: ${communication.timestamp ? new Date(communication.timestamp).toLocaleDateString() : "Unknown"}\n` +
                  `Subject: ${communication.subject || "No subject"}\n` +
                  `Content: ${excerpt}${excerpt.length >= maxContentLength ? "..." : ""}`
                );
              }
            }
          } catch (err) {
            console.error(`Error fetching document set ${setId}:`, err);
          }
        }
      }
      
      // Fetch documents and communications tagged with specified tags
      if (tagIds && tagIds.length > 0) {
        for (const tagId of tagIds.slice(0, 5)) { // Limit to 5 tags
          try {
            const tag = await storage.getTag(tagId);
            if (!tag) continue;
            
            // Query document_tags table to find communications with this tag
            const taggedEntries = await db
              .select()
              .from(documentTags)
              .where(
                and(
                  eq(documentTags.tagId, tagId),
                  eq(documentTags.entityType, "communication")
                )
              )
              .limit(maxDocuments);
            
            // Fetch the actual communications
            for (const entry of taggedEntries) {
              try {
                const communication = await storage.getCommunication(entry.entityId);
                if (communication) {
                  const excerpt = communication.content
                    ? communication.content.substring(0, maxContentLength)
                    : communication.summary || "";
                  documents.push(
                    `**Document Tagged "${tag.name}"**\n` +
                    `From: ${communication.sender || "Unknown"}\n` +
                    `To: ${communication.recipients?.join(", ") || "Unknown"}\n` +
                    `Date: ${communication.timestamp ? new Date(communication.timestamp).toLocaleDateString() : "Unknown"}\n` +
                    `Subject: ${communication.subject || "No subject"}\n` +
                    `Content: ${excerpt}${excerpt.length >= maxContentLength ? "..." : ""}`
                  );
                }
              } catch (commErr) {
                console.error(`Error fetching communication ${entry.entityId}:`, commErr);
              }
            }
          } catch (err) {
            console.error(`Error fetching communications for tag ${tagId}:`, err);
          }
        }
      }
    } catch (error) {
      console.error("Error fetching document context:", error);
      // Continue with empty documents array
    }
    
    return documents.slice(0, maxDocuments); // Final limit
  }

