  // Get signaling token for WebRTC connection (authenticated, authorized access to specific session)
  app.post("/api/live-interview-sessions/:id/signaling-token", isAuthenticated, async (req: any, res) => {
    try {
      const session = await storage.getLiveInterviewSession(req.params.id);
      if (!session) {
        return res.status(404).json({ message: "Session not found" });
      }
      
      // Verify user has access to this session
      // Check if they are on the case (for internal users) or if they're a participant
      const user = req.user;
      const participants = await storage.getLiveInterviewParticipants(session.id);
      
      // Allow if user is on the case team, is admin/attorney/compliance_officer, or is a participant
      const isParticipant = participants.some(p => p.userId === user.id);
      const hasRoleAccess = ["admin", "compliance_officer", "attorney"].includes(user.role);
      
      if (!hasRoleAccess && !isParticipant) {
        return res.status(403).json({ message: "Not authorized to join this session" });
      }
      
      // Determine participant role
      const existingParticipant = participants.find(p => p.userId === user.id);
      const role = existingParticipant?.role || req.body.role || 
        (session.interviewerId === user.id ? "interviewer" : "attendee");
      
      // Import the token generator
      const { generateSignalingToken } = require('./webrtc-signaling');
      
      const token = generateSignalingToken({
        sessionId: session.id,
        userId: user.id,
        userName: `${user.firstName || ''} ${user.lastName || ''}`.trim() || user.email || 'Unknown',
        role,
        roomId: session.roomId,
      });
      
      await logAction(req, "signaling_token_generated", "live_interview_session", session.id);
      
      res.json({ 
        token, 
        roomId: session.roomId,
        expiresIn: 300, // 5 minutes
        sessionId: session.id,
      });
    } catch (error: any) {
      console.error("Error generating signaling token:", error);
      res.status(500).json({ message: error.message });
    }
  });

