  app.post("/api/live-interview-sessions/:sessionId/recordings/:recordingId/upload-url", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { sessionId, recordingId } = req.params;
      
      // Validate session exists
      const session = await storage.getLiveInterviewSession(sessionId);
      if (!session) {
        return res.status(404).json({ message: "Session not found" });
      }
      
      // Get signed URL for upload
      const objectStorageService = new ObjectStorageService();
      const uploadUrl = await objectStorageService.getObjectEntityUploadURL();
      
      // The upload URL contains the object path in the URL
      // Extract the path for storing in the recording record
      const urlObj = new URL(uploadUrl);
      const pathMatch = urlObj.pathname.match(/\/([^?]+)/);
      const objectPath = pathMatch ? `/objects/uploads/${nanoid()}` : null;
      
      console.log(`[Recording Upload] Generated upload URL for recording ${recordingId} in session ${sessionId}`);
      
      res.json({
        uploadUrl,
        objectPath,
        recordingId,
        sessionId
      });
    } catch (error: any) {
      console.error("Error getting recording upload URL:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Complete recording upload and trigger transcription
  app.post("/api/live-interview-sessions/:sessionId/recordings/:recordingId/complete-upload", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { sessionId, recordingId } = req.params;
      const { objectPath, fileName, fileSize, duration, transcribe = true } = req.body;
      
      // Validate session exists
      const session = await storage.getLiveInterviewSession(sessionId);
      if (!session) {
        return res.status(404).json({ message: "Session not found" });
      }
      
      // Update recording with storage path and mark as processing
      const updateData: any = {
        storageUrl: objectPath,
        fileSize,
        duration,
        status: transcribe ? "processing" : "completed"
      };
      
      const recording = await storage.updateInterviewRecording(recordingId, updateData);
      
      await logAction(req, "recording_uploaded", "interview_recording", recordingId, {
        objectPath,
        fileSize,
        duration,
        willTranscribe: transcribe
      });
      
      console.log(`[Recording Upload] Recording ${recordingId} uploaded to ${objectPath}`);
      
      // If transcription is requested, trigger it asynchronously
      if (transcribe && objectPath) {
        (async () => {
          try {
            console.log(`[Transcription] Starting transcription for recording ${recordingId}`);
            
            // Fetch video file from object storage
            const objectStorageService = new ObjectStorageService();
            const objectFile = await objectStorageService.getObjectEntityFile(objectPath);
            const [fileContents] = await objectFile.download();
            
            // Use ElevenLabs transcription service
            const transcription = await transcribeVideoFile(fileContents, {
              mimeType: 'video/webm',
              filename: fileName || 'recording.webm'
            });
            
            if (transcription && transcription.segments) {
              // Create transcript segments in bulk
              // Group words into sentence-like segments based on timing
              const sentenceSegments: any[] = [];
              let currentSentence = "";
              let sentenceStart = 0;
              let lastTimestamp = 0;
              
              transcription.segments.forEach((seg, idx) => {
                const gapMs = seg.timestampMs - lastTimestamp;
                
                // Start new segment if gap > 2 seconds or sentence ends
                if ((gapMs > 2000 && currentSentence.length > 0) || 
                    (currentSentence.endsWith('.') || currentSentence.endsWith('?') || currentSentence.endsWith('!'))) {
                  if (currentSentence.trim().length > 0) {
                    sentenceSegments.push({
                      sessionId,
                      speakerId: "unknown",
                      speakerName: "Participant",
                      speakerRole: "participant" as const,
                      text: currentSentence.trim(),
                      startTime: sentenceStart / 1000, // Convert to seconds
                      endTime: lastTimestamp / 1000,
                      confidence: seg.confidence || 0.9,
                      orderIndex: sentenceSegments.length,
                    });
                  }
                  currentSentence = seg.text;
                  sentenceStart = seg.timestampMs;
                } else {
                  currentSentence += " " + seg.text;
                }
                lastTimestamp = seg.timestampMs;
              });
              
              // Add final segment
              if (currentSentence.trim().length > 0) {
                sentenceSegments.push({
                  sessionId,
                  speakerId: "unknown",
                  speakerName: "Participant",
                  speakerRole: "participant" as const,
                  text: currentSentence.trim(),
                  startTime: sentenceStart / 1000,
                  endTime: lastTimestamp / 1000,
                  confidence: 0.9,
                  orderIndex: sentenceSegments.length,
                });
              }
              
              if (sentenceSegments.length > 0) {
                await storage.createInterviewTranscriptSegmentsBulk(sentenceSegments);
              }
              
              // Update recording with transcript URL
              await storage.updateInterviewRecording(recordingId, {
                transcriptUrl: `/api/live-interview-sessions/${sessionId}/transcript-segments`,
                status: "completed"
              });
              
              console.log(`[Transcription] Completed transcription for recording ${recordingId}: ${sentenceSegments.length} segments`);
            } else {
              console.log(`[Transcription] No segments returned for recording ${recordingId}`);
              await storage.updateInterviewRecording(recordingId, { status: "completed" });
            }
          } catch (transcribeError: any) {
            console.error(`[Transcription] Error transcribing recording ${recordingId}:`, transcribeError);
            await storage.updateInterviewRecording(recordingId, { 
              status: "failed",
            });
          }
        })();
      }
      
      res.json({
        success: true,
        recording,
        transcriptionStarted: transcribe
      });
    } catch (error: any) {
      console.error("Error completing recording upload:", error);
      res.status(500).json({ message: error.message });
    }
  });

