  // Trigger AI analysis for a completed interview session
  app.post("/api/live-interview-sessions/:sessionId/analyses", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const sessionId = req.params.sessionId;
      const analysisType = req.body.analysisType || "comprehensive";
      
      // Create analysis record with pending status
      const analysis = await storage.createInterviewAnalysis({
        sessionId,
        analysisType,
        status: "pending",
      });
      
      // Get session and transcript data
      const session = await storage.getLiveInterviewSession(sessionId);
      const segments = await storage.getInterviewTranscriptSegments(sessionId);
      const questions = await storage.getInterviewQuestions(sessionId);
      
      if (!session) {
        return res.status(404).json({ message: "Session not found" });
      }
      
      // Build transcript text for AI analysis
      const transcriptText = segments.map(seg => 
        `[${seg.speakerRole || 'Unknown'}] ${seg.text}`
      ).join('\n');
      
      // Update analysis to processing
      await storage.updateInterviewAnalysis(analysis.id, {
        status: "processing",
        startedAt: new Date(),
      });
      
      // Perform AI analysis asynchronously
      (async () => {
        try {
          const prompt = `You are an expert legal compliance investigator analyzing an interview transcript.

INTERVIEW TRANSCRIPT:
${transcriptText}

QUESTIONS ASKED:
${questions.map(q => `- ${q.questionText} (Category: ${q.category})`).join('\n')}

Provide a comprehensive analysis in the following JSON format:
{
  "summaryInsights": ["key insight 1", "key insight 2", ...],
  "keyAdmissions": ["admission 1", "admission 2", ...],
  "keyDenials": ["denial 1", "denial 2", ...],
  "riskFactors": [{"factor": "description", "severity": "low|medium|high|critical"}],
  "contradictions": [{"statement1": "...", "statement2": "...", "explanation": "..."}],
  "followUpRecommendations": ["recommendation 1", ...],
  "credibilityScore": 0-100,
  "complianceRiskScore": 0-100,
  "evasionProbability": 0-100,
  "overallScore": 0-100
}`;

          const response = await openai.chat.completions.create({
            model: "gpt-4o",
            messages: [
              { role: "system", content: "You are an expert legal compliance analyst. Respond only with valid JSON." },
              { role: "user", content: prompt }
            ],
            response_format: { type: "json_object" },
          });
          
          const analysisResult = JSON.parse(response.choices[0].message.content || '{}');
          
          await storage.updateInterviewAnalysis(analysis.id, {
            status: "completed",
            completedAt: new Date(),
            overallScore: analysisResult.overallScore,
            credibilityScore: analysisResult.credibilityScore,
            complianceRiskScore: analysisResult.complianceRiskScore,
            evasionProbability: analysisResult.evasionProbability,
            summaryInsights: analysisResult.summaryInsights,
            keyAdmissions: analysisResult.keyAdmissions,
            keyDenials: analysisResult.keyDenials,
            riskFactors: analysisResult.riskFactors,
            contradictions: analysisResult.contradictions,
            followUpRecommendations: analysisResult.followUpRecommendations,
            rawAiResponse: analysisResult,
            modelUsed: "gpt-4o",
            tokensUsed: response.usage?.total_tokens,
          });
          
          await logAction(req, "interview_analysis_completed", "interview_analysis", analysis.id);
        } catch (aiError: any) {
          console.error("AI analysis error:", aiError);
          await storage.updateInterviewAnalysis(analysis.id, {
            status: "failed",
            error: aiError.message,
          });
        }
      })();
      
      res.json(analysis);
    } catch (error: any) {
      console.error("Error triggering analysis:", error);
      res.status(500).json({ message: error.message });
    }
  });

