  app.post("/api/interview-templates/generate-questions", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { narrative, category, documentSetIds, tagIds } = req.body;
      
      // Validate narrative
      if (!narrative || typeof narrative !== "string" || narrative.trim().length === 0) {
        return res.status(400).json({ message: "Narrative is required and must be non-empty" });
      }
      
      if (narrative.length > 4000) {
        return res.status(400).json({ message: "Narrative must be less than 4000 characters" });
      }
      
      // Build investigation type context
      const categoryContext = category ? getCategoryContext(category) : "";
      
      // Fetch relevant regulations and policies for context
      const contextDocuments = await getRelevantDocumentsForCategory(storage, category, narrative);
      
      // Fetch documents from selected Document Sets and tagged documents
      const documentContext = await getDocumentContextForQuestions(storage, documentSetIds, tagIds);
      
      // Use OpenAI to generate questions from narrative
      const completion = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: `You are an expert legal compliance interviewer helping attorneys prepare for witness interviews. 
            
Your task is to convert a narrative description of areas of inquiry into specific, targeted interview questions.

${categoryContext ? `**Investigation Type Context:**\n${categoryContext}\n` : ""}
${contextDocuments.length > 0 ? `\n**Relevant Regulatory Context:**\n${contextDocuments.join("\n\n")}\n` : ""}
${documentContext.length > 0 ? `\n**Source Documents for Analysis:**\n\nThe following documents have been provided as evidence and context. Analyze these documents to understand what was being discussed, the timeline of events, and any potential compliance issues:\n\n${documentContext.join("\n\n---\n\n")}\n` : ""}

Guidelines:
- Generate 5-10 focused questions that address the key areas mentioned in the narrative
${documentContext.length > 0 ? "- **Analyze the provided documents carefully** and create questions that probe:\n  * What was being discussed in the communications\n  * Context surrounding the events mentioned in the documents\n  * In-person conversations or phone calls that may have occurred around the same time as the documented communications\n  * Undocumented meetings or discussions related to the topics in the documents\n  * The witness's knowledge of or involvement in the matters discussed\n" : ""}
- If a specific law or regulation is mentioned in the narrative or documents, ensure questions probe compliance with that law
- Reference relevant company policies, Investigation Logic rules, and regulatory frameworks when crafting questions
- Questions should be open-ended and designed to elicit detailed responses
- Use professional, neutral legal language appropriate for the investigation type
- Frame questions to uncover facts, timeline, involvement, and evidence
- Avoid leading or suggestive questions
- Each question should stand alone and be clearly worded
- Consider the specific legal standards and elements that must be proven for the investigation type

Return your response as a JSON array of objects with this format:
[
  {
    "question": "The actual question text",
    "rationale": "Brief explanation of what this question aims to uncover (reference specific laws/policies/documents if applicable)"
  }
]

Only return the JSON array, no additional text.`
          },
          {
            role: "user",
            content: `Investigation Type: ${category || "General"}\n\nNarrative:\n${narrative}${documentContext.length > 0 ? `\n\n[${documentContext.length} source documents provided above for analysis]` : ""}`
          }
        ],
        temperature: 0.7,
      });
      
      const responseText = completion.choices[0].message.content?.trim();
      if (!responseText) {
        return res.status(500).json({ message: "Failed to generate questions" });
      }
      
      // Parse JSON response
      let questions;
      try {
        questions = JSON.parse(responseText);
      } catch (parseError) {
        console.error("Failed to parse AI response:", responseText);
        return res.status(500).json({ message: "Invalid response format from AI" });
      }
      
      // Validate response structure
      if (!Array.isArray(questions)) {
        return res.status(500).json({ message: "Invalid response structure from AI" });
      }
      
      // Add IDs and metadata
      const draftQuestions = questions.map((q, index) => ({
        id: `ai-${Date.now()}-${index}`,
        question: q.question || q.text || String(q),
        rationale: q.rationale || "",
        source: "ai",
        generatedAt: new Date().toISOString(),
      }));
      
      // Audit log
      await logAction(req, "interview_questions_generated", "interview_template", undefined, {
        narrativeLength: narrative.length,
        questionsGenerated: draftQuestions.length,
        userId: req.user.id,
      });
      
      res.json({ questions: draftQuestions });
    } catch (error: any) {
      console.error("Error generating questions:", error);
      res.status(500).json({ message: error.message });
    }
  });

