  // Public route - Get upload URL for video response (no authentication required)
  app.post("/api/interview-responses/get-upload-url", async (req, res) => {
    try {
      const { interviewId, questionIndex, accessToken } = req.body;

      // Verify access token matches the interview
      const interview = await storage.getInterviewByAccessToken(accessToken);
      if (!interview || interview.id !== interviewId) {
        return res.status(403).json({ message: "Invalid access token for this interview" });
      }

      if (interview.status === "completed") {
        return res.status(410).json({ message: "This interview has already been completed" });
      }

      // Generate upload URL - this creates a signed URL with the object path embedded
      const objectStorageService = new ObjectStorageService();
      const uploadUrl = await objectStorageService.getObjectEntityUploadURL();
      
      // Extract the normalized path from the signed URL
      // The signed URL contains the actual storage path which we need to store in the database
      const objectPath = objectStorageService.normalizeObjectEntityPath(uploadUrl);

      console.log(`[Interview Response] Generated upload URL for interview ${interviewId}, question ${questionIndex}`);
      console.log(`[Interview Response] Object path: ${objectPath}`);

      res.json({
        uploadUrl,
        objectPath,
        interviewId,
        questionIndex,
      });
    } catch (error: any) {
      console.error("Error getting interview response upload URL:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Public route - Save video response after upload (no authentication required)
  app.post("/api/interview-responses/save", async (req, res) => {
    try {
      const { interviewId, questionIndex, questionText, accessToken, videoUrl } = req.body;

      // Verify access token matches the interview
      const interview = await storage.getInterviewByAccessToken(accessToken);
      if (!interview || interview.id !== interviewId) {
        return res.status(403).json({ message: "Invalid access token for this interview" });
      }

      if (interview.status === "completed") {
        return res.status(410).json({ message: "This interview has already been completed" });
      }

      // Check if response already exists for this question
      const existingResponses = await storage.getInterviewResponses(interviewId);
      const existingResponse = existingResponses.find(r => r.questionIndex === parseInt(questionIndex));

      let response;
      if (existingResponse) {
        // Update existing response
        response = await storage.updateInterviewResponse(existingResponse.id, {
          videoUrl,
          status: "uploaded",
          recordedAt: new Date(),
        });
      } else {
        // Create new response
        response = await storage.createInterviewResponse({
          interviewId,
          questionIndex: parseInt(questionIndex),
          questionText,
          videoUrl,
          status: "uploaded",
          recordedAt: new Date(),
        });
      }

      // Trigger automatic transcription asynchronously
      const responseId = response.id;
      (async () => {
        try {
          console.log(`[AUTO-TRANSCRIBE] Starting automatic transcription for response ${responseId}`);
          
          // Get the media path from the response
          const mediaPath = videoUrl;
          if (!mediaPath) {
            console.log(`[AUTO-TRANSCRIBE] No video URL for response ${responseId}, skipping`);
            return;
          }
          
          // Use ObjectStorageService to download the file
          const objectStorageService = new ObjectStorageService();
          const mediaBuffer = await objectStorageService.downloadAsBuffer(mediaPath);
          console.log(`[AUTO-TRANSCRIBE] Downloaded ${mediaBuffer.length} bytes for response ${responseId}`);
          
          // Transcribe using ElevenLabs
          const { transcribeVideoFile } = await import("./elevenlabs");
          const transcriptionResult = await transcribeVideoFile(mediaBuffer, { 
            mimeType: "video/webm", 
            filename: "response.webm" 
          });
          
          console.log(`[AUTO-TRANSCRIBE] Transcription complete for response ${responseId}: ${transcriptionResult.fullText.length} chars`);
          
          // Update the response with transcription
          await storage.updateInterviewResponse(responseId, {
            transcriptText: transcriptionResult.fullText,
            transcriptSegments: transcriptionResult.segments,
            status: "transcribed",
          });
          
          console.log(`[AUTO-TRANSCRIBE] Saved transcript for response ${responseId}`);
        } catch (transcribeError: any) {
          console.error(`[AUTO-TRANSCRIBE] Error transcribing response ${responseId}:`, transcribeError);
          // Don't fail the save if transcription fails - it can be retried manually
          await storage.updateInterviewResponse(responseId, {
            status: "transcription_failed",
          });
        }
      })();

      res.json({ 
        success: true, 
        response: {
          id: response.id,
          questionIndex: response.questionIndex,
          videoUrl: response.videoUrl,
          status: response.status,
        }
      });
    } catch (error: any) {
      console.error("Error saving interview response:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Transcribe a specific interview response (requires authentication)
  app.post("/api/interview-responses/:responseId/transcribe", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { responseId } = req.params;
      
      // Get the response
      const response = await storage.getInterviewResponse(responseId);
      if (!response) {
        return res.status(404).json({ message: "Interview response not found" });
      }

      if (!response.videoUrl && !response.audioUrl) {
        return res.status(400).json({ message: "No video or audio URL available for transcription" });
      }

      // Get the media path from object storage
      const mediaPath = response.videoUrl || response.audioUrl;
      console.log(`[TRANSCRIBE] Fetching media from object storage: ${mediaPath}`);
      
      // Use ObjectStorageService to download the file
      const objectStorageService = new ObjectStorageService();
      const mediaBuffer = await objectStorageService.downloadAsBuffer(mediaPath!);
      console.log(`[TRANSCRIBE] Media buffer size: ${mediaBuffer.length} bytes`);
      
      // Determine if it's video or audio
      const isVideo = response.videoUrl != null;
      
      // Transcribe using ElevenLabs
      const { transcribeVideoFile, transcribeAudioFile } = await import("./elevenlabs");
      const transcriptionResult = isVideo 
        ? await transcribeVideoFile(mediaBuffer, { mimeType: "video/webm", filename: "response.webm" })
        : await transcribeAudioFile(mediaBuffer, { mimeType: "audio/webm", filename: "response.webm" });
      
      console.log(`[TRANSCRIBE] Transcription complete: ${transcriptionResult.fullText.length} chars`);
      
      // Update the response with transcription
      const updatedResponse = await storage.updateInterviewResponse(responseId, {
        transcriptText: transcriptionResult.fullText,
        transcriptSegments: transcriptionResult.segments,
        status: "transcribed",
      });
      
      res.json({
        success: true,
        transcriptText: transcriptionResult.fullText,
        transcriptSegments: transcriptionResult.segments,
        duration: transcriptionResult.duration,
      });
    } catch (error: any) {
      console.error("[TRANSCRIBE] Error transcribing interview response:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Generate AI summary for an interview (requires authentication)
  app.post("/api/interviews/:interviewId/generate-summary", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { interviewId } = req.params;
      
      // Get the interview
      const interview = await storage.getInterview(interviewId);
      if (!interview) {
        return res.status(404).json({ message: "Interview not found" });
      }
      
      // Get all responses for this interview
      const responses = await storage.getInterviewResponses(interviewId);
      if (responses.length === 0) {
        return res.status(400).json({ message: "No responses available for this interview" });
      }
      
      // Check if we have transcripts
      const responsesWithTranscripts = responses.filter(r => r.transcriptText);
      if (responsesWithTranscripts.length === 0) {
        return res.status(400).json({ message: "Please transcribe responses before generating a summary" });
      }
      
      // Build the content for AI analysis
      const questions = (interview.questions as string[]) || [];
      const transcriptContent = responsesWithTranscripts.map(r => {
        const questionText = questions[r.questionIndex] || r.questionText || `Question ${r.questionIndex + 1}`;
        return `**Question ${r.questionIndex + 1}:** ${questionText}\n**Response:** ${r.transcriptText}`;
      }).join("\n\n---\n\n");
      
      // Generate AI summary using OpenAI
      const completion = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: `You are a legal compliance analyst reviewing interview transcripts. Provide a comprehensive summary that includes:
1. **Executive Summary**: A brief 2-3 sentence overview of the interview
2. **Key Points**: Bullet points of the most important statements made by the interviewee
3. **Areas of Concern**: Any statements that may warrant follow-up investigation
4. **Credibility Assessment**: Brief assessment of response consistency and completeness
5. **Recommended Actions**: Suggested next steps based on the interview content

Format your response in clear sections with headers.`
          },
          {
            role: "user",
            content: `Please analyze and summarize the following witness interview transcript for case "${interview.caseId}".\n\nInterviewee: ${interview.intervieweeName} (${interview.intervieweeEmail})\n\n${transcriptContent}`
          }
        ],
        max_tokens: 2000,
        temperature: 0.3,
      });
      
      const aiSummaryText = completion.choices[0]?.message?.content || "";
      
      // Update the interview with the AI summary
      await storage.updateInterview(interviewId, {
        aiSummaryText,
      });
      
      console.log(`[AI-SUMMARY] Generated summary for interview ${interviewId}: ${aiSummaryText.length} chars`);
      
      res.json({
        success: true,
        aiSummaryText,
      });
    } catch (error: any) {
      console.error("[AI-SUMMARY] Error generating interview summary:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Ask follow-up questions about an interview
  app.post("/api/interviews/:interviewId/ask-followup", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { interviewId } = req.params;
      const { question, context } = req.body;
      
      if (!question || typeof question !== "string") {
        return res.status(400).json({ message: "Question is required" });
      }
      
      // Get the interview
      const interview = await storage.getInterview(interviewId);
      if (!interview) {
        return res.status(404).json({ message: "Interview not found" });
      }
      
      // Build context from the interview data
      const interviewContext = context?.responses?.map((r: any, idx: number) => 
        `Q${idx + 1}: ${r.question}\nA: ${r.answer || "[No response]"}`
      ).join("\n\n") || "";
      
      const summaryContext = context?.summary || interview.aiSummaryText || "";
      
      // Use OpenAI to answer the follow-up question
      const completion = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          {
            role: "system",
            content: `You are a legal compliance analyst assistant. You have access to an interview transcript and its AI-generated summary. 
Answer questions about the interview content accurately and professionally. 
Base your answers only on the information provided in the interview transcript and summary.
If the answer cannot be determined from the available information, say so clearly.
Keep your responses concise but thorough.`
          },
          {
            role: "user",
            content: `Here is the AI-generated summary of the interview:\n\n${summaryContext}\n\n---\n\nHere is the full interview transcript:\n\n${interviewContext}\n\n---\n\nQuestion: ${question}`
          }
        ],
        max_tokens: 1000,
        temperature: 0.3,
      });
      
      const answer = completion.choices[0]?.message?.content || "I couldn't generate a response. Please try again.";
      
      console.log(`[AI-FOLLOWUP] Answered follow-up question for interview ${interviewId}`);
      
      res.json({
        success: true,
        answer,
      });
    } catch (error: any) {
      console.error("[AI-FOLLOWUP] Error answering follow-up question:", error);
      res.status(500).json({ message: error.message });
    }
  });

