  // Public route - AI Question Clarification for Witnesses
  app.post("/api/ai/clarify-question", async (req, res) => {
    try {
      const { interviewQuestion, witnessQuestion, accessToken } = req.body;

      // Validate access token exists (we don't need to verify the full interview, just that it's a valid token)
      if (!accessToken) {
        return res.status(403).json({ message: "Access token required" });
      }

      const interview = await storage.getInterviewByAccessToken(accessToken);
      if (!interview) {
        return res.status(403).json({ message: "Invalid access token" });
      }

      // Use OpenAI to generate a clarifying response
      const systemPrompt = `You are an AI assistant helping a witness understand an interview question in a legal investigation context. 
Your role is to:
1. Clarify the intent and scope of the interview question
2. Provide helpful context without leading the witness
3. Keep responses concise and professional
4. Never suggest specific answers or influence the witness's testimony
5. If the question cannot be answered (e.g., asks for legal advice), politely decline

Keep your response under 150 words.`;

      const userPrompt = `The witness is being asked this interview question:
"${interviewQuestion}"

The witness has the following clarifying question:
"${witnessQuestion}"

Please provide a helpful clarification that helps the witness understand what is being asked, without influencing their answer.`;

      const completion = await openai.chat.completions.create({
        model: "gpt-4o",
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt }
        ],
        max_tokens: 300,
        temperature: 0.3
      });

      const aiResponse = completion.choices[0]?.message?.content || "I'm sorry, I couldn't process your question. Please try rephrasing.";

      res.json({ response: aiResponse });
    } catch (error: any) {
      console.error("Error in AI clarification:", error);
      res.status(500).json({ message: "Failed to get AI clarification" });
    }
  });

