  // Transcribe recorded interview video
  app.post("/api/recorded-interviews/:id/transcribe", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      // Validate request body
      const bodySchema = z.object({
        force: z.boolean().optional(),
        language: z.string().optional()
      });
      const validation = bodySchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({ 
          message: "Invalid request body", 
          errors: validation.error.errors 
        });
      }

      const interview = await storage.getRecordedInterview(req.params.id);
      if (!interview) {
        return res.status(404).json({ message: "Recorded interview not found" });
      }

      // Validate video URL exists
      if (!interview.videoUrl) {
        return res.status(400).json({ message: "No video recording available for transcription" });
      }

      // Check if already transcribed (unless force=true)
      const force = validation.data.force === true || req.query.force === "true";
      if (interview.transcriptSegments && !force) {
        return res.status(409).json({ 
          message: "Interview already transcribed. Use force=true to re-transcribe." 
        });
      }

      // Download video from object storage
      const objectStorage = new ObjectStorageService();
      
      // Ensure videoUrl is a valid object path
      if (!interview.videoUrl.startsWith("/objects/")) {
        return res.status(400).json({ 
          message: "Invalid video path format. Expected object storage path." 
        });
      }

      const videoFile = await objectStorage.getObjectEntityFile(interview.videoUrl);
      const [videoBuffer] = await videoFile.download();
      
      if (!videoBuffer) {
        return res.status(502).json({ message: "Failed to download video from storage" });
      }

      // Get file metadata to determine MIME type
      const fileName = interview.videoUrl.split('/').pop() || `interview-${interview.id}`;
      const fileExt = fileName.split('.').pop()?.toLowerCase() || 'webm';
      
      // Comprehensive MIME type mapping
      const mimeTypeMap: Record<string, string> = {
        'mp4': 'video/mp4',
        'webm': 'video/webm',
        'mov': 'video/quicktime',
        'm4v': 'video/x-m4v',
        'avi': 'video/x-msvideo',
        'mkv': 'video/x-matroska',
        'm4a': 'audio/mp4',
        'mp3': 'audio/mpeg',
        'wav': 'audio/wav'
      };
      const mimeType = mimeTypeMap[fileExt] || 'video/webm';

      // Transcribe video with ElevenLabs
      const language = validation.data.language || "";
      const result = await transcribeVideoFile(videoBuffer, {
        language,
        mimeType,
        filename: fileName
      });

      // Update database with transcription results
      const updatedInterview = await storage.updateRecordedInterview(interview.id, {
        transcriptText: result.fullText,
        transcriptSegments: result.segments as any,
        transcriptionMetadata: {
          provider: "elevenlabs",
          model: "scribe_v1",
          duration: result.duration,
          language: language || "auto-detect",
          transcribedAt: new Date().toISOString(),
          transcribedBy: req.user?.claims?.sub
        } as any
      });

      // Audit log the transcription
      await logAction(req, "interview_transcribed", "recorded_interview", interview.id, {
        caseId: interview.caseId,
        force,
        duration: result.duration,
        segmentCount: result.segments.length
      });

      res.json(updatedInterview);
    } catch (error: any) {
      console.error("Error transcribing interview:", error);
      res.status(502).json({ message: "Transcription failed: " + error.message });
    }
  });

