  // ElevenLabs Transcription Route
  app.post("/api/transcribe", isAuthenticated, requireRole("admin", "compliance_officer", "attorney"), async (req: any, res) => {
    try {
      const { audioUrl } = req.body;
      if (!audioUrl) {
        return res.status(400).json({ message: "Audio URL is required" });
      }

      const apiKey = process.env.ELEVENLABS_API_KEY;
      if (!apiKey) {
        return res.status(500).json({ message: "ElevenLabs API key not configured" });
      }

      const response = await fetch(audioUrl);
      if (!response.ok) {
        return res.status(400).json({ message: "Failed to fetch audio file" });
      }

      const audioBuffer = await response.arrayBuffer();
      const audioBlob = new Blob([audioBuffer], { type: response.headers.get("content-type") || "audio/wav" });
      
      const formData = new FormData();
      formData.append("audio", audioBlob, "recording.wav");

      const transcriptionResponse = await fetch("https://api.elevenlabs.io/v1/audio-to-text", {
        method: "POST",
        headers: {
          "xi-api-key": apiKey,
        },
        body: formData,
      });

      if (!transcriptionResponse.ok) {
        const errorText = await transcriptionResponse.text();
        console.error("ElevenLabs API error:", errorText);
        return res.status(transcriptionResponse.status).json({ 
          message: "Transcription failed", 
          error: errorText 
        });
      }

      const transcription = await transcriptionResponse.json();
      await logAction(req, "audio_transcribed", "transcription", undefined, { audioUrl });
      res.json(transcription);
    } catch (error: any) {
      console.error("Error transcribing audio:", error);
      res.status(500).json({ message: error.message });
    }
  });

