  // Case Efficiency Metrics
  app.get("/api/analytics/case-efficiency", isAuthenticated, requireRole("admin", "compliance_officer", "auditor"), async (req, res) => {
    try {
      const allCases = await db.select({
        id: schema.cases.id,
        caseNumber: schema.cases.caseNumber,
        title: schema.cases.title,
        violationType: schema.cases.violationType,
        status: schema.cases.status,
        priority: schema.cases.priority,
        description: schema.cases.description,
        employeeName: schema.cases.employeeName,
        createdBy: schema.cases.createdBy,
        closedAt: schema.cases.closedAt,
        createdAt: schema.cases.createdAt,
        updatedAt: schema.cases.updatedAt,
      }).from(schema.cases);
      const now = new Date();
      
      // Calculate average time to close (for closed cases)
      const closedCases = allCases.filter(c => c.closedAt);
      let avgTimeToClose = 0;
      if (closedCases.length > 0) {
        const totalDays = closedCases.reduce((sum, c) => {
          const created = new Date(c.createdAt);
          const closed = new Date(c.closedAt!);
          const days = Math.floor((closed.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));
          return sum + days;
        }, 0);
        avgTimeToClose = Math.round(totalDays / closedCases.length);
      }
      
      // Age distribution of open cases
      const openCases = allCases.filter(c => !c.closedAt);
      const ageDistribution = {
        lessThan7Days: 0,
        days8to30: 0,
        days31to90: 0,
        moreThan90Days: 0,
      };
      
      openCases.forEach(c => {
        const created = new Date(c.createdAt);
        const ageInDays = Math.floor((now.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));
        
        if (ageInDays < 7) {
          ageDistribution.lessThan7Days++;
        } else if (ageInDays <= 30) {
          ageDistribution.days8to30++;
        } else if (ageInDays <= 90) {
          ageDistribution.days31to90++;
        } else {
          ageDistribution.moreThan90Days++;
        }
      });
      
      // Quarterly efficiency factor
      const quarters = [];
      
      // Helper function to get quarter start/end dates
      const getQuarterDates = (year: number, quarter: number) => {
        const startMonth = (quarter - 1) * 3; // Q1=0, Q2=3, Q3=6, Q4=9
        const quarterStart = new Date(year, startMonth, 1, 0, 0, 0, 0);
        const quarterEnd = new Date(year, startMonth + 3, 1, 0, 0, 0, 0);
        return { quarterStart, quarterEnd };
      };
      
      // Get current quarter
      const currentMonth = now.getMonth();
      const currentYear = now.getFullYear();
      const currentQuarter = Math.floor(currentMonth / 3) + 1; // 1-4
      
      // Build quarters array (current quarter and 3 previous)
      for (let i = 0; i < 4; i++) {
        let quarter = currentQuarter - i;
        let year = currentYear;
        
        // Handle year rollover
        while (quarter <= 0) {
          quarter += 4;
          year -= 1;
        }
        
        const { quarterStart, quarterEnd } = getQuarterDates(year, quarter);
        
        const openAtStart = allCases.filter(c => {
          const created = new Date(c.createdAt);
          const closed = c.closedAt ? new Date(c.closedAt) : null;
          return created < quarterStart && (!closed || closed >= quarterStart);
        }).length;
        
        const openAtEnd = allCases.filter(c => {
          const created = new Date(c.createdAt);
          const closed = c.closedAt ? new Date(c.closedAt) : null;
          return created < quarterEnd && (!closed || closed >= quarterEnd);
        }).length;
        
        const closedInQuarter = allCases.filter(c => {
          if (!c.closedAt) return false;
          const closed = new Date(c.closedAt);
          return closed >= quarterStart && closed < quarterEnd;
        }).length;
        
        // Efficiency factor: higher is better (more cases closed relative to open balance)
        const efficiencyFactor = openAtStart > 0 ? Number((closedInQuarter / openAtStart).toFixed(2)) : 0;
        
        quarters.push({
          quarter: `Q${quarter} ${year}`,
          openAtStart,
          openAtEnd,
          closedInQuarter,
          efficiencyFactor,
        });
      }
      
      res.json({
        totalCases: allCases.length,
        openCases: openCases.length,
        closedCases: closedCases.length,
        avgTimeToClose,
        ageDistribution,
        quarterlyData: quarters.reverse(),
      });
    } catch (error: any) {
      console.error("Error fetching case efficiency metrics:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Compliance Health Score
  app.get("/api/analytics/health-score", isAuthenticated, requireRole("admin", "compliance_officer", "auditor"), async (req, res) => {
    try {
      // 1. Coverage Score (25%) - monitoring coverage
      const totalUsers = await db.select().from(schema.users);
      const employees = totalUsers.filter(u => u.role === "employee");
      const vendors = totalUsers.filter(u => u.role === "vendor");
      
      // Get users who have communications (are being monitored)
      const monitoredUserIds = await db
        .selectDistinct({ sender: schema.communications.sender })
        .from(schema.communications);
      const monitoredIds = new Set(monitoredUserIds.map(c => c.sender));
      
      const monitoredEmployees = employees.filter(e => monitoredIds.has(e.id));
      const monitoredVendors = vendors.filter(v => monitoredIds.has(v.id));
      
      const employeeCoverage = employees.length > 0 ? (monitoredEmployees.length / employees.length) * 100 : 100;
      const vendorCoverage = vendors.length > 0 ? (monitoredVendors.length / vendors.length) * 100 : 100;
      
      // Get active connectors
      const connectors = await db.select().from(schema.connectorConfigurations);
      const activeConnectors = connectors.filter(c => c.isActive === "true");
      const channelScore = Math.min((activeConnectors.length / 5) * 100, 100); // 5 major channels (email, Slack, Teams, etc.)
      
      const coverageScore = Math.round((employeeCoverage * 0.4) + (vendorCoverage * 0.3) + (channelScore * 0.3));
      
      // 2. Detection Score (30%) - alert detection and response
      const allAlerts = await db.select().from(schema.alerts);
      const detectionRules = await db.select({
        id: schema.detectionRules.id,
        isActive: schema.detectionRules.isActive,
      }).from(schema.detectionRules);
      const activeRules = detectionRules.filter(r => r.isActive === "true");
      
      const ruleScore = Math.min((activeRules.length / 20) * 100, 100); // 20 rules = 100%
      
      // Alert response time (average days from created to status change)
      const reviewedAlerts = allAlerts.filter(a => a.status !== "pending");
      let responseTimeScore = 100;
      if (reviewedAlerts.length > 0) {
        const avgResponseDays = reviewedAlerts.reduce((sum, alert) => {
          const created = new Date(alert.createdAt);
          const updated = new Date(alert.updatedAt);
          const days = (updated.getTime() - created.getTime()) / (1000 * 60 * 60 * 24);
          return sum + days;
        }, 0) / reviewedAlerts.length;
        
        // Score: <1 day = 100%, <3 days = 80%, <7 days = 60%, <14 days = 40%, 14+ days = 20%
        if (avgResponseDays < 1) responseTimeScore = 100;
        else if (avgResponseDays < 3) responseTimeScore = 80;
        else if (avgResponseDays < 7) responseTimeScore = 60;
        else if (avgResponseDays < 14) responseTimeScore = 40;
        else responseTimeScore = 20;
      }
      
      const reviewCompletionRate = allAlerts.length > 0 ? (reviewedAlerts.length / allAlerts.length) * 100 : 100;
      
      const detectionScore = Math.round((ruleScore * 0.4) + (responseTimeScore * 0.3) + (reviewCompletionRate * 0.3));
      
      // 3. Prevention Score (25%) - training and policy acknowledgment
      const trainingAssignments = await db.select().from(schema.trainingAssignments);
      const completedTraining = trainingAssignments.filter(t => t.status === "completed");
      const trainingCompletionRate = trainingAssignments.length > 0 ? (completedTraining.length / trainingAssignments.length) * 100 : 50;
      
      const policyAttestations = await db.select().from(schema.policyAttestations);
      const validAttestations = policyAttestations.filter(p => p.isValid === "true");
      const policyAcknowledgmentRate = totalUsers.length > 0 ? (validAttestations.length / totalUsers.length) * 100 : 50;
      
      // Violation trends (comparing last 30 days to previous 30 days)
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const sixtyDaysAgo = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);
      
      const recentAlerts = allAlerts.filter(a => new Date(a.createdAt) >= thirtyDaysAgo);
      const previousAlerts = allAlerts.filter(a => {
        const created = new Date(a.createdAt);
        return created >= sixtyDaysAgo && created < thirtyDaysAgo;
      });
      
      let violationTrendScore = 100;
      if (previousAlerts.length > 0) {
        const trendRatio = recentAlerts.length / previousAlerts.length;
        if (trendRatio < 0.7) violationTrendScore = 100; // Improving (30% reduction)
        else if (trendRatio < 1.0) violationTrendScore = 80; // Slightly improving
        else if (trendRatio <= 1.2) violationTrendScore = 60; // Stable
        else if (trendRatio <= 1.5) violationTrendScore = 40; // Worsening
        else violationTrendScore = 20; // Significantly worsening
      }
      
      const preventionScore = Math.round((trainingCompletionRate * 0.4) + (policyAcknowledgmentRate * 0.3) + (violationTrendScore * 0.3));
      
      // 4. Policy Compliance Score (20%) - policy management
      const policies = await db.select().from(schema.policies);
      const publishedPolicies = policies.filter(p => p.status === "published");
      const policyPublicationScore = Math.min((publishedPolicies.length / 10) * 100, 100); // 10 policies = 100%
      
      const certifications = await db.select().from(schema.certifications);
      const validCerts = certifications.filter(c => c.renewalStatus === "valid");
      const certificationRate = totalUsers.length > 0 ? (validCerts.length / totalUsers.length) * 100 : 50;
      
      // Policies reviewed in last 90 days
      const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
      const recentlyReviewedPolicies = publishedPolicies.filter(p => {
        const updated = new Date(p.updatedAt);
        return updated >= ninetyDaysAgo;
      });
      const policyReviewScore = publishedPolicies.length > 0 ? (recentlyReviewedPolicies.length / publishedPolicies.length) * 100 : 50;
      
      const policyComplianceScore = Math.round((policyPublicationScore * 0.4) + (certificationRate * 0.3) + (policyReviewScore * 0.3));
      
      // Overall Health Score (weighted average)
      const overallScore = Math.round(
        (coverageScore * 0.25) +
        (detectionScore * 0.30) +
        (preventionScore * 0.25) +
        (policyComplianceScore * 0.20)
      );
      
      // Letter grade
      let letterGrade = "F";
      if (overallScore >= 90) letterGrade = "A";
      else if (overallScore >= 80) letterGrade = "B";
      else if (overallScore >= 70) letterGrade = "C";
      else if (overallScore >= 60) letterGrade = "D";
      
      // Industry benchmarks (realistic averages by sector)
      const industryBenchmarks = {
        "Financial Services": 85,
        "Healthcare": 82,
        "Manufacturing": 75,
        "Technology": 78,
        "Retail": 72,
        "Energy": 77,
        "Average": 78,
      };
      
      res.json({
        overallScore,
        letterGrade,
        dimensions: {
          coverage: {
            score: coverageScore,
            metrics: {
              employeeCoverage: Math.round(employeeCoverage),
              vendorCoverage: Math.round(vendorCoverage),
              channelsCovered: activeConnectors.length,
              totalEmployees: employees.length,
              monitoredEmployees: monitoredEmployees.length,
              totalVendors: vendors.length,
              monitoredVendors: monitoredVendors.length,
            }
          },
          detection: {
            score: detectionScore,
            metrics: {
              activeRules: activeRules.length,
              totalAlerts: allAlerts.length,
              reviewedAlerts: reviewedAlerts.length,
              avgResponseDays: reviewedAlerts.length > 0 ? 
                Math.round(reviewedAlerts.reduce((sum, alert) => {
                  const created = new Date(alert.createdAt);
                  const updated = new Date(alert.updatedAt);
                  return sum + ((updated.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));
                }, 0) / reviewedAlerts.length * 10) / 10 : 0,
              reviewCompletionRate: Math.round(reviewCompletionRate),
            }
          },
          prevention: {
            score: preventionScore,
            metrics: {
              trainingCompletionRate: Math.round(trainingCompletionRate),
              policyAcknowledgmentRate: Math.round(policyAcknowledgmentRate),
              recentViolations: recentAlerts.length,
              previousViolations: previousAlerts.length,
              trend: recentAlerts.length < previousAlerts.length ? "improving" : 
                     recentAlerts.length === previousAlerts.length ? "stable" : "worsening",
            }
          },
          policyCompliance: {
            score: policyComplianceScore,
            metrics: {
              publishedPolicies: publishedPolicies.length,
              certificationRate: Math.round(certificationRate),
              recentlyReviewedPolicies: recentlyReviewedPolicies.length,
              totalPolicies: policies.length,
            }
          }
        },
        industryBenchmarks,
        recommendations: generateRecommendations(coverageScore, detectionScore, preventionScore, policyComplianceScore),
      });
    } catch (error: any) {
      console.error("Error calculating health score:", error);
      res.status(500).json({ message: error.message });
    }
  });

