  // List all employees for analytics selector
  // Returns users whose emails appear in communications table
  app.get("/api/management/employees", isAuthenticated, requireRole("admin"), async (req: any, res) => {
    try {
      // Get all distinct senders
      const senders = await db
        .selectDistinct({ email: schema.communications.sender })
        .from(schema.communications)
        .where(sql`${schema.communications.sender} IS NOT NULL AND ${schema.communications.sender} != ''`);

      // Get all recipients (using raw SQL with jsonb_array_elements_text)
      const recipients = await db.execute(
        sql`SELECT DISTINCT jsonb_array_elements_text(${schema.communications.recipients}) AS email 
            FROM ${schema.communications} 
            WHERE ${schema.communications.recipients} IS NOT NULL`
      );

      // Combine and deduplicate emails
      const allEmails = new Set([
        ...senders.map(c => c.email).filter(Boolean),
        ...recipients.rows.map((r: any) => r.email).filter(Boolean),
      ]);

      if (allEmails.size === 0) {
        return res.json([]);
      }

      // Fetch user details for these emails
      const employees = await db
        .select({
          id: schema.users.id,
          firstName: schema.users.firstName,
          lastName: schema.users.lastName,
          email: schema.users.email,
          role: schema.users.role,
        })
        .from(schema.users)
        .where(inArray(schema.users.email, Array.from(allEmails)))
        .orderBy(schema.users.lastName, schema.users.firstName);

      res.json(employees);
    } catch (error: any) {
      console.error("Error fetching employees:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Helper function to generate recommendations
  function generateRecommendations(coverage: number, detection: number, prevention: number, policyCompliance: number) {
    const recommendations = [];
    
    if (coverage < 70) {
      recommendations.push({
        dimension: "Coverage",
        priority: "high",
        action: "Expand monitoring to cover more employees and vendors",
        impact: "Increase visibility into potential compliance risks"
      });
    }
    
    if (detection < 70) {
      recommendations.push({
        dimension: "Detection",
        priority: "high",
        action: "Add more detection rules and improve alert response time",
        impact: "Identify compliance issues faster"
      });
    }
    
    if (prevention < 70) {
      recommendations.push({
        dimension: "Prevention",
        priority: "medium",
        action: "Increase training completion and policy acknowledgment rates",
        impact: "Reduce future violations through better awareness"
      });
    }
    
    if (policyCompliance < 70) {
      recommendations.push({
        dimension: "Policy Compliance",
        priority: "medium",
        action: "Publish more policies and ensure regular reviews",
        impact: "Strengthen compliance framework and documentation"
      });
    }
    
    return recommendations;
  }

