  // Run compliance gap analysis
  app.post("/api/regulatory-changes/:id/gap-analysis", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req, res) => {
    try {
      const [change] = await db
        .select()
        .from(schema.regulatoryChanges)
        .where(eq(schema.regulatoryChanges.id, req.params.id));
      
      if (!change) {
        return res.status(404).json({ message: "Regulatory change not found" });
      }
      
      // Identify compliance gaps based on change requirements
      const gaps = [];
      
      // Check if policies need updates
      if (change.changeType === "new_regulation" || change.changeType === "amendment") {
        gaps.push({
          area: "policies",
          severity: change.impactLevel,
          description: `Policies may need to be updated to reflect ${change.changeTitle}`,
          recommendation: "Review and update relevant policies",
        });
      }
      
      // Check if training needs updates
      if (change.impactLevel === "critical" || change.impactLevel === "high") {
        gaps.push({
          area: "training",
          severity: change.impactLevel,
          description: "Employees may need training on new regulatory requirements",
          recommendation: "Develop and deploy training modules",
        });
      }
      
      // Check implementation timeline
      if (change.complianceDeadline) {
        const now = new Date();
        const deadline = new Date(change.complianceDeadline);
        const daysUntilDeadline = Math.floor((deadline.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
        
        if (daysUntilDeadline < 90 && change.implementationStatus === "pending") {
          gaps.push({
            area: "implementation",
            severity: daysUntilDeadline < 30 ? "critical" : "high",
            description: `Only ${daysUntilDeadline} days until compliance deadline`,
            recommendation: "Accelerate implementation planning and execution",
          });
        }
      }
      
      const gapAnalysis = {
        changeId: change.id,
        changeTitle: change.changeTitle,
        overallRisk: calculateOverallRisk(gaps),
        identifiedGaps: gaps,
        totalGaps: gaps.length,
        criticalGaps: gaps.filter(g => g.severity === "critical").length,
        highGaps: gaps.filter(g => g.severity === "high").length,
      };
      
      await logAction(req, "gap_analysis_run", "regulatory_change", change.id);
      res.json(gapAnalysis);
    } catch (error: any) {
      console.error("Error running gap analysis:", error);
      res.status(500).json({ message: error.message });
    }
  });

