  // Complete a training module
  app.post("/api/employee/training/complete", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { enrollmentId, completionData } = req.body;
      
      // Get enrollment details
      const [enrollment] = await db
        .select()
        .from(schema.trainingEnrollments)
        .where(
          and(
            eq(schema.trainingEnrollments.id, enrollmentId),
            eq(schema.trainingEnrollments.userId, userId)
          )
        );
      
      if (!enrollment) {
        return res.status(404).json({ message: "Enrollment not found" });
      }
      
      // Get course details
      const [course] = await db
        .select()
        .from(schema.trainingCourses)
        .where(eq(schema.trainingCourses.id, enrollment.courseId));
      
      // Update enrollment status
      const [updated] = await db
        .update(schema.trainingEnrollments)
        .set({
          status: "completed",
          completedAt: new Date(),
          quizScore: completionData?.quizScore,
          updatedAt: new Date(),
        })
        .where(
          and(
            eq(schema.trainingEnrollments.id, enrollmentId),
            eq(schema.trainingEnrollments.userId, userId)
          )
        )
        .returning();
      
      // Auto-generate certification upon completion (if passing)
      if (course) {
        const hasQuiz = course.hasQuiz === "true";
        const quizScore = completionData?.quizScore;
        const passingScore = course.passingScore || 70;
        
        // Check if user passed (quiz-based or completion-based)
        const passed = hasQuiz 
          ? (quizScore !== undefined && quizScore >= passingScore)
          : true; // No quiz means completion is sufficient
        
        if (passed) {
          // Check for existing certification to prevent duplicates
          const existingCert = await db
            .select()
            .from(schema.certifications)
            .where(
              and(
                eq(schema.certifications.userId, userId),
                eq(schema.certifications.courseId, course.id),
                eq(schema.certifications.renewalStatus, "valid")
              )
            );
          
          if (existingCert.length === 0) {
            // Use course renewal period or default to 1 year
            const renewalDays = course.renewalPeriodDays || 365;
            const expiryDate = new Date();
            expiryDate.setDate(expiryDate.getDate() + renewalDays);
            
            await db.insert(schema.certifications).values({
              userId,
              certificationType: course.category || "training_completion",
              certificationName: course.title,
              issuedBy: "Sentinel Counsel LLP",
              issuedDate: new Date(),
              expiryDate,
              courseId: course.id,
              requiresRenewal: "true",
              renewalPeriodDays: course.renewalPeriodDays || 365, // Use renewal period, not reminder period
              renewalStatus: "valid",
            });
          }
        }
      }
      
      await logAction(req, "training_completed", "training_enrollment", enrollmentId);
      res.json(updated);
    } catch (error: any) {
      console.error("Error completing training:", error);
      res.status(400).json({ message: error.message });
    }
  });

  // Get employee's pending policy attestations
  app.get("/api/employee/policies/pending", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      
      // Get all active policies that require attestation
      const activePolicies = await db
        .select()
        .from(schema.policies)
        .where(
          and(
            eq(schema.policies.isActive, "true"),
            eq(schema.policies.requiresAttestation, "true")
          )
        );
      
      // Get user's latest attestations per policy ordered by most recent first
      const userAttestations = await db
        .select({
          attestation: schema.policyAttestations,
        })
        .from(schema.policyAttestations)
        .where(
          and(
            eq(schema.policyAttestations.userId, userId),
            eq(schema.policyAttestations.isValid, "true")
          )
        )
        .orderBy(desc(schema.policyAttestations.attestedAt));
      
      // Create map of policyId -> latest attested version (take first per policy due to ordering)
      const attestedVersions = new Map();
      for (const ua of userAttestations) {
        if (!attestedVersions.has(ua.attestation.policyId)) {
          attestedVersions.set(ua.attestation.policyId, ua.attestation.policyVersion);
        }
      }
      
      // Filter policies needing attestation
      const pendingPolicies = activePolicies.filter(policy => {
        const attestedVersion = attestedVersions.get(policy.id);
        
        // Never attested
        if (!attestedVersion) return true;
        
        // Version changed (policy updated) - always requires re-attestation
        if (policy.version !== attestedVersion) return true;
        
        // upon_update frequency only re-prompts if version changed (already handled above)
        // No need for separate check - if versions match and frequency is upon_update, don't re-prompt
        
        // Requires annual re-attestation regardless of version
        if (policy.attestationFrequency === "annually") {
          // Check if last attestation was over 1 year ago
          const lastAttestation = userAttestations.find(
            ua => ua.attestation.policyId === policy.id
          );
          if (lastAttestation) {
            const oneYearAgo = new Date();
            oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
            const attestationDate = new Date(lastAttestation.attestation.attestedAt);
            if (attestationDate < oneYearAgo) return true;
          }
        }
        
        return false;
      });
      
      res.json(pendingPolicies);
    } catch (error: any) {
      console.error("Error fetching pending policies:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // Attest to a policy
  app.post("/api/employee/policies/attest", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      const { policyId, attestationMethod, ipAddress } = req.body;
      
      // Get current policy version to store in attestation
      const [policy] = await db
        .select()
        .from(schema.policies)
        .where(eq(schema.policies.id, policyId));
      
      if (!policy) {
        return res.status(404).json({ message: "Policy not found" });
      }
      
      const [attestation] = await db
        .insert(schema.policyAttestations)
        .values({
          userId,
          policyId,
          policyVersion: policy.version, // Store version at attestation time
          attestationMethod: attestationMethod || "digital_signature",
          signatureData: `${userId}_${Date.now()}`,
          ipAddress: ipAddress || req.ip,
          isValid: "true",
        })
        .returning();
      
      await logAction(req, "policy_attested", "policy_attestation", attestation.id, { policyId });
      res.json(attestation);
    } catch (error: any) {
      console.error("Error attesting policy:", error);
      res.status(400).json({ message: error.message });
    }
  });

