  // Get employee compliance dashboard metrics
  app.get("/api/employee/dashboard", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.claims.sub;
      
      // Get pending training
      const pendingTraining = await db
        .select()
        .from(schema.trainingAssignments)
        .where(
          and(
            eq(schema.trainingAssignments.userId, userId),
            eq(schema.trainingAssignments.status, "assigned")
          )
        );
      
      // Get completed training
      const completedTraining = await db
        .select()
        .from(schema.trainingEnrollments)
        .where(
          and(
            eq(schema.trainingEnrollments.userId, userId),
            eq(schema.trainingEnrollments.status, "completed")
          )
        );
      
      // Get pending policies (using same logic as dedicated pending endpoint)
      const activePolicies = await db
        .select()
        .from(schema.policies)
        .where(
          and(
            eq(schema.policies.isActive, "true"),
            eq(schema.policies.requiresAttestation, "true")
          )
        );
      
      // Get user's latest attestations per policy with version info
      const userAttestations = await db
        .select({
          attestation: schema.policyAttestations,
        })
        .from(schema.policyAttestations)
        .where(
          and(
            eq(schema.policyAttestations.userId, userId),
            eq(schema.policyAttestations.isValid, "true")
          )
        )
        .orderBy(desc(schema.policyAttestations.attestedAt));
      
      // Create map of policyId -> latest attested version
      const attestedVersions = new Map();
      for (const ua of userAttestations) {
        if (!attestedVersions.has(ua.attestation.policyId)) {
          attestedVersions.set(ua.attestation.policyId, ua.attestation.policyVersion);
        }
      }
      
      // Filter policies needing attestation
      const pendingPolicies = activePolicies.filter(policy => {
        const attestedVersion = attestedVersions.get(policy.id);
        
        // Never attested
        if (!attestedVersion) return true;
        
        // Version changed (policy updated)
        if (policy.version !== attestedVersion) return true;
        
        // Requires annual re-attestation
        if (policy.attestationFrequency === "annually") {
          const lastAttestation = userAttestations.find(
            ua => ua.attestation.policyId === policy.id
          );
          if (lastAttestation) {
            const oneYearAgo = new Date();
            oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
            const attestationDate = new Date(lastAttestation.attestation.attestedAt);
            if (attestationDate < oneYearAgo) return true;
          }
        }
        
        return false;
      });
      
      // Get active certifications
      const certifications = await db
        .select()
        .from(schema.certifications)
        .where(
          and(
            eq(schema.certifications.userId, userId),
            eq(schema.certifications.renewalStatus, "valid")
          )
        );
      
      const metrics = {
        pendingTrainingCount: pendingTraining.length,
        completedTrainingCount: completedTraining.length,
        pendingPoliciesCount: pendingPolicies.length,
        attestedPoliciesCount: userAttestations.length,
        activeCertificationsCount: certifications.length,
        complianceScore: calculateComplianceScore({
          pendingTraining: pendingTraining.length,
          completedTraining: completedTraining.length,
          pendingPolicies: pendingPolicies.length,
          totalPolicies: activePolicies.length,
        }),
      };
      
      res.json(metrics);
    } catch (error: any) {
      console.error("Error fetching employee dashboard:", error);
      res.status(500).json({ message: error.message });
    }
  });

