  app.get("/api/grc/risks", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req, res) => {
    try {
      const { status, category } = req.query;
      
      const validStatuses = ["identified", "assessed", "mitigating", "mitigated", "accepted", "transferred", "closed"];
      const validCategories = ["operational", "financial", "compliance", "strategic", "reputational", "cybersecurity", "third_party", "legal"];
      
      let query = db.select().from(schema.grcRisks);
      const conditions = [];
      
      if (status && typeof status === "string" && validStatuses.includes(status)) {
        conditions.push(eq(schema.grcRisks.status, status as any));
      }
      if (category && typeof category === "string" && validCategories.includes(category)) {
        conditions.push(eq(schema.grcRisks.category, category as any));
      }
      
      if (conditions.length > 0) {
        query = query.where(and(...conditions)) as any;
      }
      
      const risks = await query.orderBy(desc(schema.grcRisks.inherentRiskScore), desc(schema.grcRisks.createdAt));
      
      res.json(risks);
    } catch (error: any) {
      console.error("Error fetching GRC risks:", error);
      res.status(500).json({ message: error.message });
    }
  });

