  app.patch("/api/grc/risks/:id", isAuthenticated, requireRole("admin", "compliance_officer"), async (req, res) => {
    try {
      const validated = insertGrcRiskSchema.partial().parse(req.body);
      
      // Recalculate risk score if likelihood or impact changed
      let updateData: any = { ...validated, updatedAt: new Date() };
      if (validated.likelihood || validated.impact) {
        // Fetch current record to get missing dimension
        const [current] = await db
          .select()
          .from(schema.grcRisks)
          .where(eq(schema.grcRisks.id, req.params.id));
        
        if (!current) {
          return res.status(404).json({ message: "Risk not found" });
        }
        
        const likelihood = validated.likelihood || current.likelihood;
        const impact = validated.impact || current.impact;
        updateData.inherentRiskScore = calculateRiskScore(likelihood, impact);
      }
      
      const [updated] = await db
        .update(schema.grcRisks)
        .set(updateData)
        .where(eq(schema.grcRisks.id, req.params.id))
        .returning();
      
      if (!updated) {
        return res.status(404).json({ message: "Risk not found" });
      }
      
      await logAction(req, "grc_risk_updated", "grc_risk", updated.id, validated);
      res.json(updated);
    } catch (error: any) {
      console.error("Error updating GRC risk:", error);
      res.status(400).json({ message: error.message });
    }
  });

