  // GRC Dashboard metrics endpoint
  app.get("/api/grc/dashboard", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req, res) => {
    try {
      // Get risk metrics
      const risks = await db.select().from(schema.grcRisks);
      const highRisks = risks.filter(r => r.inherentRiskScore >= 15 || r.status === "identified");
      const mitigatedRisks = risks.filter(r => r.status === "mitigated" || r.status === "accepted");
      
      // Get control metrics
      const controls = await db.select().from(schema.grcControls);
      const effectiveControls = controls.filter(c => c.effectiveness === "fully_effective" || c.effectiveness === "largely_effective");
      const failedControls = controls.filter(c => c.testStatus === "failed" || c.testStatus === "requires_remediation");
      
      // Get incident metrics
      const incidents = await db.select().from(schema.grcIncidents);
      const openIncidents = incidents.filter(i => !["resolved", "closed"].includes(i.status));
      const criticalIncidents = incidents.filter(i => i.severity === "critical" && !["resolved", "closed"].includes(i.status));
      
      // Get policy count
      const policies = await db.select().from(schema.policies).where(eq(schema.policies.isCurrent, "true"));
      
      res.json({
        risks: {
          total: risks.length,
          high: highRisks.length,
          mitigated: mitigatedRisks.length,
        },
        controls: {
          total: controls.length,
          effective: effectiveControls.length,
          failed: failedControls.length,
        },
        incidents: {
          total: incidents.length,
          open: openIncidents.length,
          critical: criticalIncidents.length,
        },
        policies: {
          total: policies.length,
        },
      });
    } catch (error: any) {
      console.error("Error fetching GRC dashboard:", error);
      res.status(500).json({ message: error.message });
    }
  });

  // ===== RISK ASSESSMENTS API =====
  
  // Helper function to generate assessment number
  async function generateAssessmentNumber(): Promise<string> {
    const year = new Date().getFullYear();
    const existingAssessments = await db.select().from(schema.grcRiskAssessments);
    const thisYearAssessments = existingAssessments.filter(a => 
      a.assessmentNumber.startsWith(`RA-${year}`)
    );
    const nextNumber = (thisYearAssessments.length + 1).toString().padStart(3, '0');
    return `RA-${year}-${nextNumber}`;
  }
  
