  async function generateKriCode(category: string): Promise<string> {
    const catCode = category.substring(0, 3).toUpperCase();
    const existingKris = await db.select().from(schema.grcKeyRiskIndicators);
    const catKris = existingKris.filter(k => k.kriCode.includes(`-${catCode}-`));
    const nextNumber = (catKris.length + 1).toString().padStart(3, '0');
    return `KRI-${catCode}-${nextNumber}`;
  }
  
