  // Get checklist items with template info
  app.get("/api/deal-checklists/:checklistId/items", isAuthenticated, requireRole("admin", "attorney", "external_counsel"), async (req, res) => {
    try {
      const items = await storage.getDealChecklistItems(req.params.checklistId);
      
      // Enrich with template item details
      const enrichedItems = await Promise.all(
        items.map(async (item) => {
          const templateItems = await db.select()
            .from(schema.templateItems)
            .where(eq(schema.templateItems.id, item.templateItemId));
          
          const templateItem = templateItems[0];
          
          // Get category info
          let category = null;
          if (templateItem?.categoryId) {
            const categories = await db.select()
              .from(schema.templateCategories)
              .where(eq(schema.templateCategories.id, templateItem.categoryId));
            category = categories[0];
          }
          
          const linkedDocs = await db.select({
            id: schema.checklistItemDocuments.id,
            autoMatched: schema.checklistItemDocuments.autoMatched,
            confidence: schema.checklistItemDocuments.confidence,
          })
            .from(schema.checklistItemDocuments)
            .where(eq(schema.checklistItemDocuments.checklistItemId, item.id));
          
          const documentCount = linkedDocs.length;
          const hasAutoMatched = linkedDocs.some(d => d.autoMatched);
          const autoMatchedDocs = linkedDocs.filter(d => d.autoMatched && d.confidence != null);
          const autoMatchConfidence = autoMatchedDocs.length > 0
            ? Math.max(...autoMatchedDocs.map(d => d.confidence!))
            : undefined;
          
          return {
            ...item,
            templateItem,
            category,
            documentCount,
            hasAutoMatched,
            autoMatchConfidence,
          };
        })
      );
      
      res.json(enrichedItems);
    } catch (error: any) {
      console.error("Error fetching checklist items:", error);
      res.status(500).json({ message: error.message });
    }
  });
  
