  // Run auto-matching for a checklist - matches documents to items based on keywords
  app.post("/api/deal-checklists/:checklistId/auto-match", isAuthenticated, requireRole("admin", "attorney", "external_counsel"), async (req: any, res) => {
    try {
      const { checklistId } = req.params;
      
      // Get the checklist and its deal
      const [checklist] = await db.select()
        .from(schema.dealChecklists)
        .where(eq(schema.dealChecklists.id, checklistId));
      
      if (!checklist) {
        return res.status(404).json({ message: "Checklist not found" });
      }
      
      // Get all data rooms for this deal
      const rooms = await db.select({ id: schema.dataRooms.id })
        .from(schema.dataRooms)
        .where(eq(schema.dataRooms.dealId, checklist.dealId));
      
      if (rooms.length === 0) {
        return res.json({ matchedCount: 0, message: "No data rooms found for this deal" });
      }
      
      // Get all documents from these data rooms
      const roomIds = rooms.map(r => r.id);
      const documents = await db.select()
        .from(schema.dataRoomDocuments)
        .where(inArray(schema.dataRoomDocuments.dataRoomId, roomIds));
      
      // Get all checklist items with their template items (which have keywords)
      const checklistItems = await db.select({
        item: schema.dealChecklistItems,
        templateItem: schema.templateItems,
      })
        .from(schema.dealChecklistItems)
        .leftJoin(schema.templateItems, eq(schema.dealChecklistItems.templateItemId, schema.templateItems.id))
        .where(eq(schema.dealChecklistItems.dealChecklistId, checklistId));
      
      // Get existing links to avoid duplicates
      const existingLinks = await db.select()
        .from(schema.checklistItemDocuments)
        .where(inArray(
          schema.checklistItemDocuments.checklistItemId,
          checklistItems.map(ci => ci.item.id)
        ));
      
      const existingLinkSet = new Set(
        existingLinks.map(l => `${l.checklistItemId}-${l.documentId}`)
      );
      
      let matchedCount = 0;
      const newLinks: any[] = [];
      
      // Debug logging
      console.log("[Auto-match] Documents found:", documents.length);
      console.log("[Auto-match] Checklist items with templates:", checklistItems.filter(ci => ci.templateItem).length);
      console.log("[Auto-match] Sample document:", documents[0] ? { id: documents[0].id, fileName: documents[0].fileName } : null);
      console.log("[Auto-match] Sample checklist item:", checklistItems[0]?.templateItem ? { name: checklistItems[0].templateItem.name, keywords: checklistItems[0].templateItem.documentKeywords } : null);
      
      // Generic single words that appear everywhere - require name match or other signal
      const genericSingleWords = new Set([
        'terms', 'agreement', 'contract', 'document', 'letter', 'report',
        'notice', 'form', 'statement', 'certificate', 'schedule', 'exhibit',
        'disclosure', 'consent', 'review', 'summary', 'copy'
      ]);
      
      // Helper function to check for keyword match (case-insensitive, word boundaries)
      const matchesKeyword = (text: string, keyword: string): boolean => {
        if (!text || !keyword) return false;
        const textLower = text.toLowerCase();
        const kwLower = keyword.toLowerCase().trim();
        
        // For multi-word phrases or hyphenated terms, simple contains check
        if (kwLower.includes(' ') || kwLower.includes('-')) {
          return textLower.includes(kwLower);
        }
        
        // For single words, use word boundary to avoid partial matches
        const escaped = kwLower.replace(/[.*+?^${}()|[\]\\]/g, '\$&');
        const pattern = new RegExp(`\\b${escaped}\\b`, 'i');
        return pattern.test(text);
      };
      
      // Count keyword occurrences (for single-word content matches)
      const countOccurrences = (text: string, keyword: string): number => {
        if (!text || !keyword) return 0;
        const kwLower = keyword.toLowerCase().trim();
        const escaped = kwLower.replace(/[.*+?^${}()|[\]\\]/g, '\$&');
        const pattern = new RegExp(`\\b${escaped}\\b`, 'gi');
        const matches = text.match(pattern);
        return matches ? matches.length : 0;
      };
      
      // Check if keyword is a phrase (multi-word or hyphenated)
      const isPhrase = (kw: string): boolean => kw.includes(' ') || kw.includes('-');
      
      // Check if keyword is specific (not generic)
      const isSpecific = (kw: string): boolean => {
        const kwLower = kw.toLowerCase().trim();
        if (isPhrase(kw)) return true;
        return !genericSingleWords.has(kwLower);
      };
      
      // For each checklist item, check if any documents match keywords
      for (const { item, templateItem } of checklistItems) {
        if (!templateItem) continue;
        
        // Parse keywords - may be array (from Drizzle) or JSON string (from raw query)
        let keywords: string[] = [];
        const rawKeywords = templateItem.documentKeywords;
        
        if (Array.isArray(rawKeywords)) {
          // Drizzle returns arrays directly
          keywords = rawKeywords;
        } else if (typeof rawKeywords === 'string') {
          // Handle JSON string (e.g., from raw queries)
          if (rawKeywords.startsWith('[')) {
            try {
              keywords = JSON.parse(rawKeywords);
            } catch (e) {
              keywords = [rawKeywords];
            }
          } else {
            keywords = [rawKeywords];
          }
        }
        
        if (keywords.length === 0) continue;
        
        console.log(`[Auto-match] Checking item "${templateItem.name}" with keywords:`, keywords);
        
        // Check each document against keywords
        for (const doc of documents) {
          const linkKey = `${item.id}-${doc.id}`;
          if (existingLinkSet.has(linkKey)) continue;
          
          const docName = (doc.name || doc.fileName || "");
          const docContent = (doc.extractedText || "");
          
          const nameMatches: string[] = [];
          const contentMatches: string[] = [];
          let hasSpecificNameMatch = false;
          let hasSpecificContentMatch = false;
          
          for (const keyword of keywords) {
            if (matchesKeyword(docName, keyword)) {
              nameMatches.push(keyword);
              if (isSpecific(keyword)) hasSpecificNameMatch = true;
            } else if (matchesKeyword(docContent, keyword)) {
              contentMatches.push(keyword);
              if (isSpecific(keyword)) hasSpecificContentMatch = true;
            }
          }
          
          const totalMatches = nameMatches.length + contentMatches.length;
          if (totalMatches === 0) continue;
          
          // Count phrase matches (highest quality)
          const phraseMatchCount = [...nameMatches, ...contentMatches].filter(isPhrase).length;
          
          // Determine match validity:
          // 1. Specific name match = valid (filename with non-generic keyword)
          // 2. Phrase match anywhere = valid
          // 3. Specific content match = valid (non-generic keyword in content)
          // 4. Multiple keyword matches (2+) = valid (multiple signals)
          // 5. Single generic content match = INVALID
          const isValidMatch = 
            hasSpecificNameMatch || 
            phraseMatchCount > 0 || 
            hasSpecificContentMatch || 
            totalMatches >= 2;
          
          if (!isValidMatch) continue;
          
          // Calculate confidence based on match quality
          let confidence = 40; // Base confidence for valid match
          
          // Boost for name matches
          if (nameMatches.length > 0) {
            confidence += 25;
            if (hasSpecificNameMatch) confidence += 15;
          }
          
          // Boost for phrase matches
          confidence += phraseMatchCount * 15;
          
          // Boost for specific content matches
          if (hasSpecificContentMatch) confidence += 10;
          
          // Small boost for multiple matches
          if (totalMatches >= 2) confidence += 5;
          
          // Cap at 100
          confidence = Math.min(100, confidence);
          
          const allMatched = [...nameMatches, ...contentMatches];
          
          newLinks.push({
            checklistItemId: item.id,
            documentId: doc.id,
            autoMatched: true,
            confidence: confidence,
            matchedKeywords: allMatched,
            reviewNotes: `Auto-matched: ${nameMatches.length} name, ${contentMatches.length} content match(es)`,
            uploadedBy: req.user?.id,
          });
          
          existingLinkSet.add(linkKey);
          matchedCount++;
        }
      }
      
      if (newLinks.length > 0) {
        await db.insert(schema.checklistItemDocuments).values(newLinks);
        
        const itemBestConfidence = new Map<string, number>();
        for (const link of newLinks) {
          const current = itemBestConfidence.get(link.checklistItemId) || 0;
          if (link.confidence > current) {
            itemBestConfidence.set(link.checklistItemId, link.confidence);
          }
        }
        
        let completedCount = 0;
        for (const [itemId, bestConf] of itemBestConfidence.entries()) {
          if (bestConf >= 60) {
            await db.update(schema.dealChecklistItems)
              .set({ status: "complete" })
              .where(
                and(
                  eq(schema.dealChecklistItems.id, itemId),
                  eq(schema.dealChecklistItems.status, "pending")
                )
              );
            completedCount++;
          }
        }
        
        console.log(`[Auto-match] ${newLinks.length} links created, ${completedCount} items auto-completed`);
      }
      
      const pendingItemIds = checklistItems
        .filter(ci => ci.item.status === "pending")
        .map(ci => ci.item.id);
      
      let retroCompleted = 0;
      if (pendingItemIds.length > 0) {
        const allLinks = matchedCount > 0
          ? await db.select()
              .from(schema.checklistItemDocuments)
              .where(inArray(schema.checklistItemDocuments.checklistItemId, pendingItemIds))
          : existingLinks.filter(l => pendingItemIds.includes(l.checklistItemId));
        
        const existingHighConfLinks = allLinks.filter(
          l => l.autoMatched && l.confidence != null && l.confidence >= 60
        );
        const alreadyCompleted = new Set(
          newLinks.filter(nl => nl.confidence >= 60).map(nl => nl.checklistItemId)
        );
        const itemsToComplete = new Set(
          existingHighConfLinks
            .map(l => l.checklistItemId)
            .filter(id => !alreadyCompleted.has(id))
        );
        for (const itemId of itemsToComplete) {
          await db.update(schema.dealChecklistItems)
            .set({ status: "complete" })
            .where(
              and(
                eq(schema.dealChecklistItems.id, itemId),
                eq(schema.dealChecklistItems.status, "pending")
              )
            );
          retroCompleted++;
        }
        if (retroCompleted > 0) {
          console.log(`[Auto-match] Retroactively completed ${retroCompleted} previously matched items`);
        }
      }
      
      const allItems = await db.select()
        .from(schema.dealChecklistItems)
        .where(eq(schema.dealChecklistItems.dealChecklistId, checklistId));
      const totalItems = allItems.length;
      const completedItems = allItems.filter(
        i => i.status === "complete" || i.status === "na" || i.status === "waived"
      ).length;
      const percentComplete = totalItems > 0 ? Math.round((completedItems / totalItems) * 100) : 0;
      
      await db.update(schema.dealChecklists)
        .set({ completedItems, percentComplete })
        .where(eq(schema.dealChecklists.id, checklistId));
      
      const totalCompleted = matchedCount + retroCompleted;
      res.json({
        matchedCount: totalCompleted,
        message: totalCompleted > 0 
          ? `Successfully matched ${totalCompleted} document(s) to checklist items`
          : "No new matches found",
      });
    } catch (error: any) {
      console.error("Error running auto-match:", error);
      res.status(500).json({ message: error.message });
    }
  });
  
