  app.post("/api/data-rooms/:roomId/apply-template/:templateId", isAuthenticated, requireRole("admin", "attorney", "external_counsel"), async (req: any, res) => {
    try {
      const { roomId, templateId } = req.params;
      
      const [template] = await db
        .select()
        .from(schema.dataRoomTemplates)
        .where(eq(schema.dataRoomTemplates.id, templateId));
      
      if (!template) {
        return res.status(404).json({ message: "Template not found" });
      }

      const folderStructure = template.folderStructure as Array<{
        name: string;
        indexNumber: string;
        children?: Array<{ name: string; indexNumber: string }>;
      }>;

      if (!folderStructure || !Array.isArray(folderStructure)) {
        return res.status(400).json({ message: "Invalid template structure" });
      }

      const createFolders = async (
        items: typeof folderStructure,
        parentId: string | null = null
      ) => {
        for (let i = 0; i < items.length; i++) {
          const item = items[i];
          const [folder] = await db
            .insert(schema.dataRoomFolders)
            .values({
              dataRoomId: roomId,
              parentFolderId: parentId,
              name: item.name,
              indexNumber: item.indexNumber,
              sortOrder: i,
              createdBy: req.user.id,
            })
            .returning();

          if (item.children && item.children.length > 0) {
            await createFolders(item.children as typeof folderStructure, folder.id);
          }
        }
      };

      await createFolders(folderStructure);

      const folders = await db
        .select()
        .from(schema.dataRoomFolders)
        .where(eq(schema.dataRoomFolders.dataRoomId, roomId))
        .orderBy(schema.dataRoomFolders.sortOrder);

      res.json({ message: "Template applied successfully", folders });
    } catch (error: any) {
      console.error("Error applying template:", error);
      res.status(400).json({ message: error.message });
    }
  });

