  // ===== Data Room Documents API Endpoints =====

  // Upload documents to a data room (with file upload and ZIP extraction)
  app.post("/api/data-rooms/:roomId/upload", isAuthenticated, requireRole("admin", "attorney", "external_counsel"), upload.array("files", 100), async (req: any, res) => {
    try {
      const { roomId } = req.params;
      // Normalize folderId - treat empty string, "null", "undefined" as null
      const rawFolderId = req.body.folderId;
      const folderId = (rawFolderId && rawFolderId !== "null" && rawFolderId !== "undefined" && rawFolderId.trim() !== "") 
        ? rawFolderId 
        : null;
      const files = req.files as Express.Multer.File[];

      if (!files || files.length === 0) {
        return res.status(400).json({ message: "No files uploaded" });
      }

      const objectStorageService = new ObjectStorageService();
      const uploadedDocs = [];
      const AdmZip = (await import("adm-zip")).default;
      const pathLib = await import("path");

      for (const file of files) {
        const fileExtension = file.originalname.split('.').pop()?.toLowerCase() || '';
        
        // Check if this is a ZIP file - extract and upload each file
        if (fileExtension === 'zip') {
          console.log(`[DataRoom] ZIP file detected: ${file.originalname} - extracting contents...`);
          
          try {
            const zip = new AdmZip(file.buffer);
            const zipEntries = zip.getEntries();
            
            // Security limits for ZIP extraction
            const MAX_FILES = 500;
            const MAX_TOTAL_SIZE = 500 * 1024 * 1024; // 500MB total
            const MAX_SINGLE_FILE_SIZE = 100 * 1024 * 1024; // 100MB per file
            const MAX_COMPRESSION_RATIO = 100; // Prevent zip bombs
            
            // Filter valid entries (skip directories, hidden files, and suspicious paths)
            const validEntries = zipEntries.filter(entry => {
              if (entry.isDirectory) return false;
              
              const entryPath = entry.entryName;
              
              // Decode URL-encoded characters
              let decodedPath: string;
              try {
                decodedPath = decodeURIComponent(entryPath);
              } catch {
                decodedPath = entryPath;
              }
              
              // Path traversal prevention
              const virtualRoot = '/safe_root';
              const resolvedPath = pathLib.resolve(virtualRoot, decodedPath);
              if (!resolvedPath.startsWith(virtualRoot + '/') && resolvedPath !== virtualRoot) {
                console.warn(`[DataRoom] ZIP: Path traversal attempt: ${entryPath}`);
                return false;
              }
              
              // Skip hidden files and system files
              const fileName = pathLib.basename(decodedPath);
              if (fileName.startsWith('.') || fileName.startsWith('__MACOSX') || fileName === 'Thumbs.db') {
                return false;
              }
              
              // Skip files that are too large
              if (entry.header.size > MAX_SINGLE_FILE_SIZE) {
                console.warn(`[DataRoom] ZIP: File too large: ${entryPath} (${Math.round(entry.header.size / 1024 / 1024)}MB)`);
                return false;
              }
              
              // Check compression ratio
              const compressedSize = entry.header.compressedSize || 1;
              const uncompressedSize = entry.header.size || 0;
              if (uncompressedSize / compressedSize > MAX_COMPRESSION_RATIO) {
                console.warn(`[DataRoom] ZIP: Suspicious compression ratio: ${entryPath}`);
                return false;
              }
              
              return true;
            });
            
            // Check limits
            if (validEntries.length > MAX_FILES) {
              console.warn(`[DataRoom] ZIP has too many files (${validEntries.length}), limiting to ${MAX_FILES}`);
              validEntries.length = MAX_FILES;
            }
            
            const totalSize = validEntries.reduce((sum, e) => sum + e.header.size, 0);
            if (totalSize > MAX_TOTAL_SIZE) {
              return res.status(400).json({ 
                message: `ZIP file is too large when extracted (${Math.round(totalSize / 1024 / 1024)}MB). Maximum allowed is ${Math.round(MAX_TOTAL_SIZE / 1024 / 1024)}MB.` 
              });
            }
            
            console.log(`[DataRoom] ZIP: Extracting ${validEntries.length} files (${Math.round(totalSize / 1024)}KB total)`);
            
            // Create folders for ZIP directory structure and upload files
            const createdFolders: Map<string, string> = new Map(); // path -> folderId
            
            for (const entry of validEntries) {
              const entryPath = entry.entryName;
              const entryBuffer = entry.getData();
              
              // Determine folder path from ZIP structure
              const entryDir = pathLib.dirname(entryPath);
              let targetFolderId = folderId || null;
              
              // Create nested folders if needed
              if (entryDir && entryDir !== '.') {
                const folderParts = entryDir.split('/').filter(p => p && !p.startsWith('.'));
                let currentPath = '';
                let parentFolderId = folderId || null;
                
                for (const folderName of folderParts) {
                  currentPath = currentPath ? `${currentPath}/${folderName}` : folderName;
                  
                  if (!createdFolders.has(currentPath)) {
                    // Check if folder already exists - build conditions array
                    const conditions = [
                      eq(schema.dataRoomFolders.dataRoomId, roomId),
                      eq(schema.dataRoomFolders.name, folderName),
                    ];
                    
                    // Add parent folder condition separately to avoid SQL syntax issues
                    if (parentFolderId) {
                      conditions.push(eq(schema.dataRoomFolders.parentFolderId, parentFolderId));
                    } else {
                      conditions.push(isNull(schema.dataRoomFolders.parentFolderId));
                    }
                    
                    const existingFolder = await db
                      .select()
                      .from(schema.dataRoomFolders)
                      .where(and(...conditions))
                      .limit(1);
                    
                    if (existingFolder.length > 0) {
                      createdFolders.set(currentPath, existingFolder[0].id);
                      parentFolderId = existingFolder[0].id;
                    } else {
                      // Only skip duplicate folder creation for the FIRST folder in the ZIP path
                      // if it matches the target folder name (avoids wrapping uploads in duplicate folders)
                      let skipFolderCreation = false;
                      const isFirstFolderInPath = currentPath === folderName;
                      
                      if (isFirstFolderInPath && parentFolderId) {
                        const parentFolder = await db
                          .select()
                          .from(schema.dataRoomFolders)
                          .where(eq(schema.dataRoomFolders.id, parentFolderId))
                          .limit(1);
                        
                        if (parentFolder.length > 0 && parentFolder[0].name === folderName) {
                          // First folder matches target folder name, use target instead of creating duplicate
                          createdFolders.set(currentPath, parentFolderId);
                          skipFolderCreation = true;
                          console.log(`[DataRoom] Skipping duplicate first folder: ${folderName} (same as upload target)`);
                        }
                      }
                      
                      if (!skipFolderCreation) {
                        // Create the folder
                        const [newFolder] = await db
                          .insert(schema.dataRoomFolders)
                          .values({
                            dataRoomId: roomId,
                            name: folderName,
                            parentFolderId: parentFolderId,
                            createdBy: req.user.id,
                          })
                          .returning();
                        
                        createdFolders.set(currentPath, newFolder.id);
                        parentFolderId = newFolder.id;
                        console.log(`[DataRoom] Created folder: ${currentPath}`);
                      }
                    }
                  } else {
                    parentFolderId = createdFolders.get(currentPath) || null;
                  }
                }
                
                targetFolderId = parentFolderId;
              }
              
              // Upload the file
              const fileName = pathLib.basename(entryPath);
              const mimeType = getMimeType(fileName);
              const targetPath = `uploads/datarooms/${roomId}/${Date.now()}-${fileName}`;
              
              const objectPath = await objectStorageService.uploadBuffer(
                targetPath,
                entryBuffer,
                mimeType
              );
              
              const [doc] = await db
                .insert(schema.dataRoomDocuments)
                .values({
                  dataRoomId: roomId,
                  folderId: targetFolderId,
                  fileName: fileName,
                  fileType: mimeType,
                  fileSize: entryBuffer.length,
                  storagePath: objectPath,
                  uploadedBy: req.user.id,
                  ocrStatus: "pending",
                })
                .returning();
              
              uploadedDocs.push(doc);
            }
            
            console.log(`[DataRoom] ZIP extraction complete: ${uploadedDocs.length} files uploaded`);
            
            // Queue OCR processing asynchronously with rate limiting (max 3 concurrent)
            const { queueDocumentsForOCR } = await import("./services/ocr-service");
            queueDocumentsForOCR(uploadedDocs.map(d => d.id));
            
          } catch (zipError: any) {
            console.error(`[DataRoom] Error extracting ZIP file:`, zipError);
            return res.status(400).json({ message: `Failed to extract ZIP file: ${zipError.message}` });
          }
          
        } else {
          // Regular file upload (non-ZIP)
          const targetPath = `uploads/datarooms/${roomId}/${Date.now()}-${file.originalname}`;
          const objectPath = await objectStorageService.uploadBuffer(
            targetPath,
            file.buffer,
            file.mimetype
          );

          const [doc] = await db
            .insert(schema.dataRoomDocuments)
            .values({
              dataRoomId: roomId,
              folderId: folderId || null,
              fileName: file.originalname,
              fileType: file.mimetype,
              fileSize: file.size,
              storagePath: objectPath,
              uploadedBy: req.user.id,
              ocrStatus: "pending",
            })
            .returning();

          uploadedDocs.push(doc);
        }
      }

      // Queue OCR processing for all uploaded documents
      if (uploadedDocs.length > 0) {
        const { queueDocumentsForOCR } = await import("./services/ocr-service");
        queueDocumentsForOCR(uploadedDocs.map(d => d.id));
        
        // Also queue for Gemini RAG indexing (for AI search functionality)
        const { queueDocumentsForGeminiIndexing } = await import("./services/transaction-search-service");
        queueDocumentsForGeminiIndexing(uploadedDocs.map(d => d.id));
      }

      res.status(201).json(uploadedDocs);
    } catch (error: any) {
      console.error("Error uploading documents:", error);
      res.status(400).json({ message: error.message });
    }
  });

  // Admin endpoint to re-process pending OCR documents
  app.post("/api/data-room-documents/reprocess-ocr", isAuthenticated, requireRole("admin"), async (req: any, res) => {
    try {
      // Find all documents with pending or processing status
      const pendingDocs = await db
        .select({ id: schema.dataRoomDocuments.id })
        .from(schema.dataRoomDocuments)
        .where(
          sql`${schema.dataRoomDocuments.ocrStatus} IN ('pending', 'processing')`
        );

      if (pendingDocs.length === 0) {
        return res.json({ message: "No pending documents found", count: 0 });
      }

      console.log(`[OCR Reprocess] Queuing ${pendingDocs.length} pending documents for OCR`);
      
      const { queueDocumentsForOCR } = await import("./services/ocr-service");
      queueDocumentsForOCR(pendingDocs.map(d => d.id));

      res.json({ 
        message: `Queued ${pendingDocs.length} documents for OCR processing`, 
        count: pendingDocs.length 
      });
    } catch (error: any) {
      console.error("Error reprocessing OCR:", error);
      res.status(500).json({ message: error.message });
    }
  });
  
  // Helper function to get MIME type from file extension
  function getMimeType(fileName: string): string {
    const ext = fileName.split('.').pop()?.toLowerCase() || '';
    const mimeTypes: Record<string, string> = {
      'pdf': 'application/pdf',
      'doc': 'application/msword',
      'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      'xls': 'application/vnd.ms-excel',
      'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'ppt': 'application/vnd.ms-powerpoint',
      'pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
      'txt': 'text/plain',
      'csv': 'text/csv',
      'html': 'text/html',
      'htm': 'text/html',
      'xml': 'text/xml',
      'json': 'application/json',
      'jpg': 'image/jpeg',
      'jpeg': 'image/jpeg',
      'png': 'image/png',
      'gif': 'image/gif',
      'bmp': 'image/bmp',
      'svg': 'image/svg+xml',
      'mp4': 'video/mp4',
      'mp3': 'audio/mpeg',
      'wav': 'audio/wav',
      'zip': 'application/zip',
      'rar': 'application/x-rar-compressed',
      '7z': 'application/x-7z-compressed',
      'eml': 'message/rfc822',
      'msg': 'application/vnd.ms-outlook',
    };
    return mimeTypes[ext] || 'application/octet-stream';
  }

