  // Download a document
  app.get("/api/data-room-documents/:id/download", isAuthenticated, async (req, res) => {
    try {
      const [doc] = await db
        .select()
        .from(schema.dataRoomDocuments)
        .where(eq(schema.dataRoomDocuments.id, req.params.id));

      if (!doc) {
        return res.status(404).json({ message: "Document not found" });
      }

      if (!doc.storagePath) {
        return res.status(404).json({ message: "Document file not found" });
      }

      const objectStorageService = new ObjectStorageService();
      res.setHeader("Content-Disposition", `attachment; filename="${doc.fileName}"`);
      if (objectStorageService.downloadLocalObject(doc.storagePath, res)) {
        return;
      }
      const objectFile = await objectStorageService.getObjectEntityFile(doc.storagePath);
      await objectStorageService.downloadObject(objectFile, res);
    } catch (error: any) {
      console.error("Error downloading document:", error);
      if (error.name === "ObjectNotFoundError") {
        return res.status(404).json({ message: "Document file not found" });
      }
      res.status(500).json({ message: error.message });
    }
  });

  // Preview document inline (no download prompt)
  app.get("/api/data-room-documents/:id/preview", isAuthenticated, async (req: any, res) => {
    try {
      const [doc] = await db
        .select()
        .from(schema.dataRoomDocuments)
        .where(eq(schema.dataRoomDocuments.id, req.params.id));

      if (!doc) {
        return res.status(404).json({ message: "Document not found" });
      }

      // Verify user has access to this data room
      const userId = req.user?.id;
      const [access] = await db
        .select()
        .from(schema.dataRoomAccess)
        .where(and(
          eq(schema.dataRoomAccess.dataRoomId, doc.dataRoomId),
          eq(schema.dataRoomAccess.userId, userId)
        ));

      // Also check if user is admin or attorney (they have implicit access)
      const [dbUser] = await db
        .select()
        .from(schema.users)
        .where(eq(schema.users.id, userId));

      const hasAccess = access || (dbUser && ['admin', 'attorney', 'external_counsel', 'compliance_officer'].includes(dbUser.role || ''));
      if (!hasAccess) {
        return res.status(403).json({ message: "Access denied to this document" });
      }

      if (!doc.storagePath) {
        return res.status(404).json({ message: "Document file not found" });
      }

      const objectStorageService = new ObjectStorageService();
      
      // Set content type based on file extension
      const ext = doc.fileName.split('.').pop()?.toLowerCase() || '';
      const mimeTypes: Record<string, string> = {
        'pdf': 'application/pdf',
        'png': 'image/png',
        'jpg': 'image/jpeg',
        'jpeg': 'image/jpeg',
        'gif': 'image/gif',
        'bmp': 'image/bmp',
        'webp': 'image/webp',
        'svg': 'image/svg+xml',
        'txt': 'text/plain',
        'csv': 'text/csv',
        'json': 'application/json',
        'xml': 'application/xml',
        'html': 'text/html',
        'htm': 'text/html',
      };
      
      const contentType = mimeTypes[ext] || doc.fileType || 'application/octet-stream';
      res.setHeader("Content-Type", contentType);
      res.setHeader("Content-Disposition", `inline; filename="${doc.fileName}"`);
      res.setHeader("X-Content-Type-Options", "nosniff");
      res.setHeader("X-Frame-Options", "SAMEORIGIN");
      res.setHeader("Content-Security-Policy", "frame-ancestors 'self'");
      
      if (objectStorageService.downloadLocalObject(doc.storagePath, res)) {
        return;
      }
      const objectFile = await objectStorageService.getObjectEntityFile(doc.storagePath);
      await objectStorageService.downloadObject(objectFile, res);
    } catch (error: any) {
      console.error("Error previewing document:", error);
      if (error.name === "ObjectNotFoundError") {
        return res.status(404).json({ message: "Document file not found" });
      }
      res.status(500).json({ message: error.message });
    }
  });

