  // Invite a guest to a data room
  app.post("/api/data-rooms/:roomId/guests", isAuthenticated, requireRole("admin", "attorney"), async (req: any, res) => {
    try {
      const { email, firstName, lastName, company, phone, groupId, role, accessNotes, accessExpiresAt } = req.body;
      
      if (!email) {
        return res.status(400).json({ message: "Email is required" });
      }

      // Check if guest already exists by email
      let [existingGuest] = await db
        .select()
        .from(schema.dataRoomGuests)
        .where(eq(schema.dataRoomGuests.email, email.toLowerCase()));

      let guestId: string;
      const inviteToken = nanoid(32);
      const inviteExpires = new Date();
      inviteExpires.setDate(inviteExpires.getDate() + 7); // Token valid for 7 days

      if (existingGuest) {
        guestId = existingGuest.id;
        // Update guest with new invite token if needed
        await db
          .update(schema.dataRoomGuests)
          .set({
            inviteToken,
            inviteTokenExpires: inviteExpires,
            updatedAt: new Date(),
          })
          .where(eq(schema.dataRoomGuests.id, existingGuest.id));
      } else {
        // Create new guest
        const [newGuest] = await db
          .insert(schema.dataRoomGuests)
          .values({
            email: email.toLowerCase(),
            firstName,
            lastName,
            company,
            phone,
            inviteToken,
            inviteTokenExpires: inviteExpires,
            status: "pending",
            invitedBy: req.user.id,
          })
          .returning();
        guestId = newGuest.id;
      }

      // Check if access already exists for this data room
      const [existingAccess] = await db
        .select()
        .from(schema.dataRoomAccess)
        .where(and(
          eq(schema.dataRoomAccess.dataRoomId, req.params.roomId),
          eq(schema.dataRoomAccess.guestId, guestId)
        ));

      if (existingAccess) {
        return res.status(400).json({ message: "Guest already has access to this data room" });
      }

      // Create access record
      const [newAccess] = await db
        .insert(schema.dataRoomAccess)
        .values({
          dataRoomId: req.params.roomId,
          guestId,
          groupId,
          role: role || "viewer",
          accessNotes,
          accessExpiresAt: accessExpiresAt ? new Date(accessExpiresAt) : null,
          invitedBy: req.user.id,
          inviteSentAt: new Date(),
          status: "pending",
        })
        .returning();

      // Log the invitation
      await db.insert(schema.dataRoomAuditLog).values({
        dataRoomId: req.params.roomId,
        userId: req.user.id,
        action: "invite",
        resourceType: "guest",
        resourceId: guestId,
        resourceName: email,
        details: { role, groupId, company },
        ipAddress: req.ip,
        userAgent: req.get("user-agent"),
      });

      res.status(201).json({ access: newAccess, inviteToken });
    } catch (error: any) {
      console.error("Error inviting guest:", error);
      res.status(400).json({ message: error.message });
    }
  });

