  // Get a single checklist with items
  app.get("/api/checklists/:id", isAuthenticated, requireRole("admin", "attorney", "external_counsel"), async (req, res) => {
    try {
      const [checklist] = await db
        .select()
        .from(schema.ddChecklists)
        .where(eq(schema.ddChecklists.id, req.params.id));
      
      if (!checklist) {
        return res.status(404).json({ message: "Checklist not found" });
      }

      const items = await db
        .select()
        .from(schema.ddChecklistItems)
        .where(eq(schema.ddChecklistItems.checklistId, req.params.id))
        .orderBy(schema.ddChecklistItems.sortOrder);

      // Calculate completion percentage
      const totalItems = items.filter(i => i.status !== "not_applicable").length;
      const completedItems = items.filter(i => i.status === "completed").length;
      const completionPercentage = totalItems > 0 ? Math.round((completedItems / totalItems) * 100) : 0;

      res.json({ ...checklist, items, completionPercentage });
    } catch (error: any) {
      console.error("Error fetching checklist:", error);
      res.status(500).json({ message: error.message });
    }
  });

