  // Upload and index a document to a data room
  app.post("/api/data-rooms/:roomId/documents/upload", isAuthenticated, requireRole("admin", "attorney", "external_counsel"), async (req: any, res) => {
    try {
      // Get the data room to find the deal
      const [room] = await db
        .select()
        .from(schema.dataRooms)
        .where(eq(schema.dataRooms.id, req.params.roomId));

      if (!room) {
        return res.status(404).json({ message: "Data room not found" });
      }

      const { fileName, fileContent, folderId, description, category, tags } = req.body;
      
      if (!fileName || !fileContent) {
        return res.status(400).json({ message: "fileName and fileContent are required" });
      }

      // Decode base64 file content
      const fileBuffer = Buffer.from(fileContent, "base64");

      // Create the document record
      const [doc] = await db
        .insert(schema.dataRoomDocuments)
        .values({
          dataRoomId: req.params.roomId,
          folderId: folderId || null,
          fileName,
          fileSize: fileBuffer.length,
          fileType: fileName.split(".").pop() || "unknown",
          description,
          documentCategory: category,
          tags: tags || [],
          uploadedBy: req.user.id,
          indexStatus: "pending",
        })
        .returning();

      // Start indexing in background (don't wait)
      if (room.dealId) {
        transactionSearchService.uploadAndIndexDocument(
          doc.id,
          fileBuffer,
          fileName,
          room.dealId,
          { category, documentType: fileName.split(".").pop() }
        ).catch(err => {
          console.error("Background indexing failed:", err);
        });
      }

      res.status(201).json(doc);
    } catch (error: any) {
      console.error("Error uploading document:", error);
      res.status(500).json({ message: error.message });
    }
  });

