  // Background research analysis function
  async function runBackgroundResearchAnalysis(researchId: string, research: any, documents: any[]) {
    const startTime = Date.now();
    const enabledModules = (research.enabledModules || []) as string[];
    const totalModules = enabledModules.length || 1;
    let completedModules = 0;
    
    // Fetch SEC EDGAR data if it's a comprehensive research
    let secEdgarSummary = '';
    if (research.researchType === 'comprehensive' || research.researchType === 'full') {
      try {
        await db
          .update(schema.backgroundResearch)
          .set({ currentStep: 'Searching SEC EDGAR database...' })
          .where(eq(schema.backgroundResearch.id, researchId));
        
        const secResult = await secEdgarApi.researchCompany(research.targetName);
        secEdgarSummary = secEdgarApi.generateSummaryForAI(secResult);
        
        // Store SEC research results in findings
        if (secResult.isPublicCompany) {
          await db.insert(schema.researchFindings).values({
            id: nanoid(),
            researchId,
            module: 'sec_edgar',
            title: 'SEC EDGAR Company Information',
            description: `Found SEC filings for ${secResult.companyInfo?.name || research.targetName}`,
            severity: 'info',
            isKeyFinding: true,
            details: {
              companyInfo: secResult.companyInfo,
              financialSummary: secResult.financialSummary,
              recentFilingsCount: secResult.recentFilings.length,
              materialEventsCount: secResult.materialEvents.filter(e => e.requiresReview).length,
            },
          });
        } else {
          await db.insert(schema.researchFindings).values({
            id: nanoid(),
            researchId,
            module: 'sec_edgar',
            title: 'SEC EDGAR Search Complete',
            description: `No public company SEC filings found for "${research.targetName}" - likely a private company`,
            severity: 'info',
            isKeyFinding: false,
            details: { isPublicCompany: false, searchMatches: secResult.searchMatches.length },
          });
        }
      } catch (error) {
        console.error('SEC EDGAR research failed:', error);
      }
    }
    
    // Fetch corporate/UCC research data
    let corporateSummary = '';
    if (research.researchType === 'comprehensive' || research.researchType === 'full') {
      try {
        await db
          .update(schema.backgroundResearch)
          .set({ currentStep: 'Researching corporate records...' })
          .where(eq(schema.backgroundResearch.id, researchId));
        
        const corpResult = await corporateResearchApi.researchCompany(research.targetName);
        corporateSummary = corporateResearchApi.generateSummaryForAI(corpResult);
        
        if (corpResult.entityFound) {
          await db.insert(schema.researchFindings).values({
            id: nanoid(),
            researchId,
            module: 'corporate_records',
            title: 'Corporate Entity Information',
            description: `Found corporate records for ${corpResult.companyInfo?.name || research.targetName}`,
            severity: 'info',
            isKeyFinding: true,
            details: {
              companyInfo: corpResult.companyInfo,
              officersCount: corpResult.officers.length,
              uccFilingsCount: corpResult.uccFilings.length,
              relatedEntitiesCount: corpResult.relatedEntities.length,
            },
          });
        } else {
          await db.insert(schema.researchFindings).values({
            id: nanoid(),
            researchId,
            module: 'corporate_records',
            title: 'Corporate Records Search Complete',
            description: `No matching corporate entity found for "${research.targetName}" in public registries`,
            severity: 'info',
            isKeyFinding: false,
            details: { entityFound: false, dataSource: corpResult.dataSource },
          });
        }
      } catch (error) {
        console.error('Corporate research failed:', error);
      }
    }
    
    // Combine all document text with SEC and corporate data
    const allDocumentText = [
      secEdgarSummary,
      corporateSummary,
      ...documents
        .filter(d => d.extractedText)
        .map(d => `=== ${d.fileName} ===\n${d.extractedText?.substring(0, 10000)}`)
    ].filter(Boolean).join('\n\n');
    
    const updateProgress = async (step: string) => {
      completedModules++;
      const progress = Math.round((completedModules / totalModules) * 100);
      await db
        .update(schema.backgroundResearch)
        .set({ progress, currentStep: step })
        .where(eq(schema.backgroundResearch.id, researchId));
    };
    
    const allFindings: any[] = [];
    const allEntities: any[] = [];
    
    // Run each enabled module
    for (const module of enabledModules) {
      try {
        await updateProgress(`Analyzing: ${module.replace(/_/g, ' ')}`);
        
        const moduleFindings = await runAIModule(researchId, module, research, allDocumentText);
        allFindings.push(...moduleFindings);
        
      } catch (error) {
        console.error(`Error in module ${module}:`, error);
      }
    }
    
    // Generate executive summary
    await updateProgress('Generating executive summary...');
    const executiveSummary = await generateExecutiveSummary(research, allFindings);
    
    // Calculate overall risk score
    const riskScore = calculateResearchRiskScore(allFindings);
    const riskLevel = riskScore >= 75 ? 'critical' : riskScore >= 50 ? 'high' : riskScore >= 25 ? 'medium' : 'low';
    
    // Get key findings
    const keyFindings = allFindings
      .filter(f => f.isKeyFinding || f.severity === 'high' || f.severity === 'critical')
      .slice(0, 10)
      .map(f => ({ title: f.title, severity: f.severity, module: f.module }));
    
    // Update research with results
    const processingTime = Math.round((Date.now() - startTime) / 1000);
    await db
      .update(schema.backgroundResearch)
      .set({
        status: 'completed',
        progress: 100,
        currentStep: 'Complete',
        executiveSummary,
        riskScore,
        riskLevel,
        keyFindings,
        processingTimeSeconds: processingTime,
        completedAt: new Date(),
      })
      .where(eq(schema.backgroundResearch.id, researchId));
  }
  
  // Run individual AI analysis module
  async function runAIModule(researchId: string, module: string, research: any, documentText: string): Promise<any[]> {
    const modulePrompts: Record<string, string> = {
      'company_overview': `Analyze the provided documents to create a comprehensive company overview for "${research.targetName}". Extract:
- Business description and history
- Headquarters location and key offices
- Number of employees (if mentioned)
- Revenue and growth indicators
- Major milestones and achievements
- Industry position and market presence

Provide findings as a JSON array with objects containing: title, description, severity (info/low/medium/high/critical), isKeyFinding (boolean), details (object with extracted data).`,
      
      'key_people': `Identify all key people mentioned in relation to "${research.targetName}". For each person extract:
- Full name and title/role
- Responsibilities and tenure
- Notable accomplishments or concerns
- Any potential conflicts of interest
- Background details (education, prior experience)

Provide findings as a JSON array. Mark executives with concerning backgrounds as medium/high severity.`,
      
      'risk_indicators': `Analyze the documents for risk indicators related to "${research.targetName}". Look for:
- Financial risks (debt, losses, cash flow issues)
- Operational risks (supply chain, key person dependency)
- Legal/regulatory risks (lawsuits, violations, investigations)
- Reputational risks (negative press, controversies)
- Compliance gaps
- Red flags in contracts or communications

Provide findings as a JSON array. Rate severity based on potential impact.`,
      
      'financial_analysis': `Extract and analyze all financial information about "${research.targetName}":
- Revenue and revenue growth trends
- Profitability metrics
- Key financial ratios
- Debt levels and structure
- Cash position and burn rate
- Customer concentration
- Working capital analysis
- Capital expenditure patterns

Provide findings as a JSON array with severity based on financial health indicators.`,
      
      'material_contracts': `Identify and analyze key contracts and agreements for "${research.targetName}":
- Major customer contracts (terms, duration, value)
- Supplier/vendor agreements
- Partnership and joint venture agreements
- Licensing agreements
- Employment agreements (especially change of control provisions)
- Real estate leases
- Debt and financing agreements
- Unusual or concerning terms

Provide findings as a JSON array. Mark contracts with unfavorable or unusual terms as medium/high severity.`,
      
      'litigation_regulatory': `Search documents for litigation and regulatory matters involving "${research.targetName}":
- Pending lawsuits and claims
- Past settlements or judgments
- Regulatory investigations
- Compliance issues or violations
- Government inquiries
- Environmental matters
- Employment disputes
- IP litigation

Provide findings as a JSON array with severity based on potential exposure.`,
      
      'competitive_landscape': `Analyze the competitive position of "${research.targetName}":
- Key competitors and market share
- Competitive advantages and moats
- Industry trends affecting the company
- Market position and differentiation
- Barriers to entry
- Threats from new entrants or substitutes

Provide findings as a JSON array. Highlight competitive vulnerabilities as medium severity.`,
      
      'ip_technology': `Evaluate intellectual property and technology for "${research.targetName}":
- Patents owned or pending
- Trademarks and brands
- Trade secrets and proprietary processes
- Technology stack and infrastructure
- R&D capabilities
- IP risks and dependencies
- Open source usage

Provide findings as a JSON array.`,
      
      'customer_concentration': `Analyze customer relationships for "${research.targetName}":
- Top customers and revenue concentration
- Customer contract terms and duration
- Customer retention and churn
- Relationship risks
- Dependencies on key accounts
- Geographic distribution

Provide findings as a JSON array. High concentration is medium/high severity.`,
      
      'news_media': `Based on the documents, identify any news or media coverage patterns for "${research.targetName}":
- Press coverage (positive and negative)
- Industry recognition
- Social media presence
- Executive public statements
- Crisis history
- Reputation indicators

Provide findings as a JSON array.`,
      
      'business_lines': `Identify and analyze the business lines/segments of "${research.targetName}":
- Products and services offered
- Revenue by segment
- Growth by segment
- Profitability by line
- New product pipeline
- Discontinued operations

Provide findings as a JSON array.`,
      
      'contradiction_detection': `Look for contradictions, inconsistencies, or conflicts in the documents about "${research.targetName}":
- Numbers that don't match between documents
- Conflicting statements about the same topic
- Timeline inconsistencies
- Different versions of events
- Mismatched financial figures
- Statements that contradict known facts

Provide findings as a JSON array. All contradictions should be medium/high severity with isKeyFinding=true.`,
    };
    
    const prompt = modulePrompts[module];
    if (!prompt) return [];
    
    try {
      const response = await openai.chat.completions.create({
        model: 'gpt-4o',
        messages: [
          {
            role: 'system',
            content: `You are an expert M&A due diligence analyst performing background research. Analyze documents carefully and provide structured findings. Always respond with valid JSON.`
          },
          {
            role: 'user',
            content: `${prompt}\n\n=== DOCUMENTS ===\n${documentText.substring(0, 50000)}`
          }
        ],
        response_format: { type: 'json_object' },
        temperature: 0.3,
        max_tokens: 4000,
      });
      
      const content = response.choices[0].message.content || '{}';
      const parsed = JSON.parse(content);
      const findings = Array.isArray(parsed) ? parsed : (parsed.findings || parsed.results || []);
      
      // Insert findings into database
      for (const finding of findings) {
        await db
          .insert(schema.researchFindings)
          .values({
            researchId,
            module,
            category: finding.category || module,
            title: finding.title || 'Finding',
            description: finding.description || '',
            details: finding.details || null,
            severity: finding.severity || 'info',
            isKeyFinding: finding.isKeyFinding || false,
            requiresFollowUp: finding.requiresFollowUp || false,
            sourceType: 'ai_analysis',
            sourceExcerpt: finding.sourceExcerpt || null,
            confidenceScore: finding.confidence || 0.8,
          });
      }
      
      return findings;
    } catch (error) {
      console.error(`Error in AI module ${module}:`, error);
      return [];
    }
  }
  
  // Generate executive summary
  async function generateExecutiveSummary(research: any, findings: any[]): Promise<string> {
    const keyFindings = findings.filter(f => f.severity === 'high' || f.severity === 'critical' || f.isKeyFinding);
    
    try {
      const response = await openai.chat.completions.create({
        model: 'gpt-4o',
        messages: [
          {
            role: 'system',
            content: 'You are a senior M&A attorney preparing an executive briefing for partners. Write clearly and professionally.'
          },
          {
            role: 'user',
            content: `Write a concise executive summary (3-4 paragraphs) for the background research on "${research.targetName}" (${research.targetIndustry || 'Industry unknown'}).

Key Findings:
${keyFindings.slice(0, 15).map(f => `- [${f.severity?.toUpperCase()}] ${f.title}: ${f.description?.substring(0, 200)}`).join('\n')}

Total findings analyzed: ${findings.length}
Documents reviewed: ${research.documentCount || 0}

Include:
1. Overview of the target and key business characteristics
2. Notable risk areas requiring attention
3. Potential red flags or concerns discovered
4. Recommended areas for deeper due diligence`
          }
        ],
        temperature: 0.4,
        max_tokens: 1500,
      });
      
      return response.choices[0].message.content || 'Executive summary could not be generated.';
    } catch (error) {
      console.error("Error generating executive summary:", error);
      return 'Executive summary generation failed.';
    }
  }
  
  // Calculate risk score from findings
  function calculateResearchRiskScore(findings: any[]): number {
    if (findings.length === 0) return 0;
    
    const severityWeights: Record<string, number> = {
      'critical': 100,
      'high': 75,
      'medium': 40,
      'low': 15,
      'info': 5,
    };
    
    const weightedScores = findings.map(f => severityWeights[f.severity || 'info'] || 5);
    const avgScore = weightedScores.reduce((a, b) => a + b, 0) / weightedScores.length;
    
    // Boost score based on number of high/critical findings
    const criticalCount = findings.filter(f => f.severity === 'critical').length;
    const highCount = findings.filter(f => f.severity === 'high').length;
    const boost = Math.min(20, criticalCount * 5 + highCount * 2);
    
    return Math.min(100, Math.round(avgScore + boost));
  }

  // ===== Third-Party/Vendor Risk Management API Endpoints =====

  // Helper function to generate vendor number
  async function generateVendorNumber(): Promise<string> {
    const year = new Date().getFullYear();
    const vendors = await db.select().from(schema.vendors);
    const thisYearVendors = vendors.filter(v => 
      v.vendorNumber.startsWith(`VND-${year}`)
    );
    const nextNumber = (thisYearVendors.length + 1).toString().padStart(4, '0');
    return `VND-${year}-${nextNumber}`;
  }

  // Helper function to calculate overall risk score from assessment categories (58 total)
  function calculateOverallRiskScore(assessment: any): number {
    // ESG Categories (19 categories, weight: 20%)
    const esgCategories = [
      assessment.environmentalCompliance || 0,
      assessment.carbonFootprint || 0,
      assessment.wasteManagement || 0,
      assessment.energyEfficiency || 0,
      assessment.waterUsage || 0,
      assessment.biodiversityImpact || 0,
      assessment.climateRisk || 0,
      assessment.laborPractices || 0,
      assessment.humanRights || 0,
      assessment.diversityInclusion || 0,
      assessment.healthSafety || 0,
      assessment.communityImpact || 0,
      assessment.productSafety || 0,
      assessment.boardComposition || 0,
      assessment.executiveCompensation || 0,
      assessment.shareholderRights || 0,
      assessment.businessEthics || 0,
      assessment.antiCorruption || 0,
      assessment.transparency || 0,
    ];
    const esgAvg = esgCategories.reduce((sum, score) => sum + score, 0) / esgCategories.length;
    
    // Regulatory & Compliance Categories (12 categories, weight: 25%)
    const regulatoryCategories = [
      assessment.regulatoryCompliance || 0,
      assessment.fcpaCompliance || 0,
      assessment.gdprCompliance || 0,
      assessment.ccpaCompliance || 0,
      assessment.soxCompliance || 0,
      assessment.pcidssCompliance || 0,
      assessment.hipaaCompliance || 0,
      assessment.iso27001Compliance || 0,
      assessment.soc2Compliance || 0,
      assessment.exportControlCompliance || 0,
      assessment.sanctionsScreening || 0,
      assessment.antiMoneyLaundering || 0,
    ];
    const regulatoryAvg = regulatoryCategories.reduce((sum, score) => sum + score, 0) / regulatoryCategories.length;
    
    // Financial Risk Categories (6 categories, weight: 20%)
    const financialCategories = [
      assessment.financialStability || 0,
      assessment.creditRating || 0,
      assessment.liquidityRisk || 0,
      assessment.profitability || 0,
      assessment.debtLevels || 0,
      assessment.cashFlowHealth || 0,
    ];
    const financialAvg = financialCategories.reduce((sum, score) => sum + score, 0) / financialCategories.length;
    
    // Operational Risk Categories (7 categories, weight: 15%)
    const operationalCategories = [
      assessment.businessContinuity || 0,
      assessment.disasterRecovery || 0,
      assessment.operationalResilience || 0,
      assessment.qualityManagement || 0,
      assessment.supplyChainRisk || 0,
      assessment.geopoliticalRisk || 0,
      assessment.concentrationRisk || 0,
    ];
    const operationalAvg = operationalCategories.reduce((sum, score) => sum + score, 0) / operationalCategories.length;
    
    // Cybersecurity & Data Risk Categories (7 categories, weight: 15%)
    const cyberCategories = [
      assessment.cyberSecurityPosture || 0,
      assessment.dataProtection || 0,
      assessment.incidentResponseCapability || 0,
      assessment.vulnerabilityManagement || 0,
      assessment.accessControls || 0,
      assessment.encryptionPractices || 0,
      assessment.thirdPartyRisk || 0,
    ];
    const cyberAvg = cyberCategories.reduce((sum, score) => sum + score, 0) / cyberCategories.length;
    
    // Reputational Risk Categories (4 categories, weight: 5%)
    const reputationalCategories = [
      assessment.reputationalRisk || 0,
      assessment.mediaPerception || 0,
      assessment.customerSatisfaction || 0,
      assessment.litigationHistory || 0,
    ];
    const reputationalAvg = reputationalCategories.reduce((sum, score) => sum + score, 0) / reputationalCategories.length;
    
    // Strategic Risk Categories (4 categories, included in overall with 5% weight)
    const strategicCategories = [
      assessment.strategicAlignment || 0,
      assessment.innovationCapacity || 0,
      assessment.marketPosition || 0,
      assessment.competitiveAdvantage || 0,
    ];
    const strategicAvg = strategicCategories.reduce((sum, score) => sum + score, 0) / strategicCategories.length;
    
    // Calculate weighted average (total 100%)
    const weightedScore = (
      (esgAvg * 0.20) +           // ESG: 20%
      (regulatoryAvg * 0.25) +    // Regulatory: 25%
      (financialAvg * 0.20) +     // Financial: 20%
      (operationalAvg * 0.15) +   // Operational: 15%
      (cyberAvg * 0.15) +         // Cybersecurity: 15%
      (reputationalAvg * 0.03) +  // Reputational: 3%
      (strategicAvg * 0.02)       // Strategic: 2%
    );
    
    return Math.round(weightedScore);
  }

  // Vendors endpoints
  app.get("/api/vendors", isAuthenticated, requireRole("admin", "compliance_officer", "auditor"), async (req, res) => {
    try {
      const { status, tier } = req.query;
      
      const validStatuses = ["pending_onboarding", "onboarding_in_progress", "active", "under_review", "suspended", "terminated", "offboarding"];
      const validTiers = ["critical", "strategic", "tactical", "low_risk"];
      
      let query = db.select().from(schema.vendors);
      const conditions = [];
      
      if (status && typeof status === "string" && validStatuses.includes(status)) {
        conditions.push(eq(schema.vendors.status, status as any));
      }
      if (tier && typeof tier === "string" && validTiers.includes(tier)) {
        conditions.push(eq(schema.vendors.tier, tier as any));
      }
      
      if (conditions.length > 0) {
        query = query.where(and(...conditions)) as any;
      }
      
      const vendors = await query.orderBy(desc(schema.vendors.overallRiskScore), schema.vendors.vendorName);
      
      res.json(vendors);
    } catch (error: any) {
      console.error("Error fetching vendors:", error);
      res.status(500).json({ message: error.message });
    }
  });

