  app.post("/api/vendors/:vendorId/assessments", isAuthenticated, requireRole("admin", "compliance_officer"), async (req, res) => {
    try {
      const validated = schema.insertVendorRiskAssessmentSchema.parse(req.body);
      
      // Calculate overall risk score from categories
      const overallScore = calculateOverallRiskScore(validated);
      
      const [assessment] = await db
        .insert(schema.vendorRiskAssessments)
        .values({
          ...validated,
          vendorId: req.params.vendorId,
          overallScore,
          assessedBy: req.user!.id,
        })
        .returning();
      
      // Update vendor's overall risk score and last assessment date
      const [vendor] = await db.select().from(schema.vendors).where(eq(schema.vendors.id, req.params.vendorId));
      const previousScore = vendor?.overallRiskScore || 0;
      
      await db
        .update(schema.vendors)
        .set({
          overallRiskScore: overallScore,
          lastRiskAssessmentDate: new Date(),
          updatedAt: new Date(),
        })
        .where(eq(schema.vendors.id, req.params.vendorId));
      
      // Generate alert if risk score increased significantly
      if (overallScore > previousScore + 10) {
        await db.insert(schema.vendorRiskAlerts).values({
          vendorId: req.params.vendorId,
          alertType: "risk_score_increase",
          severity: overallScore >= 70 ? "critical" : overallScore >= 50 ? "high" : "medium",
          title: `Significant Risk Score Increase for ${vendor?.vendorName}`,
          description: `Risk score increased from ${previousScore} to ${overallScore} (+${overallScore - previousScore} points)`,
          previousRiskScore: previousScore,
          currentRiskScore: overallScore,
          riskScoreChange: overallScore - previousScore,
          isAutomated: "yes",
          triggeredBy: "system",
          relatedAssessmentId: assessment.id,
          createdBy: req.user!.id,
        });
      }
      
      await logAction(req, "vendor_assessment_created", "vendor_assessment", assessment.id, { vendorId: req.params.vendorId, overallScore });
      res.json(assessment);
    } catch (error: any) {
      console.error("Error creating vendor assessment:", error);
      res.status(400).json({ message: error.message });
    }
  });

