  app.get("/api/vendors/dashboard/metrics", isAuthenticated, requireRole("admin", "compliance_officer", "auditor"), async (req, res) => {
    try {
      const vendors = await db.select().from(schema.vendors);
      const assessments = await db.select().from(schema.vendorRiskAssessments);
      const alerts = await db.select().from(schema.vendorRiskAlerts);
      const onboardingWorkflows = await db.select().from(schema.vendorOnboardingWorkflows);
      
      // Vendor metrics
      const activeVendors = vendors.filter(v => v.status === "active");
      const criticalVendors = vendors.filter(v => v.tier === "critical");
      const highRiskVendors = vendors.filter(v => v.overallRiskScore >= 70);
      const vendorsByTier = {
        critical: vendors.filter(v => v.tier === "critical").length,
        strategic: vendors.filter(v => v.tier === "strategic").length,
        tactical: vendors.filter(v => v.tier === "tactical").length,
        low_risk: vendors.filter(v => v.tier === "low_risk").length,
      };
      
      // Assessment metrics
      const recentAssessments = assessments.filter(a => {
        const date = new Date(a.assessmentDate);
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
        return date >= thirtyDaysAgo;
      });
      
      // Alert metrics
      const openAlerts = alerts.filter(a => a.status === "open");
      const criticalAlerts = alerts.filter(a => a.severity === "critical" && a.status === "open");
      
      // Onboarding metrics
      const activeOnboarding = onboardingWorkflows.filter(w => !["approved", "rejected"].includes(w.status));
      
      res.json({
        vendors: {
          total: vendors.length,
          active: activeVendors.length,
          critical: criticalVendors.length,
          highRisk: highRiskVendors.length,
          byTier: vendorsByTier,
        },
        assessments: {
          total: assessments.length,
          recent: recentAssessments.length,
        },
        alerts: {
          total: alerts.length,
          open: openAlerts.length,
          critical: criticalAlerts.length,
        },
        onboarding: {
          active: activeOnboarding.length,
        },
      });
    } catch (error: any) {
      console.error("Error fetching vendor dashboard metrics:", error);
      res.status(500).json({ message: error.message });
    }
  });

