  // Share document with another user (creates notification)
  app.post("/api/communications/:id/share", isAuthenticated, requireRole("admin", "compliance_officer", "attorney", "auditor"), async (req: any, res) => {
    try {
      const { recipientUserIds, message } = req.body;
      
      if (!recipientUserIds || !Array.isArray(recipientUserIds) || recipientUserIds.length === 0) {
        return res.status(400).json({ message: "At least one recipient is required" });
      }

      // Get the document
      const communication = await storage.getCommunication(req.params.id);
      if (!communication) {
        return res.status(404).json({ message: "Document not found" });
      }

      // Get sender's info for the notification
      const sender = await storage.getUser(req.user.id);
      const senderName = sender ? `${sender.firstName || ''} ${sender.lastName || ''}`.trim() || sender.email : 'A team member';

      // Create notifications for all recipients
      const { createNotification } = await import('./services/notification-service');
      const notifications = [];
      const emailsSent: string[] = [];
      
      // Get the base URL for document links
      const baseUrl = process.env.REPLIT_DEV_DOMAIN 
        ? `https://${process.env.REPLIT_DEV_DOMAIN}` 
        : `https://${process.env.REPL_SLUG}.${process.env.REPL_OWNER}.repl.co`;
      
      for (const recipientId of recipientUserIds) {
        // Don't notify yourself
        if (recipientId === req.user.id) continue;
        
        // Get recipient info for email
        const recipient = await storage.getUser(recipientId);
        
        const notification = await createNotification(
          recipientId,
          "document_review_request",
          `${senderName} flagged a document for your review`,
          message || `Please review: ${communication.subject || 'Untitled Document'}`,
          `/document-review?docId=${communication.id}`,
          {
            documentId: communication.id,
            documentSubject: communication.subject,
            sharedBy: req.user.id,
            sharedByName: senderName,
          }
        );
        notifications.push(notification);
        
        // Send email notification if recipient has email
        if (recipient?.email && emailService.isReady()) {
          try {
            const recipientName = `${recipient.firstName || ''} ${recipient.lastName || ''}`.trim() || 'User';
            await emailService.sendDocumentShareEmail({
              recipientName,
              recipientEmail: recipient.email,
              senderName,
              documentTitle: communication.subject || 'Untitled Document',
              documentType: communication.communicationType || 'Communication',
              message: message || undefined,
              documentUrl: `${baseUrl}/document-review?docId=${communication.id}`,
            });
            emailsSent.push(recipient.email);
          } catch (emailError) {
            console.error(`[Share] Failed to send email to ${recipient.email}:`, emailError);
          }
        }
      }

      await logAction(req, "document_shared", "communication", communication.id, { 
        recipientUserIds,
        message,
        emailsSent,
      });

      res.json({ 
        success: true, 
        message: `Document shared with ${notifications.length} user(s)${emailsSent.length > 0 ? ` (${emailsSent.length} email(s) sent)` : ''}`,
        notificationCount: notifications.length,
        emailCount: emailsSent.length,
      });
    } catch (error: any) {
      console.error("Error sharing document:", error);
      res.status(500).json({ message: error.message });
    }
  });

