  // Whistleblower / Hotline Routes (PUBLIC - No Authentication Required)
  app.post("/api/whistleblower/submit", async (req: any, res) => {
    try {
      const { 
        isAnonymous,
        intakeChannel,
        incidentCategory,
        incidentSubcategory,
        incidentDescription,
        incidentDate,
        incidentLocation,
        allegedViolators,
        witnesses,
        requiresConfidentiality,
        severity,
        reporterName,
        reporterEmail,
        reporterPhone,
      } = req.body;

      // Generate unique report number
      const year = new Date().getFullYear();
      const existingReports = await db.select().from(schema.hotlineReports);
      const thisYearReports = existingReports.filter(r => 
        r.reportNumber.startsWith(`AUTO-HTL-${year}`)
      );
      const nextNumber = (thisYearReports.length + 1).toString().padStart(4, '0');
      const reportNumber = `AUTO-HTL-${year}-${nextNumber}`;

      // Parse JSON strings
      const violatorsArray = typeof allegedViolators === 'string' ? JSON.parse(allegedViolators) : allegedViolators || [];
      const witnessesArray = typeof witnesses === 'string' ? JSON.parse(witnesses) : witnesses || [];

      // Generate anonymous access code for status lookup
      const accessCode = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);

      // Calculate SLA deadlines (EU requirements: 7 days acknowledgment, 90 days follow-up)
      const now = new Date();
      const acknowledgmentDeadline = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
      const followUpDeadline = new Date(now.getTime() + 90 * 24 * 60 * 60 * 1000);

      // Create the hotline report with inline reporter fields
      const [report] = await db.insert(schema.hotlineReports).values({
        reportNumber,
        isAnonymous: isAnonymous === "true" ? "true" : "false",
        reporterName: isAnonymous === "false" ? reporterName : null,
        reporterEmail: isAnonymous === "false" ? reporterEmail : null,
        reporterPhone: isAnonymous === "false" ? reporterPhone : null,
        reporterRelationship: isAnonymous === "false" ? "employee" : null,
        anonymousAccessCode: accessCode,
        intakeChannel: intakeChannel || "web",
        incidentCategory,
        incidentSubcategory,
        incidentDescription,
        incidentDate: incidentDate ? new Date(incidentDate) : null,
        incidentLocation,
        allegedViolators: JSON.stringify(violatorsArray),
        witnesses: JSON.stringify(witnessesArray),
        requiresConfidentiality: requiresConfidentiality === "true" ? "true" : "false",
        severity: severity || "medium",
        status: "intake",
        acknowledgmentDeadline,
        followUpDeadline,
      }).returning();

      // Create audit log (without user ID since this is public)
      await db.insert(schema.auditLogs).values({
        action: "whistleblower_report_submitted",
        entityType: "hotline_report",
        entityId: report.id,
        details: JSON.stringify({
          reportNumber,
          isAnonymous: report.isAnonymous,
          incidentCategory,
        }),
        ipAddress: req.ip,
        userAgent: req.headers["user-agent"],
      });

      const response = { 
        reportNumber: report.reportNumber,
        accessCode: isAnonymous === "true" ? accessCode : undefined,
      };
      console.log("[Whistleblower Submit] Returning response:", response);
      res.status(201).json(response);
    } catch (error: any) {
      console.error("Error submitting whistleblower report:", error);
      res.status(500).json({ message: "Failed to submit report. Please try again." });
    }
  });

  app.get("/api/whistleblower/lookup/:reportNumber", async (req, res) => {
    try {
      const { reportNumber } = req.params;

      const [report] = await db.select()
        .from(schema.hotlineReports)
        .where(eq(schema.hotlineReports.reportNumber, reportNumber))
        .limit(1);

      if (!report) {
        return res.status(404).json({ message: "Report not found" });
      }

      // Return limited information for anonymous lookup
      const response = {
        reportNumber: report.reportNumber,
        status: report.status || "intake",
        incidentCategory: report.incidentCategory,
        intakeDate: report.intakeDate?.toISOString(),
        assignedTo: report.assignedTo ? "Assigned" : undefined,
        lastUpdate: report.updatedAt?.toISOString(),
      };
      console.log("[Whistleblower Lookup] Returning response:", response);
      res.json(response);
    } catch (error: any) {
      console.error("Error looking up report:", error);
      res.status(500).json({ message: "Failed to look up report" });
    }
  });

  // Custom Rules API (Compliance Logic Studio)
  // GET /api/rules - List all detection rules (built-in + custom)
  app.get("/api/rules", requireRole("admin", "compliance_officer", "attorney"), async (req, res) => {
    try {
      const { isCustom, isActive, severity, violationType } = req.query;
      
      const conditions = [];
      if (isCustom !== undefined) {
        conditions.push(eq(schema.detectionRules.isCustom, isCustom === "true" ? "true" : "false"));
      }
      if (isActive !== undefined) {
        conditions.push(eq(schema.detectionRules.isActive, isActive === "true" ? "true" : "false"));
      }
      if (severity) {
        conditions.push(eq(schema.detectionRules.severity, severity as any));
      }
      if (violationType) {
        conditions.push(eq(schema.detectionRules.violationType, violationType as any));
      }
      
      let rules;
      if (conditions.length > 0) {
        rules = await db.select()
          .from(schema.detectionRules)
          .where(and(...conditions))
          .orderBy(desc(schema.detectionRules.createdAt));
      } else {
        rules = await db.select()
          .from(schema.detectionRules)
          .orderBy(desc(schema.detectionRules.createdAt));
      }
      
      // Transform string booleans to actual booleans for frontend
      const transformedRules = rules.map(rule => ({
        ...rule,
        isActive: rule.isActive === "true",
        isCustom: rule.isCustom === "true",
      }));
      
      res.json(transformedRules);
    } catch (error: any) {
      console.error("Error fetching rules:", error);
      res.status(500).json({ message: "Failed to fetch rules" });
    }
  });

  // POST /api/rules - Create custom rule
  app.post("/api/rules", requireRole("admin", "compliance_officer"), async (req, res) => {
    try {
      const {
        ruleName,
        ruleDescription,
        detectionType,
        violationType,
        keywords,
        regexPatterns,
        severity,
        riskScore,
        conditionGroups,
        numericThresholds,
        entityExclusions,
        templateId,
      } = req.body;

      const newRule = await db.insert(schema.detectionRules).values({
        ruleName,
        ruleDescription,
        detectionType: detectionType || "other_violation",
        violationType: violationType || "other",
        keywords: keywords || [],
        regexPatterns: regexPatterns || [],
        severity: severity || "medium",
        riskScore: riskScore || 50,
        isCustom: "true",
        isActive: "false", // Start as inactive until tested
        conditionGroups,
        numericThresholds,
        entityExclusions,
        templateId,
        createdBy: req.user?.id,
      }).returning();

      console.log("[Custom Rules] Created new rule:", newRule[0].id);
      res.status(201).json(newRule[0]);
    } catch (error: any) {
      console.error("Error creating rule:", error);
      res.status(500).json({ message: "Failed to create rule" });
    }
  });

  // GET /api/rules/:id - Get single rule
  app.get("/api/rules/:id", requireRole("admin", "compliance_officer", "attorney"), async (req, res) => {
    try {
      const { id } = req.params;
      
      const [rule] = await db.select()
        .from(schema.detectionRules)
        .where(eq(schema.detectionRules.id, id))
        .limit(1);

      if (!rule) {
        return res.status(404).json({ message: "Rule not found" });
      }

      // Transform string booleans to actual booleans for frontend
      const transformedRule = {
        ...rule,
        isActive: rule.isActive === "true",
        isCustom: rule.isCustom === "true",
      };

      res.json(transformedRule);
    } catch (error: any) {
      console.error("Error fetching rule:", error);
      res.status(500).json({ message: "Failed to fetch rule" });
    }
  });

  // PATCH /api/rules/:id - Update rule
  app.patch("/api/rules/:id", requireRole("admin", "compliance_officer"), async (req, res) => {
    try {
      const { id } = req.params;
      const updates = req.body;

      // Increment version if significant changes
      if (updates.keywords || updates.numericThresholds || updates.conditionGroups) {
        const [currentRule] = await db.select()
          .from(schema.detectionRules)
          .where(eq(schema.detectionRules.id, id))
          .limit(1);
        
        if (currentRule) {
          updates.ruleVersion = (currentRule.ruleVersion || 1) + 1;
        }
      }

      updates.updatedAt = new Date();

      const [updatedRule] = await db.update(schema.detectionRules)
        .set(updates)
        .where(eq(schema.detectionRules.id, id))
        .returning();

      if (!updatedRule) {
        return res.status(404).json({ message: "Rule not found" });
      }

      console.log("[Custom Rules] Updated rule:", id);
      res.json(updatedRule);
    } catch (error: any) {
      console.error("Error updating rule:", error);
      res.status(500).json({ message: "Failed to update rule" });
    }
  });

  // DELETE /api/rules/:id - Soft delete rule (deactivate)
  app.delete("/api/rules/:id", requireRole("admin"), async (req, res) => {
    try {
      const { id } = req.params;

      const [rule] = await db.update(schema.detectionRules)
        .set({ isActive: "false", updatedAt: new Date() })
        .where(eq(schema.detectionRules.id, id))
        .returning();

      if (!rule) {
        return res.status(404).json({ message: "Rule not found" });
      }

      console.log("[Custom Rules] Deactivated rule:", id);
      res.json({ message: "Rule deactivated successfully" });
    } catch (error: any) {
      console.error("Error deleting rule:", error);
      res.status(500).json({ message: "Failed to delete rule" });
    }
  });

