        selectedTagIds,
        exclusionTagIds: exclusionTagIds || [],
        exportFormat: exportFormat || "pdf",
        batesPrefix: batesPrefix || "PROD",
        batesPadding: batesPadding || 6,
        requestedBy: req.user.id,
