  // ===== AMBIENT INTELLIGENCE - Live Meeting Transcription with AI Suggestions =====
  // Get all ambient intelligence sessions for the current user
  app.get("/api/ambient-sessions", isAuthenticated, async (req: any, res) => {
    try {
      const { caseId, unlinked } = req.query;
      
      // Enterprise compliance platform - sessions are visible to all authenticated users
      // Join with summaries to include AI-generated summary text
      const baseQuery = db
        .select({
          id: schema.ambientSessions.id,
          caseId: schema.ambientSessions.caseId,
          sessionName: schema.ambientSessions.sessionName,
          sessionType: schema.ambientSessions.sessionType,
          status: schema.ambientSessions.status,
          notes: schema.ambientSessions.notes,
          startedAt: schema.ambientSessions.startedAt,
          endedAt: schema.ambientSessions.endedAt,
          durationSeconds: schema.ambientSessions.durationSeconds,
          participantNames: schema.ambientSessions.participantNames,
          createdBy: schema.ambientSessions.createdBy,
          createdAt: schema.ambientSessions.createdAt,
          updatedAt: schema.ambientSessions.updatedAt,
          aiSummary: schema.ambientSessionSummaries.summaryText,
        })
        .from(schema.ambientSessions)
        .leftJoin(
          schema.ambientSessionSummaries,
          eq(schema.ambientSessions.id, schema.ambientSessionSummaries.sessionId)
        );
      
      // Filter by case if specified, or filter for unlinked sessions
      let sessions;
      if (caseId) {
        sessions = await baseQuery
          .where(eq(schema.ambientSessions.caseId, caseId as string))
          .orderBy(desc(schema.ambientSessions.createdAt))
          .limit(50);
      } else if (unlinked === "true") {
        // Return only sessions without a linked case
        sessions = await baseQuery
          .where(isNull(schema.ambientSessions.caseId))
          .orderBy(desc(schema.ambientSessions.createdAt))
          .limit(50);
      } else {
        sessions = await baseQuery
          .orderBy(desc(schema.ambientSessions.createdAt))
          .limit(50);
      }
      // Add fullTranscript field (expected by frontend, derived from having transcripts)
      const sessionsWithTranscriptFlag = await Promise.all(
        sessions.map(async (session) => {
          const [transcriptResult] = await db
            .select({ count: sql<number>`count(*)` })
            .from(schema.ambientTranscripts)
            .where(eq(schema.ambientTranscripts.sessionId, session.id));
          
          return {
            ...session,
            fullTranscript: transcriptResult.count > 0 ? "has_transcript" : null,
          };
        })
      );
      
      res.json(sessionsWithTranscriptFlag);
    } catch (error: any) {
      console.error("Error fetching ambient sessions:", error);
      res.status(500).json({ message: error.message });
    }
  });

