// Rule evaluation engine for custom rules
function evaluateRule(rule: any, text: string): any {
  const lowerText = text.toLowerCase();
  const matches: any[] = [];
  let confidence = 0;
  let matched = false;

  // 1. Keyword matching
  if (rule.keywords && Array.isArray(rule.keywords)) {
    for (const keyword of rule.keywords) {
      if (lowerText.includes(keyword.toLowerCase())) {
        matches.push({
          type: "keyword",
          value: keyword,
          position: lowerText.indexOf(keyword.toLowerCase()),
        });
        confidence += 15;
        matched = true;
      }
    }
  }

  // 2. Regex pattern matching
  if (rule.regexPatterns && Array.isArray(rule.regexPatterns)) {
    for (const pattern of rule.regexPatterns) {
      try {
        const regex = new RegExp(pattern, "gi");
        const regexMatches = text.match(regex);
        if (regexMatches) {
          matches.push({
            type: "regex",
            value: pattern,
            matchedText: regexMatches,
          });
          confidence += 20;
          matched = true;
        }
      } catch (e) {
        console.error("Invalid regex pattern:", pattern);
      }
    }
  }

  // 3. Numeric threshold evaluation
  if (rule.numericThresholds && Array.isArray(rule.numericThresholds)) {
    for (const threshold of rule.numericThresholds) {
      // Extract numbers from text
      const numberMatches = text.match(/\$?[\d,]+(?:\.\d{2})?/g);
      if (numberMatches) {
        for (const numStr of numberMatches) {
          const num = parseFloat(numStr.replace(/[$,]/g, ""));
          let thresholdMet = false;

          switch (threshold.operator) {
            case ">":
              thresholdMet = num > threshold.value;
              break;
            case "<":
              thresholdMet = num < threshold.value;
              break;
            case ">=":
              thresholdMet = num >= threshold.value;
              break;
            case "<=":
              thresholdMet = num <= threshold.value;
              break;
            case "=":
              thresholdMet = num === threshold.value;
              break;
          }

          if (thresholdMet) {
            matches.push({
              type: "numeric",
              field: threshold.field,
              operator: threshold.operator,
              threshold: threshold.value,
              actualValue: num,
              matchedText: numStr,
            });
            confidence += 30;
            matched = true;
          }
        }
      }
    }
  }

  // 4. Condition groups (AND/OR logic)
  if (rule.conditionGroups && Array.isArray(rule.conditionGroups)) {
    for (const group of rule.conditionGroups) {
      let groupMatched = false;
      
      if (group.operator === "AND") {
        groupMatched = group.conditions.every((cond: any) => 
          evaluateCondition(cond, lowerText)
        );
      } else if (group.operator === "OR") {
        groupMatched = group.conditions.some((cond: any) => 
          evaluateCondition(cond, lowerText)
        );
      }

      if (groupMatched) {
        matches.push({
          type: "conditionGroup",
          operator: group.operator,
          conditions: group.conditions,
        });
        confidence += 25;
        matched = true;
      }
    }
  }

  confidence = Math.min(confidence, 100);

  return {
    matched,
    confidence,
    matches,
    explanation: generateExplanation(matches, rule),
    timestamp: new Date().toISOString(),
  };
}

// Helper to evaluate individual conditions
function evaluateCondition(condition: any, text: string): boolean {
  switch (condition.type) {
    case "keyword":
      return text.includes(condition.value.toLowerCase());
    case "entity":
      return text.includes(condition.value.toLowerCase());
    case "amount":
      const amounts = text.match(/\$?[\d,]+(?:\.\d{2})?/g);
      if (!amounts) return false;
      return amounts.some(a => {
        const num = parseFloat(a.replace(/[$,]/g, ""));
        switch (condition.operator) {
          case ">": return num > condition.value;
          case "<": return num < condition.value;
          case ">=": return num >= condition.value;
          case "<=": return num <= condition.value;
          case "=": return num === condition.value;
          default: return false;
        }
      });
    default:
      return false;
  }
}

// Generate human-readable explanation of why rule matched
function generateExplanation(matches: any[], rule: any): string {
  if (matches.length === 0) {
    return "No conditions matched";
  }

  const explanations: string[] = [];
  
  for (const match of matches) {
    switch (match.type) {
      case "keyword":
        explanations.push(`Found keyword "${match.value}"`);
        break;
      case "regex":
        explanations.push(`Matched pattern: ${match.matchedText.join(", ")}`);
        break;
      case "numeric":
        explanations.push(
          `${match.field} value ${match.actualValue} ${match.operator} threshold ${match.threshold}`
        );
        break;
      case "conditionGroup":
        explanations.push(`Condition group (${match.operator}) matched`);
        break;
    }
  }

  return `Rule triggered: ${rule.ruleName}. ${explanations.join("; ")}`;
}

// Helper function to calculate compliance score
function calculateComplianceScore(data: {
  pendingTraining: number;
  completedTraining: number;
  pendingPolicies: number;
  totalPolicies: number;
}): number {
  const trainingScore = data.completedTraining / (data.completedTraining + data.pendingTraining || 1);
  const policyScore = (data.totalPolicies - data.pendingPolicies) / (data.totalPolicies || 1);
  return Math.round((trainingScore * 0.6 + policyScore * 0.4) * 100);
}

// Helper function to generate recommended actions for regulatory changes
function generateRecommendedActions(change: any, regulationsCount: number, policiesCount: number, trainingCount: number): string[] {
  const actions = [];
  
  if (change.impactLevel === "critical" || change.impactLevel === "high") {
    actions.push("Immediately convene compliance committee to assess impact");
    actions.push("Assign executive sponsor to oversee implementation");
  }
  
  if (regulationsCount > 0) {
    actions.push(`Review and update ${regulationsCount} affected regulation(s) in knowledge base`);
  }
  
  if (policiesCount > 0) {
    actions.push(`Assess ${policiesCount} active policies for necessary updates`);
  }
  
  if (trainingCount > 0) {
    actions.push(`Evaluate ${trainingCount} training courses for content updates`);
  }
  
  if (change.complianceDeadline) {
    const deadline = new Date(change.complianceDeadline);
    const now = new Date();
    const daysUntilDeadline = Math.floor((deadline.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
    
    if (daysUntilDeadline < 90) {
      actions.push(`URGENT: ${daysUntilDeadline} days until compliance deadline - accelerate implementation`);
    } else {
      actions.push(`Develop implementation timeline (${daysUntilDeadline} days until deadline)`);
    }
  }
  
  actions.push("Conduct risk assessment and gap analysis");
  actions.push("Update compliance obligations matrix");
  actions.push("Communicate changes to affected stakeholders");
  
  return actions;
}

// Helper function to calculate overall risk from compliance gaps
function calculateOverallRisk(gaps: any[]): string {
  if (gaps.length === 0) return "low";
  
  const hasCritical = gaps.some(g => g.severity === "critical");
  const hasHigh = gaps.some(g => g.severity === "high");
  
  if (hasCritical) return "critical";
  if (hasHigh && gaps.length >= 3) return "critical";
  if (hasHigh) return "high";
  if (gaps.length >= 5) return "high";
  if (gaps.length >= 3) return "medium";
  return "low";
}

// Helper function to calculate risk score from likelihood and impact
function calculateRiskScore(likelihood: string, impact: string): number {
  const likelihoodScores: Record<string, number> = {
    rare: 1,
    unlikely: 2,
    possible: 3,
    likely: 4,
    almost_certain: 5,
  };
  
  const impactScores: Record<string, number> = {
    insignificant: 1,
    minor: 2,
    moderate: 3,
    major: 4,
    catastrophic: 5,
  };
  
  return (likelihoodScores[likelihood] || 1) * (impactScores[impact] || 1);
}

// Helper function to generate unique incident number
async function generateIncidentNumber(): Promise<string> {
  const year = new Date().getFullYear();
  const incidents = await db.select().from(schema.grcIncidents);
  const thisYearIncidents = incidents.filter(i => 
    i.incidentNumber.startsWith(`INC-${year}`)
  );
  const nextNumber = (thisYearIncidents.length + 1).toString().padStart(4, '0');
  return `INC-${year}-${nextNumber}`;
}

// AI Task Processing for Findings Module
async function processAiTask(
  taskId: string,
  caseId: string,
  findingId: string | null,
  actionType: string,
  payload: any,
  userId: string
): Promise<void> {
  try {
    // Update task status to processing
    await storage.updateFindingAiTask(taskId, { 
      status: 'processing',
      startedAt: new Date(),
    });

    let result: any = {};
    let generatedContent = '';

    switch (actionType) {
      case 'summarize_interview':
        result = await processSummarizeInterview(caseId, payload, userId);
        generatedContent = result.summary;
        break;

      case 'compare_witnesses':
        result = await processCompareWitnesses(caseId, payload, userId);
        generatedContent = result.comparison;
        break;

      case 'extract_legal_issues':
        result = await processExtractLegalIssues(caseId, payload, userId);
        generatedContent = result.legalIssues;
        break;

      case 'draft_liability_analysis':
        result = await processDraftLiabilityAnalysis(caseId, payload, userId);
        generatedContent = result.liabilityAnalysis;
        break;

      case 'summarize_evidence':
        result = await processSummarizeEvidence(caseId, payload, userId);
        generatedContent = result.summary;
        break;

      case 'generate_timeline':
        result = await processGenerateTimeline(caseId, payload, userId);
        generatedContent = result.timeline;
        break;

      case 'identify_contradictions':
        result = await processIdentifyContradictions(caseId, payload, userId);
        generatedContent = result.contradictions;
        break;

      case 'apply_law':
        result = await processApplyLaw(caseId, payload, userId);
        generatedContent = result.legalAnalysis;
        break;

      case 'build_theory':
        result = await processBuildTheory(caseId, payload, userId);
        generatedContent = result.theoryAnalysis;
        break;

      case 'draft_final_report':
        result = await processDraftFinalReport(caseId, payload, userId);
        generatedContent = result.finalReport;
        break;

      case 'compare_documents':
        result = await processCompareDocuments(caseId, payload, userId);
        generatedContent = result.comparison;
        break;

      case 'timeline_reconciliation':
        result = await processTimelineReconciliation(caseId, payload, userId);
        generatedContent = result.reconciliation;
        break;

      case 'credibility_analysis':
        result = await processCredibilityAnalysis(caseId, payload, userId);
        generatedContent = result.credibilityAssessment;
        break;

      default:
        throw new Error(`Unknown action type: ${actionType}`);
    }

    // Map action types to appropriate entry types
    // Aligned with sidebar categories and product requirements
    const actionToEntryType: Record<string, string> = {
      'summarize_interview': 'note',
      'compare_witnesses': 'credibility',
      'compare_documents': 'contradiction', // Document comparisons identify contradictions
      'extract_legal_issues': 'legal_issue',
      'draft_liability_analysis': 'legal_issue',
      'summarize_evidence': 'note',
      'generate_timeline': 'timeline_event',
      'identify_contradictions': 'contradiction',
      'apply_law': 'legal_issue',
      'build_theory': 'theory',
      'draft_final_report': 'recommendation',
      'timeline_reconciliation': 'timeline_event',
      'credibility_analysis': 'credibility',
      'cross_reference': 'research', // Cross-referencing is research activity
    };

    // If attached to a finding, update the finding and create a version
    if (findingId && generatedContent) {
      const finding = await storage.getFinding(findingId);
      if (finding) {
        const entryType = actionToEntryType[actionType] || 'note';
        
        await storage.updateFinding(
          findingId,
          {
            content: generatedContent,
            summary: result.summary || `AI-generated ${actionType.replace(/_/g, ' ')}`,
            entryType,
            aiGenerated: true,
            legalDomain: payload.legalDomain || null,
          },
          false // Don't create a version yet
        );

        // Create a version for tracking
        await storage.createFindingVersion({
          findingId,
          versionNumber: finding.versionCount + 1,
          versionType: 'ai_suggested',
          title: finding.title,
          content: generatedContent,
          summary: result.summary || `AI-generated ${actionType.replace(/_/g, ' ')}`,
          aiTaskId: taskId,
          createdBy: userId,
        });
      }
    }

    // Update task status to completed with full result object
    const resultSummary = generatedContent ? 
      generatedContent.substring(0, 500) + (generatedContent.length > 500 ? '...' : '') : 
      'Analysis complete';
    
    await storage.updateFindingAiTask(taskId, {
      status: 'completed',
      completedAt: new Date(),
      result: JSON.stringify(result), // Store full result object as JSON
      resultSummary,
    });

  } catch (error: any) {
    console.error(`AI Task ${taskId} failed:`, error);
    await storage.updateFindingAiTask(taskId, {
      status: 'failed',
      completedAt: new Date(),
      error: error.message || 'Unknown error',
    });
  }
}

// AI Processing Functions
async function processSummarizeInterview(caseId: string, payload: any, userId: string) {
  const { interviewId } = payload;
  
  // Get interview data
  const interview = await storage.getInterviewById(interviewId);
  if (!interview) {
    throw new Error('Interview not found');
  }

  // Get recorded interviews for this interview
  const recordedInterviews = await storage.getRecordedInterviewsByInterviewId(interviewId);
  const transcripts = recordedInterviews
    .filter((ri: any) => ri.transcript)
    .map((ri: any) => ri.transcript)
    .join('\n\n');

  if (!transcripts) {
    throw new Error('No transcripts available for this interview');
  }

  // Use OpenAI to summarize
  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a legal investigator summarizing interview transcripts for an internal investigation. 
Focus on key facts, admissions, denials, and any inconsistencies. 
Organize your summary with clear sections: Key Facts, Notable Statements, Areas of Concern, and Follow-up Questions.
Be objective and factual.`
      },
      {
        role: 'user',
        content: `Please summarize the following interview transcript from ${interview.witnessName || 'witness'}:

${transcripts}`
      }
    ],
    temperature: 0.3,
    max_tokens: 2000,
  });

  return {
    summary: response.choices[0].message.content || 'Unable to generate summary',
    interviewId,
    witnessName: interview.witnessName,
  };
}

async function processCompareWitnesses(caseId: string, payload: any, userId: string) {
  const { interviewIds } = payload;
  
  if (!interviewIds || interviewIds.length < 2) {
    throw new Error('At least two interviews are required for comparison');
  }

  // Get interview data for all specified interviews
  const interviews = await Promise.all(
    interviewIds.map((id: string) => storage.getInterviewById(id))
  );

  const validInterviews = interviews.filter(Boolean);
  if (validInterviews.length < 2) {
    throw new Error('Could not find enough valid interviews');
  }

  // Get transcripts for each interview
  const interviewData = await Promise.all(
    validInterviews.map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const transcripts = recorded
        .filter((ri: any) => ri.transcript)
        .map((ri: any) => ri.transcript)
        .join('\n\n');
      return {
        witnessName: interview.witnessName,
        transcripts,
      };
    })
  );

  const witnessContext = interviewData
    .map((d: any, i: number) => `=== Witness ${i + 1}: ${d.witnessName} ===\n${d.transcripts}`)
    .join('\n\n');

  // Use OpenAI to compare
  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a legal investigator comparing testimony from multiple witnesses.
Your goal is to identify:
1. Points of Agreement - Facts that all witnesses agree on
2. Points of Disagreement - Contradictions or differing accounts
3. Unique Information - Facts mentioned by only one witness
4. Credibility Indicators - Signs of reliability or unreliability
5. Follow-up Questions - Areas requiring further investigation

Be objective and highlight specific quotes when identifying discrepancies.`
      },
      {
        role: 'user',
        content: `Please compare the following witness testimonies:

${witnessContext}`
      }
    ],
    temperature: 0.3,
    max_tokens: 3000,
  });

  return {
    comparison: response.choices[0].message.content || 'Unable to generate comparison',
    witnessNames: interviewData.map((d: any) => d.witnessName),
    interviewCount: validInterviews.length,
  };
}

async function processExtractLegalIssues(caseId: string, payload: any, userId: string) {
  // Get case details
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  // Get all communications and interviews for the case
  const communications = await storage.getCommunicationsByCase(caseId);
  const interviews = await storage.getInterviewsByCase(caseId);

  // Sample communications for analysis (limit to avoid token limits)
  const sampleComms = communications.slice(0, 50).map((c: any) => ({
    type: 'email',
    subject: c.subject,
    body: c.body?.substring(0, 500),
    from: c.sender,
    date: c.timestamp,
  }));

  // Get interview summaries
  const interviewSummaries = interviews.map((i: any) => ({
    witness: i.witnessName,
    role: i.witnessRole,
    status: i.status,
  }));

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a senior legal investigator analyzing case materials to identify potential legal issues.
Categorize issues by:
1. Regulatory Violations (FCPA, SOX, Antitrust, BSA/AML, etc.)
2. Civil Liability Exposure
3. Criminal Liability Exposure  
4. Internal Policy Violations
5. Contractual Issues
6. Employment/HR Issues

For each issue, provide:
- Description of the issue
- Relevant evidence
- Potential severity (Low/Medium/High/Critical)
- Recommended next steps`
      },
      {
        role: 'user',
        content: `Analyze the following case materials for ${caseData.name}:

Case Description: ${caseData.description || 'Not provided'}
Case Type: ${caseData.caseType || 'Internal Investigation'}

Communications Sample (${communications.length} total):
${JSON.stringify(sampleComms, null, 2)}

Interviews Conducted:
${JSON.stringify(interviewSummaries, null, 2)}`
      }
    ],
    temperature: 0.3,
    max_tokens: 3000,
  });

  return {
    legalIssues: response.choices[0].message.content || 'Unable to extract legal issues',
    communicationsAnalyzed: Math.min(50, communications.length),
    interviewsReferenced: interviews.length,
  };
}

async function processDraftLiabilityAnalysis(caseId: string, payload: any, userId: string) {
  const { focusAreas, includeRecommendations } = payload;

  // Get case details
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  // Get findings for this case
  const findings = await storage.getFindings(caseId, {});

  // Get interviews
  const interviews = await storage.getInterviewsByCase(caseId);

  // Get alerts
  const alerts = await storage.getAlertsByCase(caseId);

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a senior legal counsel drafting a liability analysis for an internal investigation.
Structure your analysis as follows:
1. Executive Summary
2. Factual Background
3. Legal Analysis
   a. Applicable Laws and Regulations
   b. Elements of Potential Violations
   c. Analysis of Evidence
4. Liability Assessment
   a. Corporate Liability
   b. Individual Liability
5. Mitigating Factors
6. Aggravating Factors
${includeRecommendations ? '7. Recommendations' : ''}

Be thorough but concise. Use legal terminology appropriately.
Note: This is a draft for internal use only and should be reviewed by counsel.`
      },
      {
        role: 'user',
        content: `Draft a liability analysis for: ${caseData.name}

Case Details:
${caseData.description || 'No description provided'}

${focusAreas ? `Focus Areas: ${focusAreas.join(', ')}` : ''}

Investigation Findings (${findings.length} total):
${findings.slice(0, 10).map((f: any) => `- ${f.title}: ${f.summary || f.content?.substring(0, 200)}`).join('\n')}

Interviews Conducted: ${interviews.length}
Witnesses: ${interviews.map((i: any) => i.witnessName).join(', ')}

Alerts/Red Flags: ${alerts.length}
${alerts.slice(0, 5).map((a: any) => `- ${a.violationType}: ${a.message?.substring(0, 100)}`).join('\n')}`
      }
    ],
    temperature: 0.4,
    max_tokens: 4000,
  });

  return {
    liabilityAnalysis: response.choices[0].message.content || 'Unable to draft liability analysis',
    findingsReferenced: Math.min(10, findings.length),
    interviewsReferenced: interviews.length,
    alertsReferenced: Math.min(5, alerts.length),
  };
}

async function processSummarizeEvidence(caseId: string, payload: any, userId: string) {
  const { evidenceIds, evidenceType } = payload;

  let evidenceContent = '';

  if (evidenceType === 'communications') {
    const comms = await storage.getCommunicationsByCase(caseId);
    const relevantComms = evidenceIds 
      ? comms.filter((c: any) => evidenceIds.includes(c.id))
      : comms.slice(0, 20);
    
    evidenceContent = relevantComms.map((c: any) => 
      `From: ${c.sender}\nTo: ${c.recipients}\nDate: ${c.timestamp}\nSubject: ${c.subject}\n${c.body?.substring(0, 500)}`
    ).join('\n---\n');
  }

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are summarizing evidence for a legal investigation.
Provide a clear, organized summary that highlights:
1. Key facts established by the evidence
2. Important dates and timeline
3. Key individuals involved
4. Any red flags or concerning patterns
5. Gaps in the evidence`
      },
      {
        role: 'user',
        content: `Summarize the following evidence:\n\n${evidenceContent}`
      }
    ],
    temperature: 0.3,
    max_tokens: 2000,
  });

  return {
    summary: response.choices[0].message.content || 'Unable to summarize evidence',
    evidenceCount: evidenceIds?.length || 20,
  };
}

async function processGenerateTimeline(caseId: string, payload: any, userId: string) {
  // Get case events
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  // Get communications
  const communications = await storage.getCommunicationsByCase(caseId);
  
  // Get interviews
  const interviews = await storage.getInterviewsByCase(caseId);

  // Get alerts
  const alerts = await storage.getAlertsByCase(caseId);

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are creating a chronological timeline of events for a legal investigation.
Format the timeline with:
- Clear dates
- Brief description of each event
- Key participants
- Significance to the investigation

Organize chronologically and highlight key turning points.`
      },
      {
        role: 'user',
        content: `Create a timeline for: ${caseData.name}

Communications (${communications.length} total):
${communications.slice(0, 30).map((c: any) => `${c.timestamp}: ${c.sender} -> ${c.recipients}: ${c.subject}`).join('\n')}

Interviews:
${interviews.map((i: any) => `${i.scheduledDate || i.createdAt}: Interview with ${i.witnessName} (${i.status})`).join('\n')}

Alerts:
${alerts.slice(0, 10).map((a: any) => `${a.createdAt}: ${a.violationType} - ${a.message?.substring(0, 50)}`).join('\n')}`
      }
    ],
    temperature: 0.3,
    max_tokens: 2000,
  });

  return {
    timeline: response.choices[0].message.content || 'Unable to generate timeline',
    eventsAnalyzed: communications.length + interviews.length + alerts.length,
  };
}

async function processIdentifyContradictions(caseId: string, payload: any, userId: string) {
  // Get all interview transcripts
  const interviews = await storage.getInterviewsByCase(caseId);
  
  const interviewData = await Promise.all(
    interviews.map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const transcripts = recorded
        .filter((ri: any) => ri.transcript)
        .map((ri: any) => ri.transcript)
        .join('\n');
      return {
        witnessName: interview.witnessName,
        transcripts,
      };
    })
  );

  const validInterviews = interviewData.filter((d: any) => d.transcripts);

  if (validInterviews.length < 2) {
    return {
      contradictions: 'Insufficient interview transcripts to identify contradictions. At least 2 interviews with transcripts are required.',
      interviewsAnalyzed: validInterviews.length,
    };
  }

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a legal investigator analyzing witness testimony to identify contradictions.
Look for:
1. Direct Contradictions - Witnesses saying opposite things about the same fact
2. Inconsistencies - Differing accounts that don't directly contradict
3. Timeline Conflicts - Events placed at different times
4. Omissions - Important facts mentioned by one witness but not another
5. Internal Contradictions - A witness contradicting themselves

For each issue, cite specific statements and explain the significance.`
      },
      {
        role: 'user',
        content: `Identify contradictions in the following witness testimonies:

${validInterviews.map((d: any) => `=== ${d.witnessName} ===\n${d.transcripts}`).join('\n\n')}`
      }
    ],
    temperature: 0.3,
    max_tokens: 3000,
  });

  return {
    contradictions: response.choices[0].message.content || 'Unable to identify contradictions',
    interviewsAnalyzed: validInterviews.length,
    witnessNames: validInterviews.map((d: any) => d.witnessName),
  };
}

