async function processApplyLaw(caseId: string, payload: any, userId: string) {
  const { legalDomain } = payload;

  if (!legalDomain) {
    throw new Error('Legal domain is required');
  }

  const legalElements = LEGAL_ELEMENTS[legalDomain];
  if (!legalElements) {
    throw new Error(`Unknown legal domain: ${legalDomain}`);
  }

  // Get case details
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  // Get all case materials
  const findings = await storage.getFindings(caseId, {});
  const interviews = await storage.getInterviewsByCase(caseId);
  const communications = await storage.getCommunicationsByCase(caseId);
  const alerts = await storage.getAlertsByCase(caseId);

  // Get interview transcripts
  const interviewData = await Promise.all(
    interviews.slice(0, 10).map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const transcripts = recorded
        .filter((ri: any) => ri.transcript)
        .map((ri: any) => ri.transcript?.substring(0, 1000))
        .join('\n');
      return {
        witnessName: interview.witnessName,
        witnessRole: interview.witnessRole,
        transcripts,
      };
    })
  );

  const elementsFormatted = legalElements.elements.map((e, i) => `${i + 1}. ${e}`).join('\n');

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a senior attorney conducting an element-by-element legal analysis.

For the claim: ${legalElements.name}${legalElements.statute ? ` (${legalElements.statute})` : ''}

Required Elements:
${elementsFormatted}

For EACH element, provide:
1. ELEMENT NAME - State the legal element
2. LEGAL STANDARD - Brief statement of what must be proven
3. EVIDENCE FOR - Facts and evidence supporting this element
4. EVIDENCE AGAINST - Facts and evidence undermining this element
5. ASSESSMENT - [MET / LIKELY MET / UNCERTAIN / LIKELY NOT MET / NOT MET]
6. GAPS - What additional evidence would be needed

After analyzing all elements, provide:
- OVERALL LIABILITY ASSESSMENT (percentage likelihood: 0-100%)
- KEY RISK FACTORS
- RECOMMENDED NEXT STEPS

Be thorough and cite specific evidence from the case materials.`
      },
      {
        role: 'user',
        content: `Conduct element-by-element analysis for: ${caseData.name}

Case Description: ${caseData.description || 'Not provided'}

=== INVESTIGATION FINDINGS ===
${findings.slice(0, 15).map((f: any) => `[${f.entryType || 'note'}] ${f.title}: ${f.content?.substring(0, 300)}`).join('\n\n')}

=== INTERVIEW SUMMARIES ===
${interviewData.map((d: any) => `${d.witnessName} (${d.witnessRole || 'Unknown Role'}):\n${d.transcripts || 'No transcript'}`).join('\n\n')}

=== KEY COMMUNICATIONS ===
${communications.slice(0, 20).map((c: any) => `[${c.timestamp}] ${c.sender} to ${c.recipients}: ${c.subject} - ${c.body?.substring(0, 150)}`).join('\n')}

=== ALERTS/RED FLAGS ===
${alerts.slice(0, 10).map((a: any) => `${a.violationType}: ${a.message?.substring(0, 100)}`).join('\n')}`
      }
    ],
    temperature: 0.3,
    max_tokens: 4000,
  });

  return {
    legalAnalysis: response.choices[0].message.content || 'Unable to complete legal analysis',
    legalDomain: legalElements.name,
    statute: legalElements.statute,
    elementsAnalyzed: legalElements.elements.length,
    findingsReferenced: Math.min(15, findings.length),
    interviewsReferenced: Math.min(10, interviews.length),
  };
}

async function processBuildTheory(caseId: string, payload: any, userId: string) {
  // Get case details
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  // Get all case materials
  const findings = await storage.getFindings(caseId, {});
  const interviews = await storage.getInterviewsByCase(caseId);
  const communications = await storage.getCommunicationsByCase(caseId);
  const alerts = await storage.getAlertsByCase(caseId);

  // Separate findings by type for better analysis
  const theories = findings.filter((f: any) => f.entryType === 'theory');
  const contradictions = findings.filter((f: any) => f.entryType === 'contradiction');
  const legalIssues = findings.filter((f: any) => f.entryType === 'legal_issue');

  // Get interview transcripts
  const interviewData = await Promise.all(
    interviews.slice(0, 8).map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const transcripts = recorded
        .filter((ri: any) => ri.transcript)
        .map((ri: any) => ri.transcript?.substring(0, 800))
        .join('\n');
      return {
        witnessName: interview.witnessName,
        transcripts,
      };
    })
  );

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a senior investigator and trial attorney building theories of the case.

Your task is to synthesize all evidence into coherent theories that explain what happened.

For each theory, provide:

## PRIMARY THEORY
- **Narrative**: Tell the story of what happened
- **Key Facts**: The core facts that support this theory
- **Supporting Evidence**: Specific evidence that proves each key fact
- **Potential Witnesses**: Who can testify to support this theory
- **Legal Claims Supported**: What legal claims does this theory support
- **Vulnerabilities**: Weaknesses or gaps in this theory
- **Confidence Level**: [HIGH / MEDIUM / LOW] with explanation

## ALTERNATIVE THEORY 1
(Same structure as above)

## ALTERNATIVE THEORY 2
(Same structure if evidence supports multiple alternatives)

## THEORY COMPARISON
- Which theory is best supported by evidence?
- What additional evidence would definitively prove/disprove each theory?
- What are the key pivot points that determine which theory is correct?

Be specific and cite evidence. Consider both plaintiff/complainant and defendant/respondent perspectives.`
      },
      {
        role: 'user',
        content: `Build theory of case for: ${caseData.name}

Case Description: ${caseData.description || 'Not provided'}

=== EXISTING THEORIES (from investigation) ===
${theories.map((f: any) => `${f.title}: ${f.content?.substring(0, 400)}`).join('\n\n')}

=== IDENTIFIED CONTRADICTIONS ===
${contradictions.map((f: any) => `${f.title}: ${f.content?.substring(0, 300)}`).join('\n\n')}

=== LEGAL ISSUES IDENTIFIED ===
${legalIssues.map((f: any) => `${f.title}: ${f.content?.substring(0, 300)}`).join('\n\n')}

=== OTHER FINDINGS ===
${findings.filter((f: any) => !['theory', 'contradiction', 'legal_issue'].includes(f.entryType)).slice(0, 10).map((f: any) => `[${f.entryType || 'note'}] ${f.title}: ${f.content?.substring(0, 200)}`).join('\n\n')}

=== INTERVIEW SUMMARIES ===
${interviewData.map((d: any) => `${d.witnessName}:\n${d.transcripts || 'No transcript'}`).join('\n\n')}

=== KEY COMMUNICATIONS ===
${communications.slice(0, 15).map((c: any) => `[${c.timestamp}] ${c.sender}: ${c.subject} - ${c.body?.substring(0, 100)}`).join('\n')}

=== ALERTS ===
${alerts.slice(0, 8).map((a: any) => `${a.violationType}: ${a.message?.substring(0, 80)}`).join('\n')}`
      }
    ],
    temperature: 0.4,
    max_tokens: 4000,
  });

  return {
    theoryAnalysis: response.choices[0].message.content || 'Unable to build case theory',
    findingsAnalyzed: findings.length,
    interviewsAnalyzed: Math.min(8, interviews.length),
    communicationsAnalyzed: Math.min(15, communications.length),
  };
}

async function processDraftFinalReport(caseId: string, payload: any, userId: string) {
  // Get case details
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  // Get all case materials
  const findings = await storage.getFindings(caseId, {});
  const interviews = await storage.getInterviewsByCase(caseId);
  const communications = await storage.getCommunicationsByCase(caseId);
  const alerts = await storage.getAlertsByCase(caseId);

  // Organize findings by type
  const findingsByType: Record<string, any[]> = {};
  findings.forEach((f: any) => {
    const type = f.entryType || 'note';
    if (!findingsByType[type]) findingsByType[type] = [];
    findingsByType[type].push(f);
  });

  // Get interview summaries
  const interviewSummaries = await Promise.all(
    interviews.map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const hasTranscript = recorded.some((ri: any) => ri.transcript);
      return {
        witnessName: interview.witnessName,
        witnessRole: interview.witnessRole,
        status: interview.status,
        hasTranscript,
      };
    })
  );

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a senior attorney drafting a formal investigative report for an internal investigation.

Structure the report as follows:

# INVESTIGATIVE REPORT

## I. EXECUTIVE SUMMARY
- Brief overview of investigation
- Key findings
- Conclusions and recommendations

## II. INVESTIGATION SCOPE & METHODOLOGY
- What was investigated
- Timeline of investigation
- Investigators involved
- Limitations or constraints

## III. FACTUAL BACKGROUND
- Chronological narrative of events
- Key parties involved
- Relevant organizational context

## IV. WITNESS INTERVIEWS
- Summary of each witness interview
- Key testimony from each witness
- Credibility assessments

## V. DOCUMENTARY EVIDENCE
- Key documents reviewed
- Significant findings from documents
- Patterns or gaps in documentation

## VI. LEGAL ANALYSIS
- Applicable laws and policies
- Analysis of potential violations
- Liability assessment

## VII. FACTUAL FINDINGS
- Findings listed by topic
- Evidence supporting each finding
- Level of certainty for each

## VIII. CONCLUSIONS
- Ultimate conclusions on key questions
- Unresolved issues

## IX. RECOMMENDATIONS
- Recommended actions
- Remediation steps
- Policy improvements

## X. APPENDICES
- List of witnesses interviewed
- List of documents reviewed
- Timeline of key events

Use formal legal writing style. Be thorough but concise. Cite specific evidence.`
      },
      {
        role: 'user',
        content: `Draft investigative report for: ${caseData.name}

Case Description: ${caseData.description || 'Not provided'}
Case Type: ${caseData.caseType || 'Internal Investigation'}
Case Status: ${caseData.status || 'Active'}

=== INVESTIGATION FINDINGS (${findings.length} total) ===

Theories (${findingsByType.theory?.length || 0}):
${(findingsByType.theory || []).map((f: any) => `- ${f.title}: ${f.content?.substring(0, 300)}`).join('\n')}

Legal Issues (${findingsByType.legal_issue?.length || 0}):
${(findingsByType.legal_issue || []).map((f: any) => `- ${f.title}: ${f.content?.substring(0, 300)}`).join('\n')}

Contradictions (${findingsByType.contradiction?.length || 0}):
${(findingsByType.contradiction || []).map((f: any) => `- ${f.title}: ${f.content?.substring(0, 300)}`).join('\n')}

Credibility Notes (${findingsByType.credibility?.length || 0}):
${(findingsByType.credibility || []).map((f: any) => `- ${f.title}: ${f.content?.substring(0, 300)}`).join('\n')}

Other Notes (${findingsByType.note?.length || 0}):
${(findingsByType.note || []).slice(0, 10).map((f: any) => `- ${f.title}: ${f.content?.substring(0, 200)}`).join('\n')}

=== INTERVIEWS CONDUCTED (${interviews.length}) ===
${interviewSummaries.map((i: any) => `- ${i.witnessName} (${i.witnessRole || 'Unknown'}): ${i.status}${i.hasTranscript ? ' [Transcript Available]' : ''}`).join('\n')}

=== COMMUNICATIONS REVIEWED (${communications.length}) ===
Key communications:
${communications.slice(0, 20).map((c: any) => `[${c.timestamp}] ${c.sender} -> ${c.recipients}: ${c.subject}`).join('\n')}

=== ALERTS GENERATED (${alerts.length}) ===
${alerts.slice(0, 10).map((a: any) => `- ${a.violationType}: ${a.message?.substring(0, 100)}`).join('\n')}`
      }
    ],
    temperature: 0.4,
    max_tokens: 6000,
  });

  return {
    finalReport: response.choices[0].message.content || 'Unable to draft final report',
    findingsIncluded: findings.length,
    interviewsIncluded: interviews.length,
    communicationsReviewed: communications.length,
    alertsReviewed: alerts.length,
  };
}

async function processCompareDocuments(caseId: string, payload: any, userId: string) {
  const { documentIds } = payload;

  // Get communications (documents) for comparison
  const communications = await storage.getCommunicationsByCase(caseId);
  
  let docsToCompare;
  if (documentIds && documentIds.length >= 2) {
    docsToCompare = communications.filter((c: any) => documentIds.includes(c.id));
  } else {
    // If no specific docs, compare most recent significant communications
    docsToCompare = communications.slice(0, 5);
  }

  if (docsToCompare.length < 2) {
    throw new Error('At least 2 documents are required for comparison');
  }

  const docContent = docsToCompare.map((d: any, i: number) => 
    `=== Document ${i + 1} ===\nFrom: ${d.sender}\nTo: ${d.recipients}\nDate: ${d.timestamp}\nSubject: ${d.subject}\n\n${d.body?.substring(0, 2000)}`
  ).join('\n\n');

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a legal document analyst comparing documents for an investigation.

Analyze the documents and provide:

## DOCUMENT OVERVIEW
- Summary of each document
- Type and purpose of each document

## KEY SIMILARITIES
- Common themes or topics
- Consistent facts or statements
- Aligned positions or agreements

## KEY DIFFERENCES  
- Contradictory statements
- Different facts or timelines
- Inconsistent positions

## CHRONOLOGICAL ANALYSIS
- How do the documents relate in time?
- Evolution of positions or facts

## RED FLAGS
- Suspicious discrepancies
- Potential fabrication indicators
- Missing information

## INVESTIGATIVE SIGNIFICANCE
- What do these documents prove or disprove?
- What questions do they raise?
- Recommended follow-up

Cite specific quotes and passages.`
      },
      {
        role: 'user',
        content: `Compare the following documents:\n\n${docContent}`
      }
    ],
    temperature: 0.3,
    max_tokens: 3000,
  });

  return {
    comparison: response.choices[0].message.content || 'Unable to compare documents',
    documentsCompared: docsToCompare.length,
  };
}

async function processTimelineReconciliation(caseId: string, payload: any, userId: string) {
  // Get all case data
  const caseData = await storage.getCaseById(caseId);
  if (!caseData) {
    throw new Error('Case not found');
  }

  const communications = await storage.getCommunicationsByCase(caseId);
  const interviews = await storage.getInterviewsByCase(caseId);
  const alerts = await storage.getAlertsByCase(caseId);
  const findings = await storage.getFindings(caseId, {});

  // Get timeline events from findings
  const timelineFindings = findings.filter((f: any) => f.entryType === 'timeline_event');

  // Get interview data with timeline references
  const interviewData = await Promise.all(
    interviews.slice(0, 8).map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const transcripts = recorded
        .filter((ri: any) => ri.transcript)
        .map((ri: any) => ri.transcript?.substring(0, 600))
        .join('\n');
      return {
        witnessName: interview.witnessName,
        transcripts,
      };
    })
  );

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are a legal investigator reconciling timelines from multiple sources.

Your task is to:

## MASTER TIMELINE
Create a single, reconciled timeline of events with all known dates and approximate dates.

## TIMELINE BY SOURCE
Show what each source (witness, document, etc.) says about the timeline.

## CONFLICTS & INCONSISTENCIES
- Dates that conflict between sources
- Events mentioned by one source but not others
- Impossible or improbable sequences

## GAPS IN TIMELINE
- Periods with no information
- Events that must have occurred but aren't documented
- Missing context

## CONFIDENCE ASSESSMENT
For each event, rate confidence:
- CONFIRMED: Multiple sources agree
- LIKELY: Single reliable source or circumstantial support
- UNCERTAIN: Conflicting accounts
- DISPUTED: Sources actively disagree

## INVESTIGATIVE PRIORITIES
What timeline questions need resolution?`
      },
      {
        role: 'user',
        content: `Reconcile timeline for: ${caseData.name}

=== DOCUMENTED TIMELINE EVENTS ===
${timelineFindings.map((f: any) => `${f.title}: ${f.content?.substring(0, 200)}`).join('\n')}

=== COMMUNICATIONS (chronological) ===
${communications.slice(0, 30).map((c: any) => `[${c.timestamp}] ${c.sender}: ${c.subject}`).join('\n')}

=== WITNESS ACCOUNTS ===
${interviewData.map((d: any) => `${d.witnessName}:\n${d.transcripts || 'No timeline information'}`).join('\n\n')}

=== ALERTS (dated) ===
${alerts.slice(0, 15).map((a: any) => `[${a.createdAt}] ${a.violationType}: ${a.message?.substring(0, 60)}`).join('\n')}`
      }
    ],
    temperature: 0.3,
    max_tokens: 3500,
  });

  return {
    reconciliation: response.choices[0].message.content || 'Unable to reconcile timeline',
    sourcesAnalyzed: {
      communications: Math.min(30, communications.length),
      interviews: Math.min(8, interviews.length),
      alerts: Math.min(15, alerts.length),
      timelineFindings: timelineFindings.length,
    },
  };
}

async function processCredibilityAnalysis(caseId: string, payload: any, userId: string) {
  const { interviewIds } = payload;

  // Get interviews
  let interviews = await storage.getInterviewsByCase(caseId);
  
  if (interviewIds && interviewIds.length > 0) {
    interviews = interviews.filter((i: any) => interviewIds.includes(i.id));
  }

  if (interviews.length === 0) {
    throw new Error('No interviews found for credibility analysis');
  }

  // Get interview data with transcripts
  const interviewData = await Promise.all(
    interviews.slice(0, 6).map(async (interview: any) => {
      const recorded = await storage.getRecordedInterviewsByInterviewId(interview.id);
      const transcripts = recorded
        .filter((ri: any) => ri.transcript)
        .map((ri: any) => ri.transcript?.substring(0, 1500))
        .join('\n');
      return {
        id: interview.id,
        witnessName: interview.witnessName,
        witnessRole: interview.witnessRole,
        transcripts,
      };
    })
  );

  const validInterviews = interviewData.filter((d: any) => d.transcripts);

  if (validInterviews.length === 0) {
    return {
      credibilityAssessment: 'No interview transcripts available for credibility analysis.',
      witnessesAnalyzed: 0,
    };
  }

  const response = await openai.chat.completions.create({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: `You are an experienced investigator assessing witness credibility.

For EACH witness, analyze and provide:

## WITNESS: [Name]

### CREDIBILITY INDICATORS

**Positive Indicators:**
- Consistency (internal and with other evidence)
- Specificity and detail
- Acknowledgment of uncertainty
- Admission against interest
- Corroboration by other sources

**Negative Indicators:**
- Inconsistencies in testimony
- Vagueness or evasiveness  
- Defensive or rehearsed responses
- Implausible claims
- Bias or motive to lie

### DEMEANOR NOTES
(Based on transcript language patterns)
- Cooperative vs. resistant
- Forthcoming vs. guarded
- Confident vs. uncertain

### CREDIBILITY RATING
[HIGHLY CREDIBLE / GENERALLY CREDIBLE / MIXED CREDIBILITY / LOW CREDIBILITY / UNRELIABLE]

### KEY CONCERNS
- Specific statements that raise credibility issues
- Areas requiring verification

### COMPARATIVE ANALYSIS
After individual assessments, compare witnesses:
- Who is most credible and why?
- Where do credible witnesses disagree?
- What accounts for credibility differences?

Be objective and cite specific evidence.`
      },
      {
        role: 'user',
        content: `Assess credibility of the following witnesses:

${validInterviews.map((d: any) => `=== ${d.witnessName} (${d.witnessRole || 'Role Unknown'}) ===\n${d.transcripts}`).join('\n\n')}`
      }
    ],
    temperature: 0.3,
    max_tokens: 3500,
  });

  return {
    credibilityAssessment: response.choices[0].message.content || 'Unable to assess credibility',
    witnessesAnalyzed: validInterviews.length,
    witnessNames: validInterviews.map((d: any) => d.witnessName),
  };
}
